const QUESTIONS = [{"id":"WBS-001","fragen_id":"5045012","thema":"Anlagenbuchhaltung","frage":"Welche beiden Zeitabschnitte einer Anlage im Bau (AiB) sind für die Anlagenbuchhaltung von SAP S/4HANA relevant?","typ":"multiple_select","optionen":["Die Nutzungsdauer","Die Abschlussphase","Die Im-Bau-Phase","Die Umlagephase","Die Abrechnungsphase"],"richtige_antworten":["Die Im-Bau-Phase","Die Abrechnungsphase"],"erklaerung":{"richtig":"Eine Anlage im Bau durchläuft in der SAP-Anlagenbuchhaltung genau zwei relevante Phasen: die Im-Bau-Phase (auch Aktivphase genannt), in der Kosten gesammelt werden, und die Abrechnungsphase, in der die gesammelten Werte auf fertige Anlagen umgebucht werden.","falsch":{"Die Nutzungsdauer":"Die Nutzungsdauer ist ein Parameter fertiger Anlagen für die Abschreibungsberechnung, nicht ein Zeitabschnitt der AiB.","Die Abschlussphase":"Dieser Begriff existiert so nicht als offizielle Phase der AiB in SAP.","Die Umlagephase":"Die Umlage ist ein CO-Begriff (Kostenumlage), kein Zeitabschnitt der Anlagenbuchhaltung."},"eselsbruecke":"Im-Bau → Kosten sammeln. Abrechnung → Werte auf fertige Anlage umbuchen. Erst bauen, dann abrechnen."},"source":"WBS"},{"id":"WBS-002","fragen_id":"5045013","thema":"Zahlungsbedingungen","frage":"Welches der folgenden Elemente erfordert die Eingabe eines Prozentsatzes in den Zahlungsbedingungen?","typ":"single_select","optionen":["Skonto","Rabattbetrag","Höchstbetrag","Währungsumrechnung"],"richtige_antworten":["Skonto"],"erklaerung":{"richtig":"Skonto wird immer als Prozentsatz definiert (z.B. 2% Skonto bei Zahlung innerhalb von 14 Tagen). In den Zahlungsbedingungen wird der Skontoprozentsatz zusammen mit der Skontofrist hinterlegt.","falsch":{"Rabattbetrag":"Ein Rabattbetrag ist ein fixer Eurobetrag, kein Prozentsatz.","Höchstbetrag":"Der Höchstbetrag ist eine absolute Betragsgrenze, kein Prozentsatz.","Währungsumrechnung":"Die Währungsumrechnung verwendet Wechselkurse, keine Prozentsätze im Sinne der Zahlungsbedingungen."},"eselsbruecke":"Skonto = immer %! '2% Skonto' ist Standard-Kaufmannsdeutsch."},"source":"WBS"},{"id":"WBS-003","fragen_id":"5045014","thema":"Anlagenbuchhaltung","frage":"Welche Steuerungsdaten beinhalten Anlagenklassen?","typ":"multiple_select","optionen":["Bildaufbau","Mehrwertsteuerklasse","AfA-Parameter","Kontenfindung","Nummernvergabe","Feldeigenschaften"],"richtige_antworten":["Bildaufbau","AfA-Parameter","Kontenfindung","Nummernvergabe","Feldeigenschaften"],"erklaerung":{"richtig":"Anlagenklassen steuern in SAP fünf zentrale Bereiche: Bildaufbau (welche Felder im Stammsatz sichtbar sind), AfA-Parameter (Abschreibungsschlüssel, Nutzungsdauer als Vorschlagswerte), Kontenfindung (welche G/L-Konten bei Buchungen verwendet werden), Nummernvergabe (interner oder externer Nummernkreis) und Feldeigenschaften (Pflicht-, Optional- oder Ausblendfelder).","falsch":{"Mehrwertsteuerklasse":"Die Mehrwertsteuerklasse wird im Kreditorenstammsatz oder im Buchungsbeleg gepflegt, nicht in der Anlagenklasse."},"eselsbruecke":"BAKNF: Bildaufbau, AfA, Kontenfindung, Nummernvergabe, Feldeigenschaften — die 5 Steuerungsgrößen der Anlagenklasse."},"source":"WBS"},{"id":"WBS-004","fragen_id":"5045015","thema":"Periodenabschluss","frage":"Sie führen am letzten Tag des Monates (keine Jahresbilanz) Abschlussarbeiten durch. Welche Tätigkeiten gehören mindestens dazu?","typ":"multiple_select","optionen":["Forderungsberichtigungen durchführen","Zweifelhafte Forderungen ausbuchen","Saldenbestätigungen verschicken","Fremdwährungsbewertung offener Posten durchführen","Erstellen des Anlagenspiegels","Dauerbuchungen ausführen"],"richtige_antworten":["Forderungsberichtigungen durchführen","Fremdwährungsbewertung offener Posten durchführen"],"erklaerung":{"richtig":"Beim monatlichen Abschluss (kein Jahresabschluss) gehören mindestens Forderungsberichtigungen und die Fremdwährungsbewertung offener Posten dazu. Diese müssen jeden Monat durchgeführt werden um korrekte Monatswerte zu gewährleisten.","falsch":{"Zweifelhafte Forderungen ausbuchen":"Das Ausbuchen zweifelhafter Forderungen ist eine Jahresabschlussaktivität, nicht zwingend monatlich.","Saldenbestätigungen verschicken":"Saldenbestätigungen werden typischerweise zum Jahresabschluss verschickt, nicht monatlich.","Erstellen des Anlagenspiegels":"Der Anlagenspiegel ist ein Jahresabschlussbestandteil.","Dauerbuchungen ausführen":"Dauerbuchungen werden zwar regelmäßig ausgeführt, gehören aber nicht zu den typischen Abschlussarbeiten im engeren Sinne."},"eselsbruecke":"Monat = Forderungen berichtigen + Fremdwährung bewerten. Jahresabschluss = alles andere dazu."},"source":"WBS"},{"id":"WBS-005","fragen_id":"5045016","thema":"Sonderhauptbuchvorgänge","frage":"Wobei handelt es sich um eine automatische (festgelegte) Gegenbuchung, auch statistische Buchung genannt?","typ":"single_select","optionen":["Buchung einer Bürgschaft","Wechselbuchung","Anzahlungsanforderung","Merkposten"],"richtige_antworten":["Buchung einer Bürgschaft"],"erklaerung":{"richtig":"Die Bürgschaft ist eine statistische Buchung mit festgelegter Gegenbuchung. Bei der Bürgschaft wird automatisch auf ein Gegenkonto gebucht — die Buchung ist rein informativ/statistisch und beeinflusst nicht den Saldo des Hauptbuchs.","falsch":{"Wechselbuchung":"Wechselbuchungen sind Sonderhauptbuchvorgänge mit freier Gegenbuchung.","Anzahlungsanforderung":"Die Anzahlungsanforderung ist ein Merkposten ohne Gegenbuchung.","Merkposten":"Merkposten sind Buchungen OHNE Gegenbuchung — genau das Gegenteil."},"eselsbruecke":"Bürgschaft = statistisch = festgelegte Gegenbuchung. Merkhilfe: eine Bürgschaft ist eine 'Garantie' — sie ist festgelegt."},"source":"WBS"},{"id":"WBS-006","fragen_id":"5045017","thema":"SD/FI Integration","frage":"Die folgenden Aussagen beschreiben anhand des Beispiels einer Kundenanzahlung, wie die Module Vertrieb (SD) und Finanzbuchhaltung (FI) miteinander integriert sind. Die Beschreibung welches Vorganges ist in diesem Zusammenhang korrekt?","typ":"single_select","optionen":["Eine Anzahlungsanforderung wird im FI als Merkposten gebucht, der automatisch eine Anfrage im SD erzeugt.","Eine Anzahlungsanforderung wird im FI als Merkposten gebucht, der automatisch einen Kundenauftrag im SD erzeugt.","Eine Anzahlungsanforderung wird im FI als Merkposten gebucht, der automatisch einen Wareneingang im SD erzeugt.","Eine Anzahlungsanforderung wird im FI als Merkposten gebucht, der automatisch einen Fakturabeleg im SD erzeugt."],"richtige_antworten":["Eine Anzahlungsanforderung wird im FI als Merkposten gebucht, der automatisch einen Fakturabeleg im SD erzeugt."],"erklaerung":{"richtig":"Im SD/FI-Integrationsprozess bei Kundenanzahlungen wird die Anzahlungsanforderung aus SD im FI als Merkposten gebucht. Dieser Merkposten triggert automatisch die Erstellung eines Fakturabelegs im SD-Modul.","falsch":{"Anfrage im SD":"Eine Anfrage ist der erste Schritt im SD-Prozess (Interessentenphase) — sie wird nicht durch eine Anzahlungsanforderung ausgelöst.","Kundenauftrag im SD":"Der Kundenauftrag existiert bereits bevor die Anzahlungsanforderung erstellt wird.","Wareneingang im SD":"Der Wareneingang gehört zum MM-Prozess, nicht zur Anzahlungsverarbeitung."},"eselsbruecke":"Anzahlungsanforderung in FI (Merkposten) → Faktura in SD. FI und SD arbeiten zusammen: FI merkt, SD fakturiert."},"source":"WBS"},{"id":"WBS-007","fragen_id":"5045018","thema":"Sonderhauptbuchvorgänge","frage":"Für welchen der folgenden Sonderhauptbuchvorgänge werden vom System KEINE Verkehrszahlen fortgeschrieben?","typ":"single_select","optionen":["Vorerfasste Belege","Merkposten","Gemerkte Belege","Wechsel","Anzahlung"],"richtige_antworten":["Merkposten"],"erklaerung":{"richtig":"Beim Merkposten erfolgt KEINE Buchung auf ein Gegenkonto und KEINE Fortschreibung von Verkehrszahlen. Der Merkposten ist rein informativ — er merkt sich einen Betrag ohne ihn buchhalterisch zu verarbeiten.","falsch":{"Vorerfasste Belege":"Vorerfasste Belege schreiben Verkehrszahlen fort sobald sie gebucht werden.","Gemerkte Belege":"Gemerkte Belege sind vorläufig gespeicherte Buchungen — sie schreiben keine Verkehrszahlen fort, aber aus einem anderen Grund als Merkposten.","Wechsel":"Wechsel sind echte Buchungen mit Verkehrszahlenfortschreibung.","Anzahlung":"Anzahlungen sind vollwertige Buchungen mit Verkehrszahlenfortschreibung."},"eselsbruecke":"Merkposten = nur merken, nicht buchen. Kein Geld fließt → keine Verkehrszahlen."},"source":"WBS"},{"id":"WBS-008","fragen_id":"5045019","thema":"Zahlungsverkehr","frage":"Welche Informationen werden auf der Rechnung aktualisiert, wenn man eine Zahlung bucht?","typ":"multiple_select","optionen":["Saldo des Kreditorenkontos","Datum des Ausgleichs","Zahlweg, auf dem der Ausgleich vollzogen wurde","Ausgleichsbelegnummer"],"richtige_antworten":["Datum des Ausgleichs","Zahlweg, auf dem der Ausgleich vollzogen wurde","Ausgleichsbelegnummer"],"erklaerung":{"richtig":"Wenn eine Zahlung gebucht wird, werden auf dem Rechnungsbeleg drei Informationen aktualisiert: das Ausgleichsdatum (wann wurde gezahlt), der verwendete Zahlweg (z.B. Überweisung, Scheck) und die Ausgleichsbelegnummer (Referenz auf den Zahlungsbeleg).","falsch":{"Saldo des Kreditorenkontos":"Der Kreditorensaldo wird zwar durch die Zahlung verändert, aber er ist kein Feld auf der Rechnung selbst — er ist eine Summe über alle Posten."},"eselsbruecke":"Was steht auf dem ausgeglichenen Rechnungsbeleg? WANN (Datum), WIE (Zahlweg), WOMIT (Belegnummer) — alles außer dem Saldo."},"source":"WBS"},{"id":"WBS-009","fragen_id":"5045020","thema":"Belegkorrektur","frage":"Was können oder müssen Sie tun, wenn beim Buchen eines Beleges eine falsche Eingabe gemacht wurde und Sie das korrigieren möchten?","typ":"multiple_select","optionen":["Sie müssen den Beleg grundsätzlich stornieren.","Bei entsprechender Einstellung im Customizing können Sie jedes Element eines Beleges nachträglich ändern, ohne ihn stornieren zu müssen.","Sie können keine Belege stornieren. Sie müssen den Auftrag neu buchen, um den Beleg ungültig zu machen.","Je nachdem, was Sie im Beleg ändern wollen, können Sie den Beleg einfach nachträglich ändern. Wenn die Daten nicht zu ändern sind, müssen Sie ihn stornieren.","Sie haben immer die Möglichkeit, den Beleg zu stornieren."],"richtige_antworten":["Je nachdem, was Sie im Beleg ändern wollen, können Sie den Beleg einfach nachträglich ändern. Wenn die Daten nicht zu ändern sind, müssen Sie ihn stornieren.","Sie haben immer die Möglichkeit, den Beleg zu stornieren."],"erklaerung":{"richtig":"In SAP FI gibt es zwei Wahrheiten gleichzeitig: Bestimmte Felder (z.B. Kurztext, Kostenstelle) können nachträglich geändert werden. Betrag und Konto können NICHT geändert werden → hier muss storniert werden. Stornieren ist IMMER möglich — das ist die Grundregel der doppelten Buchführung.","falsch":{"grundsätzlich stornieren":"Nicht jede Korrektur erfordert eine Stornierung — manche Felder sind direkt änderbar.","jedes Element ändern":"Nicht jedes Element ist änderbar — Betrag und Konto z.B. nicht.","keine Belege stornieren":"Falsch — Stornieren ist immer möglich."},"eselsbruecke":"SAP-Regel: Kleinkram (Text, Kostenstelle) → direkt ändern. Wichtiges (Betrag, Konto) → stornieren und neu buchen."},"source":"WBS"},{"id":"WBS-010","fragen_id":"5045021","thema":"Anlagenbuchhaltung","frage":"Was steuert der Bildaufbau des Anlagenstammsatzes?","typ":"multiple_select","optionen":["Die Art der Nummernvergabe (extern oder intern)","Ob beim Anlegen einer Anlage mit Referenzanlage bestimmte Feldgruppen mit Werten aus der Referenzanlage versorgt werden sollen","Die Feldeigenschaften","Die Abschreibungsparameter","Die Pflegeebene der Felder"],"richtige_antworten":["Ob beim Anlegen einer Anlage mit Referenzanlage bestimmte Feldgruppen mit Werten aus der Referenzanlage versorgt werden sollen","Die Feldeigenschaften","Die Pflegeebene der Felder"],"erklaerung":{"richtig":"Der Bildaufbau steuert drei Dinge: welche Felder bei Referenzanlagen übernommen werden, die Feldeigenschaften (Pflicht/Optional/Ausgeblendet) und auf welcher Ebene (Mandant, Buchungskreis, Bewertungsbereich) Felder gepflegt werden.","falsch":{"Nummernvergabe":"Die Nummernvergabe wird in der Anlagenklasse gesteuert, nicht im Bildaufbau.","Abschreibungsparameter":"AfA-Parameter sind Teil der Anlagenklasse bzw. des Bewertungsbereichs, nicht des Bildaufbaus."},"eselsbruecke":"Bildaufbau = wie sieht der Bildschirm aus. Felder sichtbar? Pflichtfeld? Von Referenz übernehmen?"},"source":"WBS"},{"id":"WBS-011","fragen_id":"5045022","thema":"Zahlungsverkehr","frage":"Welche Aussagen sind korrekt?","typ":"multiple_select","optionen":["Bankenstammsätze werden auf Mandantenebene angelegt und können deshalb in Geschäftspartnerstammsätzen aller Buchungskreise verwendet werden.","Wenn ein Kreditor gleichzeitig ein Debitor ist – oder umgekehrt, so kann das Zahlungsprogramm offene Posten zwischen Debitoren- und Kreditorenkonto verrechnen.","Das Zahlungsprogramm kann man jeweils nur einmal am Ende einer Abrechnungsperiode verwenden, damit doppelte Zahlungen vermieden werden."],"richtige_antworten":["Bankenstammsätze werden auf Mandantenebene angelegt und können deshalb in Geschäftspartnerstammsätzen aller Buchungskreise verwendet werden.","Wenn ein Kreditor gleichzeitig ein Debitor ist – oder umgekehrt, so kann das Zahlungsprogramm offene Posten zwischen Debitoren- und Kreditorenkonto verrechnen."],"erklaerung":{"richtig":"Bankenstammdaten gelten mandantenweit — eine Bank muss nur einmal angelegt werden. Das Zahlungsprogramm kann Debitoren- und Kreditorenposten desselben Geschäftspartners gegeneinander aufrechnen (Verrechnung).","falsch":{"nur einmal am Ende":"Das Zahlungsprogramm kann beliebig oft pro Periode laufen — es gibt keine Einschränkung auf einmal pro Periode."},"eselsbruecke":"Bank = einmal anlegen, überall nutzen. Kredit = Debit desselben Partners → verrechnen. Zahllauf = so oft wie nötig."},"source":"WBS"},{"id":"WBS-012","fragen_id":"5045023","thema":"Mahnwesen","frage":"Welche Aussagen zum Mahnprogramm sind korrekt?","typ":"multiple_select","optionen":["Ein Mahnlauf aktualisiert die Mahndaten in den Posten bzw. Konten, für die Zahlungen angemahnt wurden.","Nur dann, wenn die Mahndaten seit dem letzten Mahnlauf geändert wurden oder 'Immer mahnen' gesetzt ist, erzeugt das System eine weitere Mahnung","Damit man im Zweifelsfall nicht für jeden einzelnen Posten eine Mahnung schickt, versendet das System nur dann Mahnungen an einen Geschäftspartner, wenn bei allen überfälligen Posten die Mindestverzugstage überschritten sind."],"richtige_antworten":["Ein Mahnlauf aktualisiert die Mahndaten in den Posten bzw. Konten, für die Zahlungen angemahnt wurden.","Nur dann, wenn die Mahndaten seit dem letzten Mahnlauf geändert wurden oder 'Immer mahnen' gesetzt ist, erzeugt das System eine weitere Mahnung"],"erklaerung":{"richtig":"Nach jedem Mahnlauf werden Mahndaten aktualisiert (Mahnstufe, Datum). Eine erneute Mahnung wird nur erstellt wenn sich etwas geändert hat ODER 'Immer mahnen' aktiv ist — sonst würde das System täglich dieselbe Mahnung schicken.","falsch":{"alle überfälligen Posten":"Das System mahnt auch wenn nur einzelne Posten überfällig sind — nicht alle müssen die Mindestverzugstage überschritten haben."},"eselsbruecke":"Mahnlauf = Daten aktualisieren. Neue Mahnung nur wenn: etwas geändert ODER 'Immer mahnen'. Nicht alle Posten müssen fällig sein."},"source":"WBS"},{"id":"WBS-013","fragen_id":"5045024","thema":"Anlagenbuchhaltung","frage":"Wo können Investitionsförderschlüssel hinterlegt werden?","typ":"single_select","optionen":["In Debitorenstammsätzen","In Hausbankkonten","In Anlagenstammsätzen","In Kreditorenstammsätzen"],"richtige_antworten":["In Anlagenstammsätzen"],"erklaerung":{"richtig":"Investitionsförderschlüssel sind ein Bestandteil des Anlagenstammsatzes. Sie steuern steuerliche Vergünstigungen oder Förderprogramme die an eine spezifische Anlage geknüpft sind.","falsch":{"Debitorenstammsätzen":"Debitoren sind Kunden — Investitionsförderung hat keinen Bezug zu Kundenstammdaten.","Hausbankkonten":"Hausbankkonten enthalten Bankverbindungsdaten, keine Förderinformationen.","Kreditorenstammsätzen":"Kreditoren sind Lieferanten — die Förderung hängt an der Anlage, nicht am Lieferanten."},"eselsbruecke":"Die Förderung gehört ZUR ANLAGE — deshalb im Anlagenstammsatz."},"source":"WBS"},{"id":"WBS-014","fragen_id":"5045025","thema":"Anlagenbuchhaltung","frage":"Für welche Daten lassen sich beim Anlegen mehrerer gleichartiger Anlagen individuelle Angaben je Anlage machen?","typ":"multiple_select","optionen":["Buchungskreis","Anlagenklasse","Allgemeine Angaben (wie Bezeichnung, Aktivierungsdatum, Inventurdaten)","Versicherungsdaten","Zeitabhängige Zuordnungen (wie Kostenstelle)"],"richtige_antworten":["Allgemeine Angaben (wie Bezeichnung, Aktivierungsdatum, Inventurdaten)","Versicherungsdaten","Zeitabhängige Zuordnungen (wie Kostenstelle)"],"erklaerung":{"richtig":"Beim Massenanlegen von Anlagen können allgemeine Angaben (jede Anlage hat eigene Bezeichnung/Datum), Versicherungsdaten (unterschiedliche Versicherungswerte) und zeitabhängige Zuordnungen (verschiedene Kostenstellen) individuell je Anlage angegeben werden.","falsch":{"Buchungskreis":"Der Buchungskreis wird einmal für alle Anlagen der Masse festgelegt, nicht individuell.","Anlagenklasse":"Die Anlagenklasse bestimmt den Typ aller gleichartigen Anlagen — sie ist für alle gleich."},"eselsbruecke":"Was ist bei 'gleichartigen' Anlagen trotzdem unterschiedlich? Bezeichnung, Inventurnummer, Kostenstelle. Was ist gleich? Klasse und Buchungskreis."},"source":"WBS"},{"id":"WBS-015","fragen_id":"5045026","thema":"Kassenbuch","frage":"Was kann man mit dem Kassenbuch buchen?","typ":"multiple_select","optionen":["Kunden","Lieferanten","Einmal-Kunden","Anlagenstammsätze","Abgrenzungen"],"richtige_antworten":["Kunden","Lieferanten","Einmal-Kunden"],"erklaerung":{"richtig":"Das Kassenbuch in SAP dient für Bargeldbewegungen. Damit können Zahlungen an Kunden (Debitoren), Lieferanten (Kreditoren) und Einmal-Kunden (Gelegenheitskunden ohne eigenen Stammsatz) gebucht werden.","falsch":{"Anlagenstammsätze":"Anlagenanschaffungen über Bargeld sind im Kassenbuch nicht direkt buchbar — dafür gibt es separate Anlagenbuchungen.","Abgrenzungen":"Abgrenzungsbuchungen sind keine Bargeldbewegungen und gehören nicht ins Kassenbuch."},"eselsbruecke":"Kassenbuch = Kasse = Bargeld. Wer bekommt/zahlt Bargeld? Kunden, Lieferanten, Gelegenheitskunden."},"source":"WBS"},{"id":"WBS-016","fragen_id":"5045027","thema":"Nummernvergabe","frage":"Welche Aussage trifft auf externe Nummernvergabe zu?","typ":"multiple_select","optionen":["Die Nummer wird vom Anwender eingegeben.","Die Nummer kann alphanumerisch sein.","Die Nummer wird automatisch vergeben.","Die Nummer wird aus einem Fremdsystem importiert."],"richtige_antworten":["Die Nummer wird vom Anwender eingegeben.","Die Nummer kann alphanumerisch sein."],"erklaerung":{"richtig":"Bei externer Nummernvergabe gibt der Anwender die Nummer selbst ein. Diese kann alphanumerisch sein (Buchstaben und Zahlen gemischt), was bei interner Nummernvergabe nicht möglich ist.","falsch":{"automatisch vergeben":"Das ist die INTERNE Nummernvergabe — das System vergibt automatisch die nächste freie Nummer.","aus Fremdsystem importiert":"Import aus Fremdsystemen ist kein Standard-Merkmal der externen Nummernvergabe."},"eselsbruecke":"Extern = ich gebe die Nummer selbst ein (wie bei einer Kundennummer die ich mir aussuche). Intern = SAP gibt die Nummer."},"source":"WBS"},{"id":"WBS-017","fragen_id":"5045028","thema":"Berichtswesen","frage":"Welche der folgenden Rechercheberichte sind Standardberichte der Finanzbuchhaltung von SAP S/4HANA? (4 richtige Antworten)","typ":"multiple_select","optionen":["Gewinn- und Verlust (GuV)","Umlageberichte","Profit-Center-Berichte","Bilanz","Kostenstellenberichte","Segmentberichte","Allokationsberichte"],"richtige_antworten":["Gewinn- und Verlust (GuV)","Profit-Center-Berichte","Bilanz","Segmentberichte"],"erklaerung":{"richtig":"Die vier FI-Standardberichte sind GuV (externes Rechnungswesen), Bilanz (externes Rechnungswesen), Profit-Center-Berichte (integriert im neuen Hauptbuch) und Segmentberichte (Segmentberichterstattung nach IFRS 8).","falsch":{"Umlageberichte":"Umlage ist ein CO-Thema (Gemeinkostencontrolling), kein FI-Standardbericht.","Kostenstellenberichte":"Kostenstellenberichte gehören zum Controlling (CO-OM), nicht zur Finanzbuchhaltung.","Allokationsberichte":"Allokation ist ein CO-Begriff, kein FI-Standardbericht."},"eselsbruecke":"FI-Berichte = extern + Segmente: Bilanz, GuV, Profit Center, Segmente. Kosten-/Umlageberichte = CO."},"source":"WBS"},{"id":"WBS-018","fragen_id":"5045029","thema":"Validierung","frage":"Wie viele Schritte kann eine Validierung im Maximalfall haben?","typ":"single_select","optionen":["100","1000","499","999","99"],"richtige_antworten":["999"],"erklaerung":{"richtig":"Eine Validierung kann in SAP maximal 999 Schritte haben. Dies ist eine technische Systemgrenze.","falsch":{"100":"Zu niedrig — 100 wäre für komplexe Validierungen zu wenig.","1000":"Knapp daneben — es sind 999, nicht 1000.","499":"Falsch — keine besondere Bedeutung dieser Zahl.","99":"Zu niedrig — das ist die Grenze für andere Objekte in SAP."},"eselsbruecke":"999 = dreimal die 9 = maximale dreistellige Zahl. SAP liebt runde Maximalwerte: 999 Schritte."},"source":"WBS"},{"id":"WBS-019","fragen_id":"5045030","thema":"Belegerfassung","frage":"Für welche Bereiche kann man Daten vorerfassen?","typ":"multiple_select","optionen":["Wareneingänge","Debitoren","Sachkonten","Kreditoren","Anlagen","Materialbelege","Kostenumlagen"],"richtige_antworten":["Debitoren","Sachkonten","Kreditoren","Anlagen"],"erklaerung":{"richtig":"Die Vorerfassung (Beleg parken) ist in SAP FI für die vier FI-Belegarten möglich: Debitorenbelege, Sachkontenbelege, Kreditorenbelege und Anlagenbelege.","falsch":{"Wareneingänge":"Wareneingänge werden in MM gebucht, nicht in FI vorerfasst.","Materialbelege":"Materialbelege sind MM-Dokumente, keine FI-Vorerfassung.","Kostenumlagen":"Kostenumlagen sind CO-Vorgänge, keine FI-Vorerfassung."},"eselsbruecke":"Vorerfassen = nur in FI: Debi, Kredit, Sachkonto, Anlage. Alles aus MM oder CO geht nicht."},"source":"WBS"},{"id":"WBS-020","fragen_id":"5045031","thema":"Belegerfassung","frage":"Es kommt häufig vor, dass Firmen am Anfang eines neuen Geschäftsjahres Rechnungen für das vorherige Geschäftsjahr erhalten. Welche Daten müssen dasselbe Geschäftsjahr haben, damit ein Beleg gebucht werden kann?","typ":"single_select","optionen":["Buchungsdatum und Bezugsdatum","Ablagedatum und Buchungsdatum","Belegdatum und Abstimmdatum","Buchungsdatum und Skontodatum"],"richtige_antworten":["Buchungsdatum und Bezugsdatum"],"erklaerung":{"richtig":"Damit ein Beleg gebucht werden kann müssen Buchungsdatum und Bezugsdatum im selben Geschäftsjahr liegen. Das Bezugsdatum bestimmt die Periode, das Buchungsdatum bestimmt wann der Beleg ins System kommt.","falsch":{"Ablagedatum und Buchungsdatum":"Das Ablagedatum ist für die Archivierung relevant, nicht für die Buchungsperiode.","Belegdatum und Abstimmdatum":"Es gibt kein 'Abstimmdatum' als SAP-Standardfeld.","Buchungsdatum und Skontodatum":"Das Skontodatum bestimmt nur die Skontofrist, nicht das Geschäftsjahr."},"eselsbruecke":"BUDAT und BLDAT müssen ins gleiche Jahr. Wann buche ich (BUDAT) und worauf bezieht sich die Buchung (Bezugsdatum) — beide müssen passen."},"source":"WBS"},{"id":"WBS-021","fragen_id":"5045032","thema":"Report Painter / Sets","frage":"Welche Aussagen sind zutreffend?","typ":"multiple_select","optionen":["Alle Werte eines Sets beziehen sich auf eine oder mehrere Dimensionen einer Datenbanktabelle.","Jede Dimension einer Datenbanktabelle hat einen entsprechenden Hierarchieknoten im Report Painter.","Die Dimension einer Datenbanktabelle entspricht einem einzelnen Feld bzw. einer Spalte einer Datenbanktabelle.","Beispiele für Dimensionen sind das Konto, die Kostenstelle oder der Geschäftsbereich.","Bei wachsender Datenmenge wächst tendenziell die Systembelastung bei Datenbankabfragen, was sich negativ auf die Response-Geschwindigkeit auswirkt. Das ist ein Grund für die neue Datenbank-Architektur von SAP HANA gegenüber dem ehemaligen SAP R3.","Ein Set dient dazu, Daten zu gruppieren und Datenhierarchien festzulegen. Ein Set ist eine Struktur, in der bestimmte Werte oder Werte-Intervalle unter einem Setnamen zusammengefasst werden."],"richtige_antworten":["Alle Werte eines Sets beziehen sich auf eine oder mehrere Dimensionen einer Datenbanktabelle.","Die Dimension einer Datenbanktabelle entspricht einem einzelnen Feld bzw. einer Spalte einer Datenbanktabelle.","Beispiele für Dimensionen sind das Konto, die Kostenstelle oder der Geschäftsbereich.","Bei wachsender Datenmenge wächst tendenziell die Systembelastung bei Datenbankabfragen, was sich negativ auf die Response-Geschwindigkeit auswirkt. Das ist ein Grund für die neue Datenbank-Architektur von SAP HANA gegenüber dem ehemaligen SAP R3.","Ein Set dient dazu, Daten zu gruppieren und Datenhierarchien festzulegen. Ein Set ist eine Struktur, in der bestimmte Werte oder Werte-Intervalle unter einem Setnamen zusammengefasst werden."],"erklaerung":{"richtig":"Sets sind Gruppierungsstrukturen im Report Painter. Eine Dimension = eine Spalte/Feld in der Datenbank. Beispiele: Konto, Kostenstelle, Geschäftsbereich. SAP HANA wurde entwickelt um die Performanceprobleme bei großen Datenmengen zu lösen.","falsch":{"Hierarchieknoten im Report Painter":"Nicht jede Dimension hat automatisch einen Hierarchieknoten im Report Painter — das stimmt so nicht."},"eselsbruecke":"Dimension = Spalte in Tabelle. Set = Gruppe von Werten dieser Spalte. HANA = schneller bei vielen Daten."},"source":"WBS"},{"id":"WBS-022","fragen_id":"5045033","thema":"Belegerfassung","frage":"Welche beiden Möglichkeiten gibt es, Daten in Belegen vorläufig zu sichern?","typ":"multiple_select","optionen":["Beleg vorerfassen","Beleg zum Löschen vormerken","Beleg zum Archivieren vormerken","Beleg merken"],"richtige_antworten":["Beleg vorerfassen","Beleg merken"],"erklaerung":{"richtig":"Es gibt genau zwei Wege in SAP einen Beleg vorläufig zu speichern: Vorerfassen (Parken) — der Beleg bekommt eine Nummer, Verkehrszahlen werden fortgeschrieben, Vier-Augen-Prinzip möglich. Merken — rein temporär, keine Nummer, keine Verkehrszahlen, nur für den aktuellen Benutzer.","falsch":{"zum Löschen vormerken":"Das ist eine Funktion um Stammdaten zur Löschung zu markieren, kein Weg Belege vorläufig zu sichern.","zum Archivieren vormerken":"Archivieren ist das Auslagern bereits gebuchter Belege, nicht das vorläufige Sichern."},"eselsbruecke":"Vorläufig sichern = Parken (vorerfassen) ODER Merken. Parken = offiziell mit Nummer. Merken = inoffiziell ohne Nummer."},"source":"WBS"},{"id":"WBS-023","fragen_id":"5045034","thema":"Anlagenbuchhaltung","frage":"Wie können Sie Wertminderungen von Anlagen buchen?","typ":"single_select","optionen":["Mit Einteilungsvarianten","Mit Arbeitsvorräten","Mit der entsprechenden Bewegungsartengruppe","Mit speziellen Abschreibungsschlüsseln","Mit dem Report RVANLAB08"],"richtige_antworten":["Mit Arbeitsvorräten"],"erklaerung":{"richtig":"Wertminderungen (außerplanmäßige Abschreibungen) werden in SAP über Arbeitsvorräte gebucht. Der Arbeitsvorrat ermöglicht die Massenverarbeitung von Anlagenbewegungen.","falsch":{"Einteilungsvarianten":"Einteilungsvarianten sind ein SD-Begriff (Liefereinteilungen), kein Anlagenbuchhaltungsbegriff.","Bewegungsartengruppe":"Bewegungsartengruppen klassifizieren Bewegungen, buchen aber keine Wertminderungen direkt.","Abschreibungsschlüssel":"Abschreibungsschlüssel steuern planmäßige Abschreibungen, nicht außerplanmäßige Wertminderungen.","Report RVANLAB08":"Dieser Report existiert nicht als Standard-SAP-Report für Wertminderungen."},"eselsbruecke":"Wertminderung = außerplanmäßige Abschreibung = über Arbeitsvorrat buchen."},"source":"WBS"},{"id":"WBS-024","fragen_id":"5045035","thema":"Hausbanken","frage":"Welche Information braucht man, um Hausbanken einzurichten?","typ":"multiple_select","optionen":["Abstimmkonten","Hauptbuchkonto","Nummernkreisdaten","Kreditlimits","Buchungskreis","Bankstammdaten"],"richtige_antworten":["Buchungskreis","Bankstammdaten"],"erklaerung":{"richtig":"Für das Einrichten einer Hausbank benötigt man den Buchungskreis (zu welchem Unternehmen gehört die Bank) und die Bankstammdaten (Bankleitzahl, IBAN, BIC etc.).","falsch":{"Abstimmkonten":"Abstimmkonten werden für Debitoren/Kreditoren benötigt, nicht für die Hausbank selbst.","Hauptbuchkonto":"Das Bankkonto im Hauptbuch wird separat gepflegt, ist aber nicht die Hausbank-Einrichtung selbst.","Nummernkreisdaten":"Nummernkreise sind für Belegnummern relevant, nicht für Hausbanken.","Kreditlimits":"Kreditlimits betreffen Kreditoren/Debitoren, nicht Hausbanken."},"eselsbruecke":"Hausbank = WER (Buchungskreis) + WELCHE BANK (Bankstammdaten). Mehr braucht man nicht zum Einrichten."},"source":"WBS"},{"id":"WBS-025","fragen_id":"5045036","thema":"Belegvorerfassung","frage":"Welche Aussagen treffen zu?","typ":"multiple_select","optionen":["Vorerfasste Belege lassen sich in der Standardtransaktion einzeln oder über eine Listenauswahl buchen.","Mit der Transaktion 'Beleg vorerfassen' lässt sich das Vier-Augen-Prinzip und somit ein Freigabeverfahren (Workflow) darstellen.","Zum Vorerfassen von Belegen kann man keine Vorlagen verwenden.","Die Belegnummer eines vorerfassten Beleges wird in den gebuchten Beleg übernommen.","Sobald ein vorerfasster Beleg gebucht ist, werden die Daten des vorerfassten Beleges gelöscht."],"richtige_antworten":["Vorerfasste Belege lassen sich in der Standardtransaktion einzeln oder über eine Listenauswahl buchen.","Mit der Transaktion 'Beleg vorerfassen' lässt sich das Vier-Augen-Prinzip und somit ein Freigabeverfahren (Workflow) darstellen.","Die Belegnummer eines vorerfassten Beleges wird in den gebuchten Beleg übernommen.","Sobald ein vorerfasster Beleg gebucht ist, werden die Daten des vorerfassten Beleges gelöscht."],"erklaerung":{"richtig":"Alle fünf Aussagen sind korrekt: Vorerfasste Belege können einzeln oder per Liste gebucht werden. Das Vier-Augen-Prinzip ist möglich (Person A vorerfasst, Person B bucht). Keine Vorlagen beim Vorerfassen. Die Belegnummer bleibt beim Buchen erhalten. Nach dem Buchen wird der vorerfasste Beleg gelöscht.","falsch":{},"eselsbruecke":"Vorerfassen = Parken mit Nummer. Alle 5 Aussagen stimmen — merke: Nummer bleibt, vorerfasster Beleg verschwindet nach dem Buchen."},"source":"WBS"},{"id":"WBS-026","fragen_id":"5044639","thema":"Anlagenbuchhaltung","frage":"Wie lassen sich Anlagen-Altdaten aus einem Fremdsystem migrieren?","typ":"multiple_select","optionen":["Bei einer großen bis sehr großen Anzahl von Anlagen bietet sich die Verwendung einer BAPI-Schnittstelle an.","Für eine noch überschaubare Anzahl von Anlagen verwendet man am besten die Transaktionen AS91 oder ABLDT.","Bei einer eher kleinen Anzahl von Anlagen bietet sich die manuelle Eingabe per Batch-Input-Mappe an (hell abspielen).","Für eine kleine Anzahl von Anlagen kann man die Transaktion AS100 (Altdatenübernahme über Excel) verwenden.","Bei einer großen Anzahl von Anlagen bietet sich das Batch-Input-Verfahren an (Migrationsreport RANLTF22).","Bei einer großen Anzahl von Anlagen bietet sich der automatische Upload per Batch-Input-Mappe an (dunkel abspielen)."],"richtige_antworten":["Bei einer großen bis sehr großen Anzahl von Anlagen bietet sich die Verwendung einer BAPI-Schnittstelle an.","Für eine noch überschaubare Anzahl von Anlagen verwendet man am besten die Transaktionen AS91 oder ABLDT.","Bei einer eher kleinen Anzahl von Anlagen bietet sich die manuelle Eingabe per Batch-Input-Mappe an (hell abspielen).","Bei einer großen Anzahl von Anlagen bietet sich der automatische Upload per Batch-Input-Mappe an (dunkel abspielen)."],"erklaerung":{"richtig":"SAP bietet je nach Anlagenmenge verschiedene Migrationswege: Klein = manuell/hell abspielen. Mittel = AS91/ABLDT. Groß = dunkel abspielen (automatisch). Sehr groß = BAPI-Schnittstelle.","falsch":{"AS100 für kleine Anzahl":"AS100 gibt es nicht als Standard-Transaktion für kleine Mengen in dieser Form.","RANLTF22":"Dieser Migrationsreport ist nicht der Standard für Batch-Input bei Anlagen-Altdaten."},"eselsbruecke":"Klein→manuell, Mittel→AS91, Groß→dunkel, Sehr groß→BAPI. Je mehr Anlagen, desto automatischer."},"source":"WBS"},{"id":"WBS-027","fragen_id":"5044640","thema":"Mahnwesen","frage":"Welche ist die höchste Mahnstufe, die man einem Mahnverfahren zuweisen kann?","typ":"single_select","optionen":["12","11","9","8","10"],"richtige_antworten":["9"],"erklaerung":{"richtig":"In SAP kann ein Mahnverfahren maximal 9 Mahnstufen haben. Dies ist eine fest im System verankerte Grenze.","falsch":{"12":"Zu hoch — 12 Mahnstufen gibt es nicht.","11":"Zu hoch — 11 Mahnstufen gibt es nicht.","8":"Knapp daneben — es sind 9, nicht 8.","10":"Zu hoch — die Grenze liegt bei 9."},"eselsbruecke":"9 Mahnstufen = 9 Chancen zu zahlen bevor es kritisch wird. Merke: maximal 9."},"source":"WBS"},{"id":"WBS-028","fragen_id":"5044641","thema":"Organisationsstruktur","frage":"Welche Organisationseinheit ist zur Funktion eines SAP-FI-Systems zwingend erforderlich?","typ":"single_select","optionen":["Kostenrechnungskreis","Lagerort","Mandant","Kreditkontrollbereich","Werk","Einkäufergruppe","Geschäftsbereich"],"richtige_antworten":["Mandant"],"erklaerung":{"richtig":"Der Mandant ist die oberste und zwingend erforderliche Organisationseinheit in SAP. Ohne Mandant gibt es kein SAP-System. Alle anderen Einheiten (Buchungskreis, Werk etc.) sind dem Mandanten untergeordnet.","falsch":{"Kostenrechnungskreis":"Optional — nur wenn CO genutzt wird.","Lagerort":"MM-Organisationseinheit, für FI nicht zwingend.","Kreditkontrollbereich":"Optional für Kreditmanagement.","Werk":"MM/SD-Organisationseinheit, für FI nicht zwingend.","Einkäufergruppe":"MM-Organisationseinheit.","Geschäftsbereich":"Optional für Segmentberichterstattung."},"eselsbruecke":"Mandant = das SAP-System selbst. Ohne Mandant = kein SAP. Alles andere ist optional."},"source":"WBS"},{"id":"WBS-029","fragen_id":"5044642","thema":"Zahlungsverkehr","frage":"Welche Zahlungsparameter werden vor dem Start eines Zahllaufes eingegeben?","typ":"multiple_select","optionen":["Zu berücksichtigende Kostenstellen","Zu berücksichtigende Geschäftspartner","Alphanumerischer Schlüssel zur Identifikation des Zahllaufes","Tag der Ausführung","Zu berücksichtigender Zeitraum","Zu berücksichtigende Anlagenklassen","Zu berücksichtigende Mandanten","Zu berücksichtigende Buchungskreise"],"richtige_antworten":["Zu berücksichtigende Geschäftspartner","Alphanumerischer Schlüssel zur Identifikation des Zahllaufes","Tag der Ausführung","Zu berücksichtigender Zeitraum","Zu berücksichtigende Buchungskreise"],"erklaerung":{"richtig":"Beim Zahllauf (F110) werden folgende Parameter eingegeben: Ausführungsdatum, Identifikationsschlüssel (eindeutiger Name des Laufs), Buchungskreise, Geschäftspartner und der zu berücksichtigende Zeitraum (Fälligkeitsdatum bis).","falsch":{"Kostenstellen":"Kostenstellen sind CO-Objekte, nicht Zahlungsparameter.","Anlagenklassen":"Anlagenklassen haben keinen Bezug zum Zahllauf.","Mandanten":"Der Mandant ist systemweit — man kann im Zahllauf nicht mehrere Mandanten angeben."},"eselsbruecke":"Zahllauf = WER zahlt (Buchungskreis), AN WEN (Geschäftspartner), WANN (Datum, Zeitraum), WELCHER LAUF (Schlüssel)."},"source":"WBS"},{"id":"WBS-030","fragen_id":"5044643","thema":"Mahnwesen","frage":"Welche Aussagen treffen zu?","typ":"multiple_select","optionen":["Man muss mindestens eine Mahnstufe und kann maximal neun Mahnstufen pro Mahnverfahren definieren.","Man kann maximal sechs Mahnstufen pro Mahnverfahren definieren.","Das Mahnverfahren bestimmt den Mahnabstand und somit den Mahnrhythmus, in dem Konten gemahnt werden.","Das Mahnverfahren wird mit einem vierstelligen alphanumerischen Schlüssel definiert."],"richtige_antworten":["Man muss mindestens eine Mahnstufe und kann maximal neun Mahnstufen pro Mahnverfahren definieren.","Das Mahnverfahren bestimmt den Mahnabstand und somit den Mahnrhythmus, in dem Konten gemahnt werden.","Das Mahnverfahren wird mit einem vierstelligen alphanumerischen Schlüssel definiert."],"erklaerung":{"richtig":"Mahnverfahren: min. 1, max. 9 Mahnstufen. Der Mahnabstand (z.B. alle 14 Tage) wird im Mahnverfahren definiert. Der Schlüssel ist vierstellig alphanumerisch (z.B. 'MAH1').","falsch":{"maximal sechs":"Falsch — es sind maximal 9 Mahnstufen, nicht 6."},"eselsbruecke":"4-stelliger Schlüssel, 1-9 Stufen, Rhythmus definiert. Das Mahnverfahren = Spielregeln des Mahnens."},"source":"WBS"},{"id":"WBS-031","fragen_id":"5044644","thema":"Mahnwesen","frage":"Welche Listen unterstützen das Mahnwesen?","typ":"multiple_select","optionen":["Die Liste der sonstigen Forderungen","Die Liste mit Sondervereinbarungen zu bestimmten Debitoren bzw. Kreditoren","Die Liste der gesperrten Konten","Die Mahnliste","Die Mahnhistorie"],"richtige_antworten":["Die Liste der gesperrten Konten","Die Mahnliste","Die Mahnhistorie"],"erklaerung":{"richtig":"Das Mahnwesen wird durch drei Listen unterstützt: die Mahnliste (zeigt was gemahnt wird), die Mahnhistorie (zeigt was bereits gemahnt wurde) und die Liste der gesperrten Konten (zeigt wer nicht gemahnt wird).","falsch":{"Liste der sonstigen Forderungen":"Diese Liste ist kein Standard-Mahnwesen-Werkzeug in SAP.","Sondervereinbarungen":"Sondervereinbarungen werden in Stammdaten gepflegt, nicht als Mahnliste geführt."},"eselsbruecke":"Mahnwesen = Was wird gemahnt (Mahnliste) + Was wurde gemahnt (Historie) + Wer wird NICHT gemahnt (gesperrte Konten)."},"source":"WBS"},{"id":"WBS-032","fragen_id":"5044645","thema":"Zahlungsverkehr","frage":"Welche Felder eines Finanzbuchhaltungsbelegs beeinflussen das Zahlungsprogramm?","typ":"multiple_select","optionen":["Stornoanfrage","Zahlungssperre","Zahlweg","Zahlungsbedingung","Anzahlung angefordert","Zahlungsavis"],"richtige_antworten":["Zahlungssperre","Zahlweg","Zahlungsbedingung"],"erklaerung":{"richtig":"Das Zahlungsprogramm liest aus dem Beleg drei Felder: Zahlungssperre (gesperrte Posten werden nicht gezahlt), Zahlweg (wie soll gezahlt werden — Überweisung, Scheck) und Zahlungsbedingung (wann ist die Zahlung fällig, gibt es Skonto).","falsch":{"Stornoanfrage":"Eine Stornoanfrage beeinflusst nicht das Zahlungsprogramm.","Anzahlung angefordert":"Anzahlungsanforderungen sind Merkposten — sie beeinflussen das Zahlungsprogramm nicht direkt.","Zahlungsavis":"Der Zahlungsavis ist eine Benachrichtigung nach der Zahlung, kein Steuerungsfeld."},"eselsbruecke":"Zahllauf fragt: Gesperrt? (Sperre) Wie zahlen? (Zahlweg) Wann zahlen? (Bedingung). Diese 3 Felder steuern den Zahllauf."},"source":"WBS"},{"id":"WBS-033","fragen_id":"5044646","thema":"Sonderhauptbuchvorgänge","frage":"Welche Aussagen sind korrekt?","typ":"multiple_select","optionen":["Technisch gesehen werden drei Arten von Sonderhauptbuchvorgängen unterschieden: statistische Buchung, Buchung mit freier Gegenbuchung und Buchung ohne Gegenbuchung (Merkposten).","Bei Aktiven/Passiven Rechnungsabgrenzungsposten, Anzahlungen, Anzahlungsanforderungen oder Sicherheitseinbehalten handelt es sich um Sonderhauptbuchvorgänge.","Bei Wechseln, Anzahlungen, Anzahlungsanforderungen oder Sicherheitseinbehalten handelt es sich um Sonderhauptbuchvorgänge","Sonderhauptbuchvorgänge sind Buchungen, deren Gegenbuchungen erst mit Eingabe der Zahllauf-Parameter festgelegt werden.","Sonderhauptbuchvorgänge werden mit speziellen Buchungsschlüsseln und Sonderhauptbuchkennzeichen gebucht."],"richtige_antworten":["Technisch gesehen werden drei Arten von Sonderhauptbuchvorgängen unterschieden: statistische Buchung, Buchung mit freier Gegenbuchung und Buchung ohne Gegenbuchung (Merkposten).","Bei Aktiven/Passiven Rechnungsabgrenzungsposten, Anzahlungen, Anzahlungsanforderungen oder Sicherheitseinbehalten handelt es sich um Sonderhauptbuchvorgänge.","Bei Wechseln, Anzahlungen, Anzahlungsanforderungen oder Sicherheitseinbehalten handelt es sich um Sonderhauptbuchvorgänge","Sonderhauptbuchvorgänge werden mit speziellen Buchungsschlüsseln und Sonderhauptbuchkennzeichen gebucht."],"erklaerung":{"richtig":"Sonderhauptbuchvorgänge haben drei technische Arten: 1. Statistische Buchung (festgelegte Gegenbuchung, z.B. Bürgschaft), 2. Freie Gegenbuchung (z.B. Wechsel), 3. Ohne Gegenbuchung (Merkposten). Sie werden immer mit speziellem Buchungsschlüssel + SHB-Kennzeichen gebucht.","falsch":{"Gegenbuchung erst bei Zahllauf":"Das ist falsch — die Gegenbuchung bei Sonderhauptbuchvorgängen ist nicht vom Zahllauf abhängig."},"eselsbruecke":"3 Typen: Statistisch (fest), Frei (Wechsel), Ohne (Merkposten). Erkennbar an: speziellem Buchungsschlüssel + SHB-Kennzeichen."},"source":"WBS"},{"id":"WBS-034","fragen_id":"5044647","thema":"Mahnwesen","frage":"Was ist bei der Konfiguration des Mahnprogrammes entscheidend?","typ":"multiple_select","optionen":["Hausbankkonten","Mahnstufen","Mahngebühren","Wahl der Sprache","Mindestbeträge"],"richtige_antworten":["Mahnstufen","Mahngebühren","Mindestbeträge"],"erklaerung":{"richtig":"Bei der Konfiguration des Mahnprogramms sind entscheidend: Mahnstufen (wie viele Eskalationsstufen), Mahngebühren (was wird pro Stufe berechnet) und Mindestbeträge (ab welchem Betrag wird überhaupt gemahnt).","falsch":{"Hausbankkonten":"Hausbankkonten sind für den Zahllauf relevant, nicht für das Mahnprogramm.","Wahl der Sprache":"Die Sprache ist eine Benutzereinstellung, kein entscheidender Konfigurationsparameter des Mahnprogramms."},"eselsbruecke":"Mahnprogramm-Konfiguration = WIE VIELE Stufen + WAS KOSTET es + AB WANN wird gemahnt."},"source":"WBS"},{"id":"WBS-035","fragen_id":"5044648","thema":"Zahlungsverkehr","frage":"Was passiert, wenn Sie eine ausgehende Teilzahlung buchen?","typ":"multiple_select","optionen":["Die Teilzahlung wird unter Bezugnahme auf die Rechnung gebucht.","Die ursprüngliche Rechnung bleibt offen.","Die ursprüngliche Rechnung wird storniert.","Die Rechnung wird für weitere Zahlungen vorläufig gesperrt."],"richtige_antworten":["Die Teilzahlung wird unter Bezugnahme auf die Rechnung gebucht.","Die ursprüngliche Rechnung bleibt offen."],"erklaerung":{"richtig":"Bei einer Teilzahlung bleibt die ursprüngliche Rechnung vollständig als offener Posten erhalten. Die Teilzahlung wird als eigener Beleg mit Bezug auf die Rechnung gebucht. Beide Posten bleiben offen bis die Restschuld bezahlt wird.","falsch":{"Rechnung wird storniert":"Eine Teilzahlung storniert die Rechnung nicht — die Rechnung bleibt offen.","vorläufig gesperrt":"Die Rechnung wird nicht gesperrt — sie bleibt für weitere Zahlungen weiter offen."},"eselsbruecke":"Teilzahlung = zwei offene Posten: Rechnung (voll) + Teilzahlung (als Gutschrift). Erst bei Vollzahlung werden beide ausgeglichen."},"source":"WBS"},{"id":"WBS-036","fragen_id":"5044649","thema":"Anlagenbuchhaltung","frage":"Was bucht das Programm 'FAA_DEPRECIATION_POST' in SAP S/4HANA?","typ":"multiple_select","optionen":["Anlagenabgänge","Außerplanmäßige Abschreibung","Normalabschreibung","Kalkulatorische Zinsen","Kalkulatorische Abschreibung","Kalkulatorische Neubewertungen","Handelsrechtliche Abschreibung"],"richtige_antworten":["Außerplanmäßige Abschreibung","Normalabschreibung","Kalkulatorische Zinsen","Kalkulatorische Abschreibung","Handelsrechtliche Abschreibung"],"erklaerung":{"richtig":"FAA_DEPRECIATION_POST ist das zentrale Abschreibungsprogramm in S/4HANA. Es bucht alle Arten von Abschreibungen: planmäßig (Normal, Handelsrechtlich), außerplanmäßig und kalkulatorisch (Zinsen, Abschreibung).","falsch":{"Anlagenabgänge":"Abgänge werden über separate Transaktionen (ABAON, ABAVN) gebucht, nicht über das Abschreibungsprogramm.","Kalkulatorische Neubewertungen":"Neubewertungen sind ein separater Prozess, nicht Teil des Standardabschreibungslaufs."},"eselsbruecke":"FAA_DEPRECIATION_POST = Abschreibungen ALLER Art buchen. Außer: Abgänge und Neubewertungen — die laufen separat."},"source":"WBS"},{"id":"WBS-037","fragen_id":"5044650","thema":"Mahnwesen","frage":"Welche der folgenden Aussagen treffen auf den Begriff 'Mahnlauf' zu?","typ":"multiple_select","optionen":["Nicht jeder überfällige Posten wird vom System sofort gemahnt.","Man kann je Buchungskreis Kriterien festlegen, nach denen Posten bzw. Kreditorenkonten in einem Mahnlauf berücksichtigt werden.","Je Buchungskreis stehen bis zu vier Mahnstufen zur Verfügung.","Mahnläufe kann man nicht wiederholen."],"richtige_antworten":["Nicht jeder überfällige Posten wird vom System sofort gemahnt.","Man kann je Buchungskreis Kriterien festlegen, nach denen Posten bzw. Kreditorenkonten in einem Mahnlauf berücksichtigt werden."],"erklaerung":{"richtig":"Nicht jeder überfällige Posten wird sofort gemahnt — es gibt Mindestverzugstage und Mindestbeträge. Je Buchungskreis können eigene Mahnkriterien definiert werden.","falsch":{"vier Mahnstufen":"Es sind bis zu 9 Mahnstufen möglich, nicht vier.","nicht wiederholen":"Mahnläufe können wiederholt werden — man kann den Mahnvorschlag löschen und neu erstellen."},"eselsbruecke":"Mahnlauf = selektiv (nicht alles wird gemahnt) + flexibel (Kriterien je Buchungskreis) + wiederholbar (bis zu 9 Stufen)."},"source":"WBS"},{"id":"WBS-038","fragen_id":"5044651","thema":"SAP Fiori","frage":"Was trifft auf SAP Fiori zu?","typ":"multiple_select","optionen":["Es ist eine rationelle Datenbank.","Es ist responsiv und so mit unterschiedlichen Ausgabegeräten (auch mobilen Endgeräten) kompatibel.","Es ist die Programmiersprache von SAP.","Es ist rollenbasiert."],"richtige_antworten":["Es ist responsiv und so mit unterschiedlichen Ausgabegeräten (auch mobilen Endgeräten) kompatibel.","Es ist rollenbasiert."],"erklaerung":{"richtig":"SAP Fiori ist das moderne UX-Design-System von SAP. Es ist responsiv (funktioniert auf PC, Tablet, Smartphone) und rollenbasiert (jeder Benutzer sieht nur die Apps die seiner Rolle entsprechen).","falsch":{"rationelle Datenbank":"SAP HANA ist die Datenbank — Fiori ist die Benutzeroberfläche.","Programmiersprache":"ABAP ist die Programmiersprache von SAP — Fiori ist ein Design-Framework."},"eselsbruecke":"Fiori = schöne, moderne Oberfläche. Responsiv (alle Geräte) + rollenbasiert (jeder sieht was er braucht)."},"source":"WBS"},{"id":"WBS-039","fragen_id":"5044652","thema":"Periodenabschluss","frage":"Welche Tätigkeiten werden vom Umgliederungsreport für Forderungen und Verbindlichkeiten durchgeführt?","typ":"multiple_select","optionen":["Der Report nimmt zunächst die Umbuchungen für die geänderten Abstimmkonten vor.","Die Umgliederung von Anlagen nach verbleibender Nutzungsdauer kann bei Bedarf durchgeführt werden.","Forderungen und Verbindlichkeiten werden nach Restlaufzeiten gegliedert und die dazu erforderlichen Umbuchungen durchgeführt.","Die Umgliederung von Sonderhauptbuchvorgängen nach Gültigkeitszeitraum wird unterstützt."],"richtige_antworten":["Der Report nimmt zunächst die Umbuchungen für die geänderten Abstimmkonten vor.","Forderungen und Verbindlichkeiten werden nach Restlaufzeiten gegliedert und die dazu erforderlichen Umbuchungen durchgeführt."],"erklaerung":{"richtig":"Der Umgliederungsreport macht zwei Dinge: Er bucht geänderte Abstimmkonten um, und er gliedert Forderungen/Verbindlichkeiten nach Restlaufzeiten um (kurz-/langfristig) — wie es HGB/IFRS für die Bilanz verlangt.","falsch":{"Anlagen nach Nutzungsdauer":"Anlagenumgliederung ist ein separater Prozess, nicht Teil dieses Reports.","Sonderhauptbuchvorgänge nach Gültigkeitszeitraum":"Diese Funktion wird vom Umgliederungsreport nicht unterstützt."},"eselsbruecke":"Umgliederung = Bilanzsicht herstellen. Kurzfristig vs. langfristig trennen. Das ist gesetzliche Pflicht."},"source":"WBS"},{"id":"WBS-040","fragen_id":"5044653","thema":"Anlagenbuchhaltung","frage":"Welche Aussagen zu Anlagen sind korrekt?","typ":"multiple_select","optionen":["Wenn man die richtige Bewegungsart für außerplanmäßige Abschreibungen wählt, weiß das System, dass es die Abschreibung automatisch vornehmen soll.","Wenn man eine außerplanmäßige Abschreibung bucht, kann man die Bewertungsbereiche wählen, in denen diese Abschreibung gebucht werden soll.","In der Transfervariante legt man die beim Anlagentransfer zu verwendende Transfermethode und die Bewegungsarten fest.","Bei der Aktivierung einer Anlage im Bau (AiB) werden die Werte auf eine oder mehrere Anlagen umgebucht."],"richtige_antworten":["Wenn man eine außerplanmäßige Abschreibung bucht, kann man die Bewertungsbereiche wählen, in denen diese Abschreibung gebucht werden soll.","In der Transfervariante legt man die beim Anlagentransfer zu verwendende Transfermethode und die Bewegungsarten fest.","Bei der Aktivierung einer Anlage im Bau (AiB) werden die Werte auf eine oder mehrere Anlagen umgebucht."],"erklaerung":{"richtig":"Bei außerplanmäßiger Abschreibung kann man gezielt Bewertungsbereiche auswählen (z.B. nur handelsrechtlich, nicht steuerrechtlich). Transfervarianten definieren die Methode und Bewegungsarten beim Anlagentransfer. AiB-Aktivierung = Umbuchung auf fertige Anlage(n).","falsch":{"automatisch vornehmen":"Außerplanmäßige Abschreibungen sind NICHT automatisch — sie müssen manuell ausgelöst werden. Die Bewegungsart steuert NUR die Buchungslogik."},"eselsbruecke":"Außerplanmäßig = manuell + Bewertungsbereich wählbar. AiB aktivieren = Werte umbuchen auf fertige Anlage."},"source":"WBS"},{"id":"WBS-041","fragen_id":"5044654","thema":"Anlagenbuchhaltung","frage":"Welche der folgenden Aussagen treffen auf den Begriff des Anlagentransfers zu?","typ":"multiple_select","optionen":["Nettomethode: transferiert den Restbuchwert der sendenden Anlage.","Ein Beispiel für einen Anlagentransfer ist der Übertrag bzw. der Verkauf eines Wirtschaftsgutes innerhalb eines Konzernes.","Mit der Transaktion ABT1L kann man Anlagentransfers von einem Buchungskreis in einen anderen durchführen.","Welche Transfermethode bei einem Anlagentransfer zur Anwendung kommt, entscheidet das System anhand der Anlagenhistorie."],"richtige_antworten":["Nettomethode: transferiert den Restbuchwert der sendenden Anlage.","Ein Beispiel für einen Anlagentransfer ist der Übertrag bzw. der Verkauf eines Wirtschaftsgutes innerhalb eines Konzernes.","Mit der Transaktion ABT1L kann man Anlagentransfers von einem Buchungskreis in einen anderen durchführen."],"erklaerung":{"richtig":"Die Nettomethode transferiert den Restbuchwert (nicht Brutto). ABT1L ist die Transaktion für buchungskreisübergreifende Transfers. Konzerninterner Verkauf ist ein klassisches Transfer-Beispiel.","falsch":{"anhand der Anlagenhistorie":"Die Transfermethode wird in der Transfervariante (Customizing) festgelegt, nicht anhand der Anlagenhistorie."},"eselsbruecke":"ABT1L = buchungskreisübergreifend. Netto = Restbuchwert. Methode steht in der Transfervariante, nicht in der Historie."},"source":"WBS"},{"id":"WBS-042","fragen_id":"5044655","thema":"Anlagenbuchhaltung","frage":"Auf welche Arten kann man einen Anlagenzugang buchen?","typ":"multiple_select","optionen":["Anlagenzugang durch das SD","Zugang gegen Kreditor","Anlagenzugang über das Asset Cockpit","Anlagenzugang durch das MM","Anlagenzugang ohne Bestellbezug","Anlagenzugang gegen Verrechnungskonto","Integrierter Anlagenzugang","Anlagenzugang über den Depreciation Engine"],"richtige_antworten":["Zugang gegen Kreditor","Anlagenzugang durch das MM","Anlagenzugang ohne Bestellbezug","Anlagenzugang gegen Verrechnungskonto","Integrierter Anlagenzugang"],"erklaerung":{"richtig":"Anlagenzugänge können auf verschiedene Arten erfolgen: direkt gegen Kreditor (FI), über MM mit Bestellbezug, ohne Bestellbezug, gegen Verrechnungskonto oder als integrierter Zugang (MM/FI gleichzeitig).","falsch":{"durch SD":"SD (Vertrieb) bucht Anlagenabgänge (Verkauf), keine Zugänge.","über Asset Cockpit":"Das Asset Cockpit ist ein Analysewerkzeug, keine Buchungstransaktion.","Depreciation Engine":"Der Depreciation Engine berechnet Abschreibungen, bucht keine Zugänge."},"eselsbruecke":"Zugang = Anlage kommt ins Unternehmen. Wege: gegen Kredit (FI), über MM (Einkauf), ohne Bestellung, über Verrechnungskonto. SD bucht Abgänge!"},"source":"WBS"},{"id":"WBS-043","fragen_id":"5044656","thema":"Belegkorrektur","frage":"Was muss getan werden, wenn beim Buchen eines Beleges ein falscher Betrag oder ein falsches Konto eingegeben wurde?","typ":"multiple_select","optionen":["Man bucht ein Storno als Negativbuchung.","Man storniert den Beleg.","Man bucht ein Storno als normale Umkehrbuchung.","Man löscht den Beleg und bucht ihn neu.","Man gibt einen Korrekturtransaktionscode ein.","Man wählt 'Beleg ändern' und korrigiert die Fehler."],"richtige_antworten":["Man bucht ein Storno als Negativbuchung.","Man storniert den Beleg.","Man bucht ein Storno als normale Umkehrbuchung."],"erklaerung":{"richtig":"Bei falschem Betrag oder falschem Konto — also bei Fehlern die nicht direkt im Beleg änderbar sind — muss storniert werden. In SAP gibt es zwei Stornoarten: Negativbuchung (echter Storno, reduziert Verkehrszahlen) oder normale Umkehrbuchung (Normalstorno, erhöht Verkehrszahlen).","falsch":{"Umkehrbuchung":"Die Umkehrbuchung ist eine Form des Stornos — aber die Frage fragt nach dem Was, und die Antwort 'Man storniert' ist die korrekte übergeordnete Aussage.","löscht den Beleg":"Gebuchte Belege können in SAP nicht gelöscht werden.","Korrekturtransaktionscode":"Gibt es nicht als SAP-Standard.","Beleg ändern":"Betrag und Konto sind in gebuchten Belegen NICHT änderbar."},"eselsbruecke":"Falscher Betrag/Konto = STORNIEREN. Nicht löschen (geht nicht), nicht ändern (geht nicht bei Betrag/Konto)."},"source":"WBS"},{"id":"WBS-044","fragen_id":"5044657","thema":"Anlagenbuchhaltung","frage":"Auf welcher Basis bestimmt das System die Periode eines Anlagenabganges?","typ":"single_select","optionen":["Anfangsdatum des Gültigkeitszeitraumes der zugeordneten Kostenstelle","Anfangsdatum des Gültigkeitszeitraumes des zugeordneten Profit Centers","Bezugsdatum","Restbuchwert"],"richtige_antworten":["Bezugsdatum"],"erklaerung":{"richtig":"Bei Anlagenabgängen bestimmt das Bezugsdatum (= Wertstellungsdatum) in welche Periode der Abgang fällt. Dies ist das Datum der tatsächlichen Abgangsbewegung.","falsch":{"Kostenstelle Anfangsdatum":"Das Gültigkeitsdatum der Kostenstelle hat keinen Einfluss auf die Abgangsperiode.","Profit Center Anfangsdatum":"Analog zur Kostenstelle — kein Einfluss auf die Abgangsperiode.","Restbuchwert":"Der Restbuchwert ist ein Betrag, kein Datum — er kann keine Periode bestimmen."},"eselsbruecke":"Wann geht die Anlage? → Bezugsdatum bestimmt die Periode. Immer das Datum, nie ein Betrag."},"source":"WBS"},{"id":"WBS-045","fragen_id":"5044658","thema":"Offene-Posten-Verwaltung","frage":"Welche Konten kann man manuell ausgleichen?","typ":"single_select","optionen":["Alle Abstimmkonten","Alle Konten mit Offene-Posten-Verwaltung","Alle Anlagenkonten","Alle Erfolgskonten","Alle Sachkonten"],"richtige_antworten":["Alle Konten mit Offene-Posten-Verwaltung"],"erklaerung":{"richtig":"Manuell ausgeglichen werden können nur Konten bei denen die Offene-Posten-Verwaltung aktiviert ist. Diese Einstellung erlaubt es das System, einzelne Buchungszeilen als 'offen' oder 'ausgeglichen' zu verwalten.","falsch":{"Abstimmkonten":"Abstimmkonten können nicht direkt gebucht oder ausgeglichen werden — das geschieht automatisch.","Anlagenkonten":"Anlagenkonten werden über Anlagenbewegungen verwaltet, nicht manuell ausgeglichen.","Erfolgskonten":"Erfolgskonten haben keine Offene-Posten-Verwaltung.","alle Sachkonten":"Nicht alle Sachkonten haben Offene-Posten-Verwaltung."},"eselsbruecke":"Ausgleichen = nur bei OP-Verwaltung. Kein Häkchen 'OP-Verwaltung' → kein manueller Ausgleich möglich."},"source":"WBS"},{"id":"WBS-046","fragen_id":"5044659","thema":"Anlagenbuchhaltung","frage":"Welche der folgenden Objekte aus dem Bereich Controlling lassen sich in einem Anlagenstammsatz hinterlegen?","typ":"multiple_select","optionen":["Auftrag","Kostenart","Leistungsart","Kostenstelle","Profit Center"],"richtige_antworten":["Auftrag","Leistungsart","Kostenstelle"],"erklaerung":{"richtig":"Im Anlagenstammsatz können CO-Objekte für die Zuordnung hinterlegt werden: Kostenstelle (für Gemeinkosten), Innenauftrag (für spezifische Projekte) und Leistungsart (für die Leistungsverrechnung).","falsch":{"Kostenart":"Kostenarten sind Kategorien für Kosten, keine Zuordnungsobjekte im Anlagenstamm.","Profit Center":"Profit Center wird in S/4HANA automatisch aus der Kostenstelle abgeleitet, muss aber nicht direkt im Anlagenstamm hinterlegt werden."},"eselsbruecke":"Anlage → CO-Zuordnung: Kostenstelle (WO fallen Kosten an), Auftrag (WOFÜR), Leistungsart (WAS). Kostenart und Profit Center gehören nicht direkt rein."},"source":"WBS"},{"id":"WBS-047","fragen_id":"5044660","thema":"Zahlungsverkehr","frage":"Welche Parameter sind beim Buchen manueller Zahlungseingänge in allen Zahlungsbelegen gleich?","typ":"multiple_select","optionen":["Das Bankkonto","Der Kostenrechnungskreis","Die Buchungsbelegart","Das Aufwandskonto"],"richtige_antworten":["Das Bankkonto","Die Buchungsbelegart"],"erklaerung":{"richtig":"Beim manuellen Buchen von Zahlungseingängen ist für alle Belege eines Batches gleich: das Bankkonto (alle Zahlungen kommen auf dasselbe Konto) und die Buchungsbelegart (z.B. DZ für Debitorenzahlung).","falsch":{"Kostenrechnungskreis":"Der Kostenrechnungskreis ist ein CO-Parameter und nicht Bestandteil des Zahlungseingangs-Buchungsbelegs.","Aufwandskonto":"Ein Aufwandskonto ist bei normalen Zahlungseingängen nicht relevant."},"eselsbruecke":"Alle Zahlungen eines Tages auf dasselbe Bankkonto (Sammelverbuchung) mit derselben Belegart. Das ist das Gemeinsame."},"source":"WBS"},{"id":"WBS-048","fragen_id":"5044661","thema":"Korrespondenz","frage":"Welche Aussagen zu Korrespondenzarten sind richtig?","typ":"multiple_select","optionen":["Kontoauszüge, Offene-Posten-Liste, Belegauszüge, Zahlungsmitteilungen oder Wechselspesenabrechnungen sind Korrespondenzarten.","Korrespondenzarten umfassen Korrespondenzen gleichen Typs und sind einem Anwendungsbereich zugeordnet.","GuV, Bilanzanhang und BAB sind Korrespondenzarten.","Korrespondenzarten umfassen Korrespondenzen gleichen Typs und werden Buchungskreisen zugeordnet."],"richtige_antworten":["Kontoauszüge, Offene-Posten-Liste, Belegauszüge, Zahlungsmitteilungen oder Wechselspesenabrechnungen sind Korrespondenzarten.","Korrespondenzarten umfassen Korrespondenzen gleichen Typs und sind einem Anwendungsbereich zugeordnet."],"erklaerung":{"richtig":"Korrespondenzarten sind vordefinierte Dokumenttypen für die Kommunikation mit Geschäftspartnern: Kontoauszug, OP-Liste, Belegauszug, Zahlungsmitteilung, Wechselabrechnung. Sie werden einem Anwendungsbereich zugeordnet, nicht einem Buchungskreis.","falsch":{"GuV, Bilanz, BAB":"Das sind interne Rechnungslegungsberichte, keine Korrespondenzarten an Geschäftspartner.","Buchungskreisen zugeordnet":"Korrespondenzarten werden Anwendungsbereichen zugeordnet, nicht Buchungskreisen."},"eselsbruecke":"Korrespondenz = was schicke ich dem Kunden/Lieferanten. Kontoauszug, Zahlungsmitteilung etc. = Korrespondenzarten."},"source":"WBS"},{"id":"WBS-049","fragen_id":"5044662","thema":"Anlagenbuchhaltung","frage":"Welche Rechenmethoden werden Abschreibungsschlüsseln zugeordnet?","typ":"multiple_select","optionen":["Mehrwertsteuermethode","Höchstbetragsmethode","Stufenmethode","Basismethode","Schrottwertmethode","Degressivmethode","Periodenmethode","Skonto-Bewertungsmethode"],"richtige_antworten":["Höchstbetragsmethode","Stufenmethode","Basismethode","Degressivmethode","Periodenmethode"],"erklaerung":{"richtig":"Abschreibungsschlüssel bestehen aus verschiedenen Rechenmethoden: Basismethode (Grundberechnung), Degressivmethode (degressiver AfA), Periodenmethode (perioden-genaue Berechnung), Stufenmethode (stufenweise) und Höchstbetragsmethode (Begrenzung).","falsch":{"Mehrwertsteuermethode":"MwSt hat nichts mit Abschreibungsberechnung zu tun.","Schrottwertmethode":"Der Schrottwert ist ein Parameter, keine Rechenmethode des Abschreibungsschlüssels.","Skonto-Bewertungsmethode":"Skonto ist ein Zahlungsbegriff, keine Abschreibungsmethode."},"eselsbruecke":"AfA-Methoden: BASIS + DEGRESSIV + PERIODEN + STUFEN + HÖCHSTBETRAG. Alles andere gehört nicht zum Abschreibungsschlüssel."},"source":"WBS"},{"id":"WBS-050","fragen_id":"5044663","thema":"Anlagenbuchhaltung","frage":"Welche Aussagen zum Jahreswechsel sind zutreffend?","typ":"multiple_select","optionen":["Beim Jahreswechsel werden die Anlagenwerte des alten Geschäftsjahres in das neue Geschäftsjahr kumulativ vorgetragen.","Man kann auch bereits vor dem Jahreswechsel Geschäftsvorfälle in das neue Geschäftsjahr buchen.","Man kann auch nach einem bereits durchgeführten Jahreswechsel in das alte Geschäftsjahr buchen.","Vor einem Jahreswechsel können KEINE Geschäftsvorfälle in das neue Geschäftsjahr gebucht werden.","Man kann den Jahreswechsel frühestens im letzten Monat des laufenden Geschäftsjahres vornehmen."],"richtige_antworten":["Man kann auch nach einem bereits durchgeführten Jahreswechsel in das alte Geschäftsjahr buchen.","Vor einem Jahreswechsel können KEINE Geschäftsvorfälle in das neue Geschäftsjahr gebucht werden.","Man kann den Jahreswechsel frühestens im letzten Monat des laufenden Geschäftsjahres vornehmen."],"erklaerung":{"richtig":"Drei korrekte Aussagen: Nachbuchungen ins alte Jahr sind auch nach dem Jahreswechsel möglich (SAP korrigiert automatisch). Vor dem Jahreswechsel können KEINE Buchungen ins neue Jahr gemacht werden. Der Jahreswechsel ist frühestens im letzten Monat des laufenden Jahres möglich.","falsch":{"kumulativ vorgetragen":"Anlagenwerte werden nicht kumulativ vorgetragen — der neue Jahresanfangswert wird berechnet.","vor Jahreswechsel ins neue Jahr buchen":"Das ist falsch — erst nach dem Jahreswechsel können Buchungen ins neue Jahr gemacht werden."},"eselsbruecke":"Jahreswechsel in AA: frühestens im letzten Monat, danach noch alte Buchungen möglich, vorher kein neues Jahr. Das System passt alles automatisch an."},"source":"WBS"},{"id":"WBS-051","fragen_id":"5044664","thema":"Debitorische Anzahlung","frage":"Wobei handelt es sich um den ersten möglichen Schritt des Prozesses der debitorischen Anzahlung?","typ":"single_select","optionen":["Faktura","Anzahlungsmitteilung","Warenanforderung","Anzahlungsanforderung","Mahnung"],"richtige_antworten":["Anzahlungsanforderung"],"erklaerung":{"richtig":"Der debitorische Anzahlungsprozess beginnt mit der Anzahlungsanforderung. Das ist die Aufforderung an den Kunden, eine Vorauszahlung zu leisten — bevor die eigentliche Leistung erbracht oder die Ware geliefert wurde.","falsch":{"Faktura":"Die Faktura kommt am Ende des Prozesses nach der Leistungserbringung.","Anzahlungsmitteilung":"Die Mitteilung kommt nach der Anforderung, nicht davor.","Warenanforderung":"Eine Warenanforderung gehört zum MM-Prozess, nicht zum Anzahlungsprozess.","Mahnung":"Mahnungen kommen wenn nicht gezahlt wird — also erst sehr spät im Prozess."},"eselsbruecke":"Erst ANFORDERN (Anzahlungsanforderung), dann bekommt man das Geld, dann wird geliefert, dann Faktura. Logische Reihenfolge!"},"source":"WBS"},{"id":"WBS-052","fragen_id":"5044665","thema":"Sonderhauptbuchvorgänge","frage":"Welche Aussagen treffen auf Merkposten zu?","typ":"multiple_select","optionen":["Merkposten sind ein Sonderhauptbuchvorgang, der in der Buchhaltung nicht ausgewiesen wird.","Merkposten lassen sich mit dem Zahlungs- oder Mahnprogramm bearbeiten.","Technisch gesehen handelt es sich beim Merkposten um einen Sonderhauptbuchvorgang der Art 'Freie Gegenbuchung'.","Beim Merkposten wird im System keine Saldo-Null-Prüfung durchgeführt.","Beim Merkposten erfolgt keine Buchung auf ein Gegenkonto."],"richtige_antworten":["Merkposten sind ein Sonderhauptbuchvorgang, der in der Buchhaltung nicht ausgewiesen wird.","Merkposten lassen sich mit dem Zahlungs- oder Mahnprogramm bearbeiten.","Beim Merkposten wird im System keine Saldo-Null-Prüfung durchgeführt.","Beim Merkposten erfolgt keine Buchung auf ein Gegenkonto."],"erklaerung":{"richtig":"Alle fünf Aussagen sind korrekt. Der Merkposten ist ein besonderer Sonderhauptbuchvorgang: er wird nicht in der Bilanz ausgewiesen, hat keine Gegenbuchung, keine Saldo-Null-Prüfung, ist technisch eine 'freie Gegenbuchung' und kann trotzdem vom Mahn- und Zahlungsprogramm verarbeitet werden.","falsch":{},"eselsbruecke":"Merkposten = 'Ich merke mir den Betrag' — keine echte Buchung, kein Gegenkonto, kein Saldo-Check. Aber Mahnung und Zahlung klappt trotzdem!"},"source":"WBS"},{"id":"WBS-053","fragen_id":"5044666","thema":"Anlagenbuchhaltung","frage":"Was sollte man bei der Definition von Anlagen-Nummernkreisen berücksichtigen?","typ":"multiple_select","optionen":["Anlagen-Nummernkreise sind pro Anlagenklasse definiert und können buchungskreisspezifisch sein.","Anlageklassen können entweder interne oder externe Nummernvergabe haben.","Anlagen-Nummernkreise werden in der Hauptbuch-Tabelle hinterlegt.","Jeder Anlagen-Nummernkreis kann nur einer Anlagenklasse zugeordnet werden."],"richtige_antworten":["Anlagen-Nummernkreise sind pro Anlagenklasse definiert und können buchungskreisspezifisch sein.","Anlageklassen können entweder interne oder externe Nummernvergabe haben."],"erklaerung":{"richtig":"Anlagen-Nummernkreise werden in der Hauptbuch-Tabelle (nicht in einer separaten Anlagentabelle) hinterlegt. Jeder Nummernkreis kann nur einer Anlagenklasse zugeordnet werden — aber mehrere Klassen können denselben Nummernkreis teilen.","falsch":{"pro Anlagenklasse definiert und buchungskreisspezifisch":"Nummernkreise für Anlagen sind MANDANTENWEIT, nicht buchungskreisspezifisch.","interne oder externe Nummernvergabe":"Das stimmt zwar grundsätzlich, aber die Aussage ist hier unvollständig — die Nummernvergabe hängt am Nummernkreis, nicht direkt an der Klasse."},"eselsbruecke":"Anlagen-Nummernkreis: mandantenweit (nicht buchungskreisspezifisch!), in Hauptbuch-Tabelle, 1 Nummernkreis → 1 Klasse."},"source":"WBS"},{"id":"WBS-054","fragen_id":"5044667","thema":"Mahnwesen","frage":"Welche für das Mahnen relevanten Daten pflegt man in den Stammdaten des Geschäftspartners?","typ":"multiple_select","optionen":["Mahngründe","Mahnschlüssel","Mahnkonten","Mahnperiode","Mahnmerkmale","Mahnbereich"],"richtige_antworten":["Mahnschlüssel","Mahnbereich"],"erklaerung":{"richtig":"Im Geschäftspartnerstammsatz werden zwei Mahnfelder gepflegt: der Mahnschlüssel (steuert die maximale Mahnstufe für diesen Partner) und der Mahnbereich (welchem Mahnbereich dieser Partner zugeordnet ist).","falsch":{"Mahngründe":"Mahngründe werden auf einzelnen Posten gepflegt, nicht im Stammsatz.","Mahnkonten":"Mahnkonten sind Konfigurationsobjekte, keine Stammsatzfelder.","Mahnperiode":"Die Mahnperiode wird im Mahnverfahren definiert, nicht im Stammsatz.","Mahnmerkmale":"Mahnmerkmale werden auf Postenebene gesetzt, nicht im Stammsatz."},"eselsbruecke":"Im GP-Stammsatz: Mahnschlüssel (wie hoch mahnen?) + Mahnbereich (welcher Bereich). Alles andere gehört woanders hin."},"source":"WBS"},{"id":"WBS-055","fragen_id":"5044668","thema":"Datenarchivierung","frage":"Welche Gründe sprechen dafür, regelmäßig Datenarchivierungen in Ihrem SAP S/4HANA-System durchzuführen?","typ":"multiple_select","optionen":["Vereinfachung der Transaktionen","Schnellere Datenbanksicherungen","Verschlankung der betriebswirtschaftlichen Prozesse","Verringerung des Datenbank-Administrationsaufwandes","Verbesserung der System-Response-Zeiten"],"richtige_antworten":["Schnellere Datenbanksicherungen","Verringerung des Datenbank-Administrationsaufwandes","Verbesserung der System-Response-Zeiten"],"erklaerung":{"richtig":"Archivierung reduziert die Datenbankgröße — das führt zu schnelleren Backups, weniger Administrationsaufwand und besserer Performance (schnellere Antwortzeiten) da weniger Daten durchsucht werden müssen.","falsch":{"Vereinfachung der Transaktionen":"Archivierung verändert keine Transaktionslogik.","Verschlankung der betriebswirtschaftlichen Prozesse":"Geschäftsprozesse werden durch Archivierung nicht verändert."},"eselsbruecke":"Archivierung = weniger Daten im System = schneller (Response), kleiner (Backup), einfacher zu verwalten (Admin)."},"source":"WBS"},{"id":"WBS-056","fragen_id":"5044669","thema":"Sachkontenstammdaten","frage":"Welche Funktionen stehen bei der Sammelbearbeitung von Sachkontenstammdaten zur Verfügung?","typ":"multiple_select","optionen":["Buchungskreisdaten ändern","Mandantendaten ändern","Kontenbezeichnungen ändern","Kontenplandaten ändern","Geschäftsbereichsdaten ändern"],"richtige_antworten":["Buchungskreisdaten ändern","Kontenbezeichnungen ändern","Kontenplandaten ändern"],"erklaerung":{"richtig":"Bei der Sammelbearbeitung von Sachkonten können Buchungskreisdaten (z.B. Feldstatusvariante), Kontenbezeichnungen und Kontenplandaten (z.B. Kontengruppe) geändert werden — für viele Konten auf einmal.","falsch":{"Mandantendaten ändern":"Es gibt keine separate 'Mandantendaten'-Ebene bei Sachkonten in diesem Kontext.","Geschäftsbereichsdaten ändern":"Geschäftsbereiche sind keine eigene Ebene im Sachkontenstamm."},"eselsbruecke":"Sammelbearbeitung Sachkonten = Kontenplan + Buchungskreis + Bezeichnung. Massenänderung für viele Konten gleichzeitig."},"source":"WBS"},{"id":"WBS-057","fragen_id":"5044670","thema":"Debitorische Anzahlung","frage":"Was wird reduziert, wenn man eine Anzahlung von einem Kunden erhält?","typ":"single_select","optionen":["Anlagenvermögen","Forderungen","Verbindlichkeiten","Kassenbestand"],"richtige_antworten":["Forderungen"],"erklaerung":{"richtig":"Wenn ein Kunde eine Anzahlung leistet, werden die Forderungen gegen diesen Kunden reduziert — denn der Kunde schuldet uns nun weniger (er hat bereits im Voraus gezahlt). Gleichzeitig steigt das Bankkonto/Kassenbestand.","falsch":{"Anlagenvermögen":"Anlagenvermögen hat keinen Bezug zu Kundenanzahlungen.","Verbindlichkeiten":"Verbindlichkeiten sind Schulden gegenüber Lieferanten — eine Kundenanzahlung betrifft das nicht.","Kassenbestand":"Der Kassenbestand STEIGT bei Eingang der Zahlung — er wird nicht reduziert."},"eselsbruecke":"Kunde zahlt im Voraus → Forderung gegen Kunden sinkt. Einfache Logik: er hat schon gezahlt, also schuldet er weniger."},"source":"WBS"},{"id":"WBS-058","fragen_id":"5044671","thema":"SD/FI Integration","frage":"Wo werden Fakturen (Fakturabelege) erstellt?","typ":"single_select","optionen":["In der Finanzbuchhaltung (FI)","Im Controlling (CO)","In der Materialwirtschaft (MM)","Im Vertrieb (SD)"],"richtige_antworten":["Im Vertrieb (SD)"],"erklaerung":{"richtig":"Fakturen werden im SD-Modul (Vertrieb) erstellt — in der Transaktion VF01. Die Fakturierung in SD löst dann automatisch eine Buchung in FI aus (Debitorenrechnung). SD erstellt, FI bucht.","falsch":{"FI":"FI empfängt den Buchungsbeleg aus SD — erstellt die Faktura nicht selbst.","CO":"CO ist das interne Rechnungswesen — Fakturen gehören zum externen Prozess.","MM":"MM ist Einkauf/Materialwirtschaft — dort werden Lieferantenrechnungen verarbeitet, keine Kundenfakturen."},"eselsbruecke":"Fakturen = Rechnungen AN Kunden = Vertrieb (SD). Rechnungen VON Lieferanten = Einkauf (MM). SD verkauft, MM kauft."},"source":"WBS"},{"id":"WBS-059","fragen_id":"5044672","thema":"Buchungsschlüssel","frage":"Was wird mit dem Buchungsschlüssel bestimmt?","typ":"multiple_select","optionen":["Welche Benutzerrollen die Buchung durchführen dürfen","Soll- oder Haben-Buchung der Belegzeile","Bewegungsart","Kontoart","Die Gestaltung der Erfassungsbilder","Belegart","Kontrollkreis","Nummernkreis"],"richtige_antworten":["Soll- oder Haben-Buchung der Belegzeile","Kontoart","Die Gestaltung der Erfassungsbilder"],"erklaerung":{"richtig":"Der Buchungsschlüssel (2-stelliger numerischer Code, z.B. 40=Soll Sachkonto, 50=Haben Sachkonto) steuert drei Dinge: ob Soll oder Haben gebucht wird, welche Kontoart angesprochen wird (Sachkonto, Debitor, Kreditor, Anlage) und wie das Erfassungsbild aussieht.","falsch":{"Benutzerrollen":"Benutzerrollen werden im Berechtigungskonzept gesteuert, nicht im Buchungsschlüssel.","Bewegungsart":"Bewegungsarten sind ein MM/AA-Konzept, nicht des Buchungsschlüssels.","Belegart":"Die Belegart wird im Belegkopf bestimmt, nicht im Buchungsschlüssel.","Kontrollkreis":"Gibt es nicht als SAP-Standard-Feld.","Nummernkreis":"Nummernkreise hängen an der Belegart, nicht am Buchungsschlüssel."},"eselsbruecke":"Buchungsschlüssel = SOLL/HABEN + KONTOART + BILDGESTALTUNG. Der 2-stellige Code sagt: wo, wie und was."},"source":"WBS"},{"id":"WBS-060","fragen_id":"5044673","thema":"Sonderhauptbuchvorgänge","frage":"Welchen Vorteil hat es, Anzahlungen als Sonderhauptbuchvorgang zu buchen?","typ":"single_select","optionen":["Beim SHB-Vorgang wird automatisch in Echtzeit auf ein Profit Center gebucht.","Im Rahmen des SHB-Vorganges wird automatisch eine Rechnung über den Restposten erstellt.","Mit einem SHB-Vorgang kann man offene Anzahlungsanforderungen automatisch als erledigt markieren.","Mit dem SHB-Vorgang bucht man Anzahlungen auf ein Abstimmkonto, das von dem normalen Forderungs- oder Verbindlichkeits-Konto abweicht."],"richtige_antworten":["Mit dem SHB-Vorgang bucht man Anzahlungen auf ein Abstimmkonto, das von dem normalen Forderungs- oder Verbindlichkeits-Konto abweicht."],"erklaerung":{"richtig":"Der entscheidende Vorteil von Anzahlungs-SHB-Vorgängen: Anzahlungen landen auf einem SEPARATEN Abstimmkonto (z.B. 'erhaltene Anzahlungen'), nicht auf dem normalen Forderungskonto. Das verhindert eine falsche Saldierung und entspricht den handelsrechtlichen Anforderungen.","falsch":{"Profit Center in Echtzeit":"Das ist eine allgemeine S/4HANA-Funktion, kein spezifischer SHB-Vorteil.","automatisch Rechnung erstellen":"SHB-Vorgänge erstellen keine automatischen Rechnungen.","Anzahlungsanforderungen als erledigt":"Das stimmt nicht — Anzahlungsanforderungen müssen manuell ausgeglichen werden."},"eselsbruecke":"Anzahlung als SHB = eigenes Abstimmkonto. Normaler Kredit/Debitor-Saldo bleibt sauber. Gesetzliche Trennung von Anzahlung und Forderung."},"source":"WBS"},{"id":"WBS-061","fragen_id":"5044674","thema":"Substitution","frage":"Welche der folgenden Aussagen sind korrekt?","typ":"multiple_select","optionen":["In der Voraussetzung wird festgelegt, welche Bedingungen für die Durchführung der Substitution erfüllt sein müssen.","Substitutionen können jeweils nur einen Wert ersetzten.","Ein Substitutionsschritt besteht aus Voraussetzung, Substitutionswert(en) und Substitutions-Exit.","Der Substitutionswert ist ein numerischer Wert oder eine Buchstabenfolge, durch den bzw. die der eingegebene Wert ersetzt wird."],"richtige_antworten":["Ein Substitutionsschritt besteht aus Voraussetzung, Substitutionswert(en) und Substitutions-Exit.","Der Substitutionswert ist ein numerischer Wert oder eine Buchstabenfolge, durch den bzw. die der eingegebene Wert ersetzt wird.","In der Voraussetzung wird festgelegt, welche Bedingungen für die Durchführung der Substitution erfüllt sein müssen."],"erklaerung":{"richtig":"Eine Substitution ersetzt automatisch einen eingegebenen Wert durch einen vordefinierten Wert. Jeder Schritt besteht aus Voraussetzung (wann?), Substitutionswert (womit ersetzen?) und Exit (spezielle Logik). Der Wert kann numerisch oder alphanumerisch sein.","falsch":{"Voraussetzung legt Bedingungen fest":"Das ist zwar inhaltlich richtig, aber die Aussage ist hier falsch formuliert — die Voraussetzung ist eine Boole'sche Bedingung, die bestimmt WANN die Substitution greift."},"eselsbruecke":"Substitution = automatisches Ersetzen. WENN (Voraussetzung) DANN ersetze durch (Substitutionswert). Pro Schritt nur 1 Wert."},"source":"WBS"},{"id":"WBS-062","fragen_id":"5044675","thema":"Cloud / S4HANA","frage":"Welches sind Vorteile von Public Cloud in SAP S/4HANA?","typ":"multiple_select","optionen":["IT-Kostenreduzierung","Größere Transparenz der Firmenaktivitäten gegenüber der Öffentlichkeit","Kosteneinsparungen bei System-Migrationen","Man ist als Firma immer auf dem neuesten Stand"],"richtige_antworten":["IT-Kostenreduzierung","Man ist als Firma immer auf dem neuesten Stand"],"erklaerung":{"richtig":"Public Cloud senkt IT-Kosten (keine eigene Hardware/Infrastruktur nötig) und hält Unternehmen automatisch auf dem neuesten Stand (SAP rollt Updates automatisch aus).","falsch":{"Transparenz gegenüber Öffentlichkeit":"Cloud bedeutet nicht, dass Firmendaten öffentlich werden — das wäre ein Nachteil, kein Vorteil.","Kosteneinsparungen bei Migrationen":"Migrationen in die Cloud können teuer sein — das ist kein automatischer Vorteil."},"eselsbruecke":"Public Cloud Vorteile: GÜNSTIGER (keine eigene IT) + AKTUELL (automatische Updates). Keine öffentliche Transparenz!"},"source":"WBS"},{"id":"WBS-063","fragen_id":"5044676","thema":"Datenarchivierung","frage":"Was sollte man mit älteren Belegen tun, um die Systemlast zu verringern?","typ":"single_select","optionen":["Erfassen und dann löschen","In ein gespiegeltes System transportieren und dann löschen","Archivieren und dann löschen","Extrahieren und dann löschen"],"richtige_antworten":["Archivieren und dann löschen"],"erklaerung":{"richtig":"Der korrekte SAP-Prozess für alte Belege: erst archivieren (in ein Archivierungssystem auslagern, gesetzliche Aufbewahrungspflichten bleiben erfüllt), dann aus der Datenbank löschen. So bleibt das System schnell und die Daten sind trotzdem noch zugreifbar.","falsch":{"Erfassen und löschen":"Unsinnig — erfassen würde mehr Daten erzeugen.","gespiegeltes System":"Eine Kopie in ein anderes System verringert nicht die Last im Produktivsystem.","Extrahieren und löschen":"Extrahieren ohne Archivierung verletzt möglicherweise Aufbewahrungspflichten."},"eselsbruecke":"SAP-Regel: ARCHIVIEREN dann LÖSCHEN. Nie einfach nur löschen — gesetzliche Aufbewahrungspflicht! Archiv = sicher + zugreifbar."},"source":"WBS"},{"id":"WBS-064","fragen_id":"5044677","thema":"Toleranzgruppen","frage":"Was wird dabei von der Mitarbeiter-Toleranzgruppe gesteuert?","typ":"multiple_select","optionen":["Wieviel Prozent Skonto der Mitarbeiter für den gesamten Beleg gewähren darf","Bis zu welchem Gesamtbetrag der Mitarbeiter einen Beleg buchen darf","Wieviel Skonto (absoluter Betrag) der Mitarbeiter pro Belegposition gewähren darf","Bis zu welchem Betrag der Mitarbeiter eine Belegposition auf ein Debitoren- oder Kreditorenkonto buchen darf","Wieviel Prozent Skonto der Mitarbeiter pro Belegposition gewähren darf","Bis zu welcher Höhe Zahlungsdifferenzen akzeptiert werden dürfen"],"richtige_antworten":["Wieviel Prozent Skonto der Mitarbeiter für den gesamten Beleg gewähren darf","Wieviel Skonto (absoluter Betrag) der Mitarbeiter pro Belegposition gewähren darf","Bis zu welchem Betrag der Mitarbeiter eine Belegposition auf ein Debitoren- oder Kreditorenkonto buchen darf","Wieviel Prozent Skonto der Mitarbeiter pro Belegposition gewähren darf","Bis zu welcher Höhe Zahlungsdifferenzen akzeptiert werden dürfen"],"erklaerung":{"richtig":"Die Mitarbeiter-Toleranzgruppe steuert fünf Grenzen: Skonto % gesamt, Skonto absolut pro Position, maximaler Buchungsbetrag pro Debitor/Kreditor-Position, Skonto % pro Position und maximale Zahlungsdifferenz.","falsch":{"Gesamtbetrag des Belegs":"Der Gesamtbetrag des Belegs wird NICHT durch die Mitarbeiter-Toleranzgruppe begrenzt — nur einzelne Positionen auf Debitoren/Kreditoren."},"eselsbruecke":"Toleranzgruppe = wie viel Spielraum hat der Buchhalter? Skonto (% und absolut), Positionsbetrag, Differenzen. Nicht der Gesamtbeleg!"},"source":"WBS"},{"id":"WBS-065","fragen_id":"5044678","thema":"Anlagenbuchhaltung","frage":"Woran erkennt man eine Anlage im Bau (AiB) eindeutig?","typ":"single_select","optionen":["An der Anlagenklasse.","Die Anlage hat eine alphanumerische Nummer.","Es gibt keine Abschreibung.","Die Anlage ist nicht aktiviert.","Die Anlage hat keine zugeordnete Kostenstelle."],"richtige_antworten":["An der Anlagenklasse."],"erklaerung":{"richtig":"Eine AiB wird EINDEUTIG durch ihre Anlagenklasse identifiziert. In SAP gibt es spezielle Anlagenklassen für Anlagen im Bau (z.B. Klasse 4000). Die Anlagenklasse ist das einzige zuverlässige Erkennungsmerkmal.","falsch":{"alphanumerische Nummer":"AiB-Nummern sind numerisch wie andere Anlagen auch.","keine Abschreibung":"Zwar haben AiB typischerweise keine planmäßige AfA, aber das allein ist kein eindeutiges Merkmal.","nicht aktiviert":"Aktivierung ist kein technisches Feld das man direkt sieht — die Klasse ist eindeutiger.","keine Kostenstelle":"Viele AiB haben sehr wohl Kostenstellen."},"eselsbruecke":"AiB erkennen = Anlagenklasse prüfen. Die Klasse DEFINIERT ob es eine AiB ist. Alle anderen Merkmale sind unzuverlässig."},"source":"WBS"},{"id":"WBS-066","fragen_id":"5044679","thema":"S/4HANA Vorteile","frage":"Was sind einige der Vorteile von SAP S/4HANA?","typ":"multiple_select","optionen":["Die Daten werden innerhalb kürzester Zeit aus jeder beliebigen Positionstabelle extrahiert.","Daten sind bis hinunter auf Einzelpostenebene in Echtzeit verfügbar.","Die Bewegungsdaten werden in einem eigenen System analysiert.","Die Daten werden auf einer übergeordneten Organisationsebene zusammengefasst, um Speicherplatz zu sparen."],"richtige_antworten":["Die Bewegungsdaten werden in einem eigenen System analysiert.","Die Daten werden auf einer übergeordneten Organisationsebene zusammengefasst, um Speicherplatz zu sparen."],"erklaerung":{"richtig":"S/4HANA-Vorteile: Bewegungsdaten können in einem separaten Analysesystem (z.B. BW/4HANA) ausgewertet werden ohne das Produktivsystem zu belasten. Datenaggregation auf höheren Ebenen spart Speicherplatz durch das vereinfachte Datenmodell.","falsch":{"kürzester Zeit aus Positionstabelle":"In S/4HANA gibt es keine klassischen Positionstabellen mehr — das Datenmodell wurde vereinfacht.","Einzelpostenebene in Echtzeit":"S/4HANA aggregiert Daten gerade NICHT auf Einzelpostenebene — das ist das alte R/3-Modell."},"eselsbruecke":"S/4HANA = vereinfachtes Datenmodell + Trennung von Produktion und Analyse. Weniger Tabellen, schnellere Verarbeitung."},"source":"WBS"},{"id":"WBS-067","fragen_id":"5044680","thema":"Sachkontenstammdaten","frage":"Welche Aussagen treffen zu?","typ":"multiple_select","optionen":["Die Nutzung der Bilanz-/GuV-Struktur für den Konzernkontenplan ist optional.","Das Kennzeichen 'Salden nur in Hauswährung' ist für gewöhnlich in Bilanzkonten aktiviert, die weder Offene Posten noch Fremdwährungen führen.","Konten, die eine Fremdwährung als Kontowährung haben, können in jeder Währung bebucht werden.","Man kann einen Konzernkontenplan für Zwecke des internen Rechnungswesens verwenden.","Erfolgskonten können nur über Abstimmkonten bebucht werden.","Abstimmkonten können nicht direkt bebucht werden.","Man kann einen Kostenrechnungsplan für Zwecke des internen Rechnungswesens verwenden.","Das Kennzeichen 'Salden nur in Hauswährung' darf in Abstimmkonten für Kreditoren und Debitoren nicht aktiviert sein."],"richtige_antworten":["Das Kennzeichen 'Salden nur in Hauswährung' ist für gewöhnlich in Bilanzkonten aktiviert, die weder Offene Posten noch Fremdwährungen führen.","Man kann einen Konzernkontenplan für Zwecke des internen Rechnungswesens verwenden.","Abstimmkonten können nicht direkt bebucht werden.","Man kann einen Kostenrechnungsplan für Zwecke des internen Rechnungswesens verwenden.","Das Kennzeichen 'Salden nur in Hauswährung' darf in Abstimmkonten für Kreditoren und Debitoren nicht aktiviert sein."],"erklaerung":{"richtig":"Fünf korrekte Aussagen: 'Salden nur Hauswährung' = Standard für normale Bilanzkonten. Konzernkontenplan kann für internes RW genutzt werden. Abstimmkonten sind schreibgeschützt (nur indirekt über Nebenbuch). Kostenrechnungsplan für internes RW möglich. Abstimmkonten dürfen 'Salden nur Hauswährung' NICHT haben (wegen Fremdwährungs-Kreditoren).","falsch":{"Bilanz/GuV für Konzernkontenplan optional":"Die Bilanz/GuV-Struktur ist für den Konzernkontenplan nicht optional — sie ist erforderlich.","Fremdwährungskonto in jeder Währung":"Ein Konto mit Fremdwährung als Kontowährung kann NUR in dieser Währung bebucht werden.","Erfolgskonten nur über Abstimmkonten":"Erfolgskonten werden direkt gebucht — Abstimmkonten sind nur für Debi/Kredit."},"eselsbruecke":"Abstimmkonten = kein direktes Buchen! Fremdwährungskonto = nur in dieser Währung. Debi/Kredit-Abstimmkonto = nie 'nur Hauswährung'."},"source":"WBS"},{"id":"WBS-068","fragen_id":"5044681","thema":"Steuerbehandlung","frage":"Wie unterstützt SAP S/4HANA die Handhabung von Steuern?","typ":"multiple_select","optionen":["Der Steuerbetrag wird automatisch auf Steuerkonten gebucht.","Das System überprüft den eingegebenen Steuerbetrag und berechnet die Steuer automatisch.","Es werden automatische Steueranpassungen für Skonti und andere Formen von Abzügen durchgeführt.","Das System gleicht die Steuerkennzeichen mit Tabellen des Finanzamtes ab."],"richtige_antworten":["Der Steuerbetrag wird automatisch auf Steuerkonten gebucht.","Das System überprüft den eingegebenen Steuerbetrag und berechnet die Steuer automatisch.","Es werden automatische Steueranpassungen für Skonti und andere Formen von Abzügen durchgeführt."],"erklaerung":{"richtig":"SAP verarbeitet Steuern vollautomatisch: Buchung auf Steuerkonten, Prüfung/Berechnung des Steuerbetrags und Anpassung bei Skonto (da Skonto die Steuerbemessungsgrundlage verändert).","falsch":{"Abgleich mit Finanzamt-Tabellen":"SAP kommuniziert nicht in Echtzeit mit dem Finanzamt — Steuertabellen müssen manuell im System gepflegt werden."},"eselsbruecke":"SAP Steuer: automatisch buchen + prüfen + bei Skonto anpassen. Aber: kein Echtzeit-Abgleich mit dem Finanzamt!"},"source":"WBS"},{"id":"WBS-069","fragen_id":"5044682","thema":"Anlagenbuchhaltung","frage":"Welche Bewertungsparameter von Anlagen sind zeitabhängig?","typ":"multiple_select","optionen":["Der variable Abschreibungsanteil","Das Buchungsdatum des Anlagenzuganges","Das Abschreibungsbeginndatum","Der Schrottwert","Die Nutzungsdauer","Der Abschreibungsschlüssel"],"richtige_antworten":["Der variable Abschreibungsanteil","Der Schrottwert","Die Nutzungsdauer","Der Abschreibungsschlüssel"],"erklaerung":{"richtig":"Zeitabhängige Parameter können sich im Laufe der Anlagennutzung ändern und SAP führt eine History: variabler Abschreibungsanteil, Schrottwert, Nutzungsdauer und Abschreibungsschlüssel können für verschiedene Zeiträume unterschiedlich sein.","falsch":{"Buchungsdatum des Zugangs":"Das Zugangsdatum ist ein festes historisches Datum — es ändert sich nie.","Abschreibungsbeginndatum":"Das Beginndatum der AfA ist ebenfalls ein festes Datum, nicht zeitabhängig."},"eselsbruecke":"Zeitabhängig = kann sich ändern und SAP merkt sich die History. Schlüssel, Nutzungsdauer, Schrottwert, variabler Anteil. Datum = fix, nicht zeitabhängig."},"source":"WBS"},{"id":"WBS-070","fragen_id":"5044683","thema":"SEPA / Zahlungsverkehr","frage":"Welche Aussagen sind korrekt?","typ":"multiple_select","optionen":["Auch wenn der Zahlungsverkehr im SEPA-Raum ausschließlich in EURO abgewickelt wird, gibt es SEPA-Länder mit anderer Landeswährung.","Das SEPA-Lastschriftverfahren ist ausschließlich in EURO.","Daten zu abweichenden Regulierern auf Buchungskreisebene übersteuern die entsprechenden Daten auf Mandantenebene.","Für jedes Konto bei einer Hausbank sind die Beträge vorgegeben, die je Zahllauf maximal zur Verfügung stehen.","Daten auf Mandantenebene übersteuern die entsprechenden Daten auf Buchungskreisebene."],"richtige_antworten":["Auch wenn der Zahlungsverkehr im SEPA-Raum ausschließlich in EURO abgewickelt wird, gibt es SEPA-Länder mit anderer Landeswährung.","Das SEPA-Lastschriftverfahren ist ausschließlich in EURO.","Daten zu abweichenden Regulierern auf Buchungskreisebene übersteuern die entsprechenden Daten auf Mandantenebene.","Für jedes Konto bei einer Hausbank sind die Beträge vorgegeben, die je Zahllauf maximal zur Verfügung stehen."],"erklaerung":{"richtig":"SEPA-Fakten: Zahlungen in Euro, aber z.B. Schweden (SEK) oder Polen (PLN) sind SEPA-Mitglieder. SEPA-Lastschrift nur Euro. Buchungskreisebene übersteuert Mandantenebene (spezifischer geht vor allgemein). Jedes Hauskonto hat ein Zahlungslimit.","falsch":{"Mandantenebene übersteuert Buchungskreisebene":"Falsch — es ist genau umgekehrt. Buchungskreis (spezifisch) übersteuert Mandant (allgemein)."},"eselsbruecke":"SEPA = Euro-Zahlungen, aber nicht alle SEPA-Länder haben Euro als Währung. Buchungskreis-Daten schlagen Mandanten-Daten."},"source":"WBS"},{"id":"WBS-071","fragen_id":"5044684","thema":"Belegvorerfassung","frage":"Was bietet die Funktion 'Belege vorerfassen' gegenüber 'Belege merken'?","typ":"multiple_select","optionen":["Vorerfasste Belege können auch direkt aus dem Modul HCM gebucht werden.","Der User wird bei vorerfassten Belegen am Ende einer Periode automatisch daran erinnert, den Beleg zu buchen.","Vorerfasste Belege können, im Gegensatz zu gemerkten Belegen, immer auch buchungskreisübergreifend gebucht werden.","Mit der Funktion 'Beleg vorerfassen' kann man das Prinzip der Vier-Augen-Prüfung unterstützen.","Ein vorerfasster Beleg kann im Rahmen eines Workflows gebucht werden.","Vorerfasste Belege unterliegen dem erweiterten Freigabeverfahren."],"richtige_antworten":["Mit der Funktion 'Beleg vorerfassen' kann man das Prinzip der Vier-Augen-Prüfung unterstützen.","Ein vorerfasster Beleg kann im Rahmen eines Workflows gebucht werden.","Vorerfasste Belege unterliegen dem erweiterten Freigabeverfahren."],"erklaerung":{"richtig":"Vorerfassung (Parken) bietet gegenüber Merken drei Vorteile: Vier-Augen-Prinzip (Person A parkt, Person B bucht), Workflow-Integration (automatische Freigabeprozesse) und erweitertes Freigabeverfahren.","falsch":{"aus HCM buchen":"HCM (Human Capital Management) hat keinen direkten Bezug zur FI-Belegvorerfassung.","Erinnerung am Periodenende":"Es gibt keine automatische Erinnerungsfunktion für vorerfasste Belege.","buchungskreisübergreifend":"Das ist kein spezifischer Vorteil von Vorerfassung gegenüber Merken."},"eselsbruecke":"Vorerfassen > Merken weil: Vier-Augen + Workflow + Freigabeverfahren. Merken ist nur temporäre Speicherung für eine Person."},"source":"WBS"},{"id":"WBS-072","fragen_id":"5044685","thema":"Mahnwesen","frage":"Wie lautet die korrekte Reihenfolge der Arbeitsschritte bei Verwendung des Mahnprogrammes?","typ":"single_select","optionen":["Mahnlauf einplanen → Mahnvorschlag ändern → Parameter pflegen → Mahndruck starten","Mahndruck starten → Mahnvorschlag ändern → Parameter pflegen → Mahnlauf einplanen","Parameter pflegen → Mahnvorschlag planen → Mahnlauf einplanen → Mahndruck ändern","Parameter pflegen → Mahnlauf ausführen → Mahndruck planen → Mahndruck starten"],"richtige_antworten":["Parameter pflegen → Mahnlauf ausführen → Mahndruck planen → Mahndruck starten"],"erklaerung":{"richtig":"Die korrekte Reihenfolge im Mahnprogramm (F150): 1. Parameter pflegen (Datum, Buchungskreis, Geschäftspartner), 2. Mahnlauf ausführen (Mahnvorschlag erstellen), 3. Mahndruck planen (Druckparameter festlegen), 4. Mahndruck starten (Mahnungen ausgeben).","falsch":{"Mahnlauf einplanen zuerst":"Man kann nicht mahnen bevor man Parameter gepflegt hat.","Mahndruck starten zuerst":"Drucken ohne vorherigen Mahnlauf ist nicht möglich.","Mahnvorschlag planen":"Der Begriff 'Mahnvorschlag planen' ist nicht korrekt — es heißt 'Mahnlauf ausführen'."},"eselsbruecke":"Mahnprogramm-Reihenfolge: PARAMETER → LAUF → DRUCK PLANEN → DRUCK STARTEN. Wie beim Kochen: erst Rezept (Parameter), dann kochen (Lauf), dann anrichten (planen), dann servieren (starten)."},"source":"WBS"},{"id":"WBS-073","fragen_id":"5044686","thema":"Sonderhauptbuchvorgänge","frage":"Welche Varianten von Sonderhauptbuchvorgängen gibt es?","typ":"multiple_select","optionen":["Buchungen von Scheckzahlungen","Vorerfasste Belege","Merkposten","Abgrenzungsbuchungen","Freie Gegenbuchung","Eingeschränkte Teilbuchung","Automatische Gegenbuchung"],"richtige_antworten":["Merkposten","Freie Gegenbuchung","Automatische Gegenbuchung"],"erklaerung":{"richtig":"Die drei technischen Varianten von Sonderhauptbuchvorgängen sind: Merkposten (ohne Gegenbuchung), Freie Gegenbuchung (z.B. Wechsel — Gegenkonto wird beim Buchen frei gewählt) und Automatische Gegenbuchung (festgelegte Gegenbuchung, z.B. Bürgschaft).","falsch":{"Scheckzahlungen":"Scheckzahlungen sind normale Zahlungsbuchungen, keine SHB-Vorgänge.","Vorerfasste Belege":"Vorerfassung ist eine Buchungsfunktion, keine SHB-Variante.","Abgrenzungsbuchungen":"Abgrenzungen sind zwar SHB-Vorgänge, aber keine eigene technische Variante — sie nutzen die drei genannten.","Eingeschränkte Teilbuchung":"Dieser Begriff ist keine SAP-Standard-SHB-Variante."},"eselsbruecke":"3 SHB-Typen: OHNE Gegenbuchung (Merkposten), FREIE Gegenbuchung (Wechsel), AUTOMATISCHE Gegenbuchung (Bürgschaft). Nur diese 3!"},"source":"WBS"},{"id":"WBS-074","fragen_id":"5044687","thema":"Mahnwesen","frage":"Welche der folgenden Aussagen sind zutreffend?","typ":"multiple_select","optionen":["Mit dem Mahnschlüssel kann man die maximal mögliche Mahnstufe für einen Posten festlegen.","Ein Mahnverfahren muss mindestens zwei Mahnstufen haben.","Gesperrte Konten und/oder Posten werden im Mahnlauf nicht berücksichtigt und in einer Ausnahmeliste ausgegeben."],"richtige_antworten":["Mit dem Mahnschlüssel kann man die maximal mögliche Mahnstufe für einen Posten festlegen.","Gesperrte Konten und/oder Posten werden im Mahnlauf nicht berücksichtigt und in einer Ausnahmeliste ausgegeben."],"erklaerung":{"richtig":"Der Mahnschlüssel auf einem Posten begrenzt wie hoch dieser Posten gemahnt werden kann (z.B. maximal Stufe 2). Gesperrte Konten/Posten werden übersprungen aber in einer Ausnahmeliste protokolliert.","falsch":{"mindestens zwei Mahnstufen":"Falsch — ein Mahnverfahren kann auch nur eine einzige Mahnstufe haben (mindestens 1, nicht 2)."},"eselsbruecke":"Mahnschlüssel = Bremse für maximale Mahnstufe. Gesperrt = nicht mahnen aber protokollieren. Minimum = 1 Stufe (nicht 2!)."},"source":"WBS"},{"id":"WBS-075","fragen_id":"5044688","thema":"Stornierung","frage":"Welcher der folgenden Sätze beschreibt den Vorgang einer Stornierung im FI (keine Negativbuchung) am besten?","typ":"single_select","optionen":["Sie macht die Buchung rückgängig und erhöht dadurch die Verkehrszahlen, jedoch ausschließlich im Controlling.","Sie macht die Buchung rückgängig. Die Verkehrszahlen werden dabei weder erhöht noch reduziert.","Sie macht die Buchung rückgängig und reduziert dabei die Verkehrszahlen.","Sie macht die Buchung rückgängig, erhöht jedoch die Verkehrszahlen."],"richtige_antworten":["Sie macht die Buchung rückgängig, erhöht jedoch die Verkehrszahlen."],"erklaerung":{"richtig":"Eine normale Stornierung (Normalstorno, keine Negativbuchung) bucht die ursprüngliche Buchung mit umgekehrten Vorzeichen — das macht den Saldo null, aber die Verkehrszahlen (Summe aller Buchungen) steigen. Der Originalbeleg + Stornobeleg sind beide sichtbar.","falsch":{"nur im Controlling":"Die Verkehrszahlen steigen überall, nicht nur im CO.","weder erhöht noch reduziert":"Das wäre die Negativbuchung (echter Storno) — dort werden Verkehrszahlen reduziert.","reduziert Verkehrszahlen":"Das ist die Negativbuchung, nicht der Normalstorno."},"eselsbruecke":"Normalstorno = Gegenbuchung → Saldo = 0, aber Verkehrszahlen steigen (beide Buchungen zählen). Negativbuchung = Verkehrszahlen sinken (als ob nie gebucht)."},"source":"WBS"},{"id":"WBS-076","fragen_id":"5044689","thema":"Belegvorerfassung","frage":"Welche Felder kann man in vorerfassten Belegen NICHT ändern?","typ":"multiple_select","optionen":["Kurztext","Kostenstelle","Buchungskreis","Belegpositionen","Währung","Betrag"],"richtige_antworten":["Buchungskreis","Währung"],"erklaerung":{"richtig":"In vorerfassten Belegen sind Buchungskreis und Währung gesperrt — diese grundlegenden Strukturdaten können nach der Vorerfassung nicht mehr geändert werden da sie die Buchungslogik grundlegend beeinflussen.","falsch":{"Kurztext":"Kurztext ist änderbar — es ist ein Beschreibungsfeld.","Kostenstelle":"Kostenstellen können in vorerfassten Belegen geändert werden.","Belegpositionen":"Belegpositionen können geändert werden — das ist ja der Sinn der Vorerfassung.","Betrag":"Betrag kann geändert werden — im Gegensatz zu gebuchten Belegen."},"eselsbruecke":"Vorerfasster Beleg: fast alles änderbar AUSSER Buchungskreis und Währung. Diese beiden definieren den Rahmen der Buchung."},"source":"WBS"},{"id":"WBS-077","fragen_id":"5044690","thema":"Zahlungsbedingungen","frage":"Wo kann man die Zahlungsbedingungen von Kunden- oder Lieferantenstammsätzen pflegen?","typ":"multiple_select","optionen":["Mandantenebene","Geschäftsbereichsebene","Vertriebsbereichsebene","Buchungskreisebene","Einkaufsorganisationsebene"],"richtige_antworten":["Vertriebsbereichsebene","Buchungskreisebene","Einkaufsorganisationsebene"],"erklaerung":{"richtig":"Zahlungsbedingungen werden auf drei Ebenen gepflegt: Buchungskreisebene (FI-Sicht), Vertriebsbereichsebene (SD-Sicht für Kunden) und Einkaufsorganisationsebene (MM-Sicht für Lieferanten).","falsch":{"Mandantenebene":"Die Mandantenebene enthält allgemeine Adressdaten, keine Zahlungsbedingungen.","Geschäftsbereichsebene":"Geschäftsbereiche sind keine eigene Pflegeebene für Zahlungsbedingungen."},"eselsbruecke":"Zahlungsbedingungen: FI = Buchungskreis, SD = Vertriebsbereich, MM = Einkaufsorganisation. Drei Module, drei Ebenen."},"source":"WBS"},{"id":"WBS-078","fragen_id":"5044691","thema":"Anlagenbuchhaltung","frage":"Welche Aussagen zu Anlagen sind korrekt?","typ":"multiple_select","optionen":["Man kann eine Anlage mit einer bereits existierenden Anlage als Vorlage anlegen.","Beim Anlegen einer Anlage muss man entscheiden, zu welcher Anlagenklasse sie gehört.","Geringwertige Wirtschaftsgüter (GWG) benötigen KEINEN speziellen Abschreibungsschlüssel.","Für Massenänderungen von Anlagen lässt sich ein Arbeitsvorrat anlegen und freigeben.","Geringwertige Wirtschaftsgüter werden normalerweise im Jahr ihrer Anschaffung voll abgeschrieben."],"richtige_antworten":["Man kann eine Anlage mit einer bereits existierenden Anlage als Vorlage anlegen.","Beim Anlegen einer Anlage muss man entscheiden, zu welcher Anlagenklasse sie gehört.","Für Massenänderungen von Anlagen lässt sich ein Arbeitsvorrat anlegen und freigeben.","Geringwertige Wirtschaftsgüter werden normalerweise im Jahr ihrer Anschaffung voll abgeschrieben."],"erklaerung":{"richtig":"Vier korrekte Aussagen: Referenzanlage als Vorlage möglich. Anlagenklasse ist beim Anlegen Pflicht. Massenänderungen über Arbeitsvorrat. GWG werden im Zugangsjahr vollständig abgeschrieben (steuerrechtlich bis 800€).","falsch":{"GWG benötigen keinen Abschreibungsschlüssel":"Falsch — GWG benötigen sehr wohl einen speziellen Abschreibungsschlüssel (z.B. für Sofortabschreibung)."},"eselsbruecke":"GWG = Sofortabschreibung im Zugangsjahr, ABER mit speziellem AfA-Schlüssel. Anlagenklasse bei Anlegen = Pflicht, nicht optional."},"source":"WBS"},{"id":"WBS-079","fragen_id":"5044692","thema":"Anlagenbuchhaltung","frage":"Welche Parameter sind im Bewertungsbereich des Anlagenstammsatzes definiert?","typ":"multiple_select","optionen":["Schrottwert","Nutzungsdauer","Abschreibungsbeginn","Beschreibung der Anlage","Kostenstellenzuordnung"],"richtige_antworten":["Schrottwert","Nutzungsdauer","Abschreibungsbeginn"],"erklaerung":{"richtig":"Im Bewertungsbereich (Reiter 'AfA-Bereiche') des Anlagenstammsatzes stehen alle bewertungsrelevanten Parameter: Schrottwert (Restwert am Ende), Nutzungsdauer (wie lange wird abgeschrieben) und Abschreibungsbeginn (ab wann).","falsch":{"Beschreibung der Anlage":"Die Beschreibung steht im allgemeinen Reiter, nicht im Bewertungsbereich.","Kostenstellenzuordnung":"Die Kostenstelle ist eine zeitabhängige Zuordnung im Organisationsreiter, nicht im Bewertungsbereich."},"eselsbruecke":"Bewertungsbereich = alles was mit AfA zu tun hat: WIE LANGE (Nutzungsdauer), AB WANN (Beginn), BIS WO (Schrottwert)."},"source":"WBS"},{"id":"WBS-080","fragen_id":"5044693","thema":"MM/FI Integration","frage":"Welche der folgenden Aktionen können ausschließlich in der Materialwirtschaft (MM), jedoch nicht in der Finanzbuchhaltung (FI) ausgeführt werden?","typ":"multiple_select","optionen":["Anlegen einer Anfrage","Anlegen einer Bestellung","Stornierung","Buchung einer Gutschrift","Buchung einer Rechnung"],"richtige_antworten":["Anlegen einer Anfrage","Anlegen einer Bestellung"],"erklaerung":{"richtig":"Anfragen (Preisanfragen an Lieferanten) und Bestellungen sind ausschließlich MM-Vorgänge — sie existieren in FI nicht. Diese Dokumente werden nur in der Materialwirtschaft erstellt.","falsch":{"Stornierung":"Stornierungen gibt es in beiden Modulen (FI und MM).","Buchung einer Gutschrift":"Gutschriften können in FI (Kreditorengutschrift) und MM gebucht werden.","Buchung einer Rechnung":"Rechnungen können in FI direkt oder über MM (Rechnungsprüfung) gebucht werden."},"eselsbruecke":"Nur MM: Anfrage + Bestellung (das sind Einkaufsdokumente). Storno, Gutschrift, Rechnung = in beiden Modulen möglich."},"source":"WBS"},{"id":"WBS-081","fragen_id":"5044694","thema":"SAP GUI / ALV","frage":"Über welche Funktionalitäten verfügt eine eingabefähige ALV-Liste (SAP List Viewer)?","typ":"multiple_select","optionen":["Drucker einrichten","Spalten löschen oder einfügen","Summen und Zwischensummen bilden","Diagramme erstellen","Filtern"],"richtige_antworten":["Spalten löschen oder einfügen","Filtern"],"erklaerung":{"richtig":"Eine eingabefähige ALV-Liste ermöglicht Spalten anzupassen (löschen/einfügen) und Daten zu filtern. Das sind die kernfunktionalen Möglichkeiten für die interaktive Arbeit.","falsch":{"Drucker einrichten":"Druckereinrichtung ist eine systemweite Einstellung, keine ALV-Funktion.","Summen und Zwischensummen":"Summen bilden ist eine Funktion der normalen ALV-Anzeige, nicht spezifisch für eingabefähige Listen.","Diagramme erstellen":"Diagramme sind in Standard-ALV nicht direkt integriert."},"eselsbruecke":"ALV eingabefähig = ich kann die Spalten anpassen (einfügen/löschen) und filtern. Das macht sie 'interaktiv'."},"source":"WBS"},{"id":"WBS-082","fragen_id":"5044695","thema":"Mahnwesen","frage":"Welche Aussagen treffen zu?","typ":"multiple_select","optionen":["Mit der Mahnsperre lässt sich ein Konto oder ein einzelner Posten zum Mahnen sperren.","Pro Buchungskreis kann man höchstens ein Mahnverfahren definieren.","In der Konfiguration des Mahnprogrammes gibt man Kriterien an, die für die Mahnbarkeit eines Kontos oder der offenen Posten entscheidend sind.","Man kann nicht nur Debitoren, sondern auch Kreditoren mahnen."],"richtige_antworten":["Mit der Mahnsperre lässt sich ein Konto oder ein einzelner Posten zum Mahnen sperren.","In der Konfiguration des Mahnprogrammes gibt man Kriterien an, die für die Mahnbarkeit eines Kontos oder der offenen Posten entscheidend sind.","Man kann nicht nur Debitoren, sondern auch Kreditoren mahnen."],"erklaerung":{"richtig":"Die Mahnkonfiguration legt fest welche Bedingungen erfüllt sein müssen damit gemahnt wird. Und ja — auch Kreditoren können gemahnt werden (z.B. bei Lieferverzug oder wenn ein Kreditor uns Geld schuldet).","falsch":{"Mahnsperre nur Konto oder Posten":"Die Mahnsperre kann auf Kontoebene UND auf Postenebene gesetzt werden — das ist korrekt. Aber die Aussage 'lässt sich... sperren' ist zu eingeschränkt formuliert.","höchstens ein Mahnverfahren pro Buchungskreis":"Pro Buchungskreis können MEHRERE Mahnverfahren definiert werden (z.B. unterschiedliche für verschiedene Kundengruppen)."},"eselsbruecke":"Mehrere Mahnverfahren pro Buchungskreis möglich! Kreditoren können auch gemahnt werden. Konfiguration = Mahnbarkeitskriterien."},"source":"WBS"},{"id":"WBS-083","fragen_id":"5044696","thema":"Validierung / Substitution","frage":"Welche Validierungs- bzw. Substitutionszeitpunkte gibt es in der Finanzbuchhaltung (FI)?","typ":"multiple_select","optionen":["Spalte Betrag (Zeitpunkt 0003)","Gesamter Beleg (Zeitpunkt 0003)","Spalte Kurztext (Zeitpunkt 0001)","Belegzeile (Zeitpunkt 0002)","Spalte Steuerkennzeichen (Zeitpunkt 0002)","Belegkopf (Zeitpunkt 0001)"],"richtige_antworten":["Gesamter Beleg (Zeitpunkt 0003)","Belegzeile (Zeitpunkt 0002)","Belegkopf (Zeitpunkt 0001)"],"erklaerung":{"richtig":"In FI gibt es drei Zeitpunkte für Validierungen/Substitutionen: 0001 = Belegkopf (wird beim Eingeben des Kopfes geprüft), 0002 = Belegzeile (wird beim Eingeben jeder Zeile geprüft), 0003 = Gesamter Beleg (wird beim Sichern des kompletten Belegs geprüft).","falsch":{"Spalte Betrag":"Es gibt keinen Zeitpunkt für einzelne Spalten — nur für Kopf, Zeile und Gesamtbeleg.","Spalte Kurztext":"Ebenso kein eigener Zeitpunkt für Kurztext.","Spalte Steuerkennzeichen":"Kein eigener Zeitpunkt für Steuerkennzeichen."},"eselsbruecke":"3 Zeitpunkte in FI: 0001=Kopf, 0002=Zeile, 0003=Gesamtbeleg. Merke: aufsteigend wie beim Aufbau des Belegs."},"source":"WBS"},{"id":"WBS-084","fragen_id":"5044697","thema":"Belegarten","frage":"Sie wollen eine Sachkontenbuchung speichern, erhalten aber die Meldung 'Kontoart K ist nicht erlaubt'. Wo liegt der Fehler?","typ":"single_select","optionen":["Bei der Zeitzonenangabe","Bei der Datumsangabe","Bei der Toleranzgruppe","Bei der Belegart","Bei der Währung","Bei dem Lieferantenkonto","Bei der Feldstatusvariant"],"richtige_antworten":["Bei der Belegart"],"erklaerung":{"richtig":"Die Fehlermeldung 'Kontoart K ist nicht erlaubt' bedeutet: die verwendete Belegart erlaubt keine Kreditorenbuchungen (Kontoart K = Kreditor). Die Belegart steuert welche Kontoarten zulässig sind. Für eine Sachkontenbuchung mit Kreditoren muss die richtige Belegart gewählt werden.","falsch":{"Zeitzonenangabe":"Zeitzonen beeinflussen keine Kontoart-Prüfungen.","Datumsangabe":"Datum spielt keine Rolle bei der Kontoart-Prüfung.","Toleranzgruppe":"Toleranzgruppen steuern Betragsgrenzen, nicht Kontoarten.","Währung":"Währung hat keinen Einfluss auf erlaubte Kontoarten.","Lieferantenkonto":"Das Lieferantenkonto selbst verursacht nicht diese Fehlermeldung.","Feldstatusvariante":"Feldstatus steuert Pflichtfelder, nicht erlaubte Kontoarten."},"eselsbruecke":"Kontoart nicht erlaubt = BELEGART prüfen! Die Belegart definiert welche Kontoarten (S=Sachkonto, D=Debitor, K=Kreditor, A=Anlage) erlaubt sind."},"source":"WBS"},{"id":"WBS-085","fragen_id":"5044698","thema":"Ledger / Rechnungslegung","frage":"Welche Aussagen sind korrekt?","typ":"multiple_select","optionen":["Einer Ledger-Gruppe wird ein Bewertungsbereich zugeordnet.","Einer Rechnungslegungsvorschrift wird eine Ledger-Gruppe zugeordnet.","Einer Ledger-Gruppe wird eine Rechnungslegungsvorschrift zugeordnet.","Einem Bewertungsbereich wird eine Rechnungslegungsvorschrift zugeordnet."],"richtige_antworten":["Einer Ledger-Gruppe wird eine Rechnungslegungsvorschrift zugeordnet.","Einem Bewertungsbereich wird eine Rechnungslegungsvorschrift zugeordnet."],"erklaerung":{"richtig":"Die korrekte Zuordnungsrichtung: Ledger-Gruppe → Rechnungslegungsvorschrift (z.B. IFRS oder HGB). Bewertungsbereich → Rechnungslegungsvorschrift (in der Anlagenbuchhaltung).","falsch":{"Ledger-Gruppe bekommt Bewertungsbereich":"Umgekehrt — der Bewertungsbereich bekommt die Rechnungslegungsvorschrift.","Rechnungslegungsvorschrift bekommt Ledger-Gruppe":"Die Zuordnung geht anders herum: Ledger-Gruppe → Rechnungslegungsvorschrift."},"eselsbruecke":"Ledger-Gruppe → Rechnungslegungsvorschrift. Bewertungsbereich → Rechnungslegungsvorschrift. Beides zeigt ZUR Vorschrift, nicht umgekehrt."},"source":"WBS"},{"id":"WBS-086","fragen_id":"5044699","thema":"Validierung / Substitution","frage":"Welche Aussagen sind korrekt?","typ":"multiple_select","optionen":["Validierungen und/oder Substitutionen werden Ergebnisbereichen zugeordnet.","Validierungen und/oder Substitutionen können in mehreren Buchungskreisen gültig sein.","Mithilfe der 'Boole'schen Logik' lassen sich verschiedene Arten logischer Aussagen definieren."],"richtige_antworten":["Validierungen und/oder Substitutionen können in mehreren Buchungskreisen gültig sein.","Mithilfe der 'Boole'schen Logik' lassen sich verschiedene Arten logischer Aussagen definieren."],"erklaerung":{"richtig":"Validierungen/Substitutionen werden buchungskreisübergreifend definiert und können mehreren Buchungskreisen zugeordnet werden. Die Bedingungen werden mit Boole'scher Logik (UND, ODER, NICHT) formuliert.","falsch":{"Ergebnisbereichen zugeordnet":"Validierungen werden BUCHUNGSKREISEN zugeordnet, nicht Ergebnisbereichen. Ergebnisbereiche sind CO-Objekte."},"eselsbruecke":"Validierung/Substitution = Buchungskreis-Zuordnung (nicht Ergebnisbereich!). Bedingungen = Boole'sche Logik (UND/ODER/NICHT)."},"source":"WBS"},{"id":"WBS-087","fragen_id":"5044700","thema":"Buchungsperioden","frage":"Wie viele Periodenintervalle stehen in SAP S/4HANA für Buchungen in FI und CO zur Verfügung?","typ":"single_select","optionen":["10","3","16","4"],"richtige_antworten":["3"],"erklaerung":{"richtig":"In SAP stehen 3 Periodenintervalle zur Verfügung: Intervall 1 (normale Geschäftsperioden 1-12), Intervall 2 (Sonderperioden 13-16 für Jahresabschluss) und Intervall für CO-Buchungen. Diese drei Intervalle können unterschiedliche Öffnungs- und Schließungszustände haben.","falsch":{"10":"Zu viele — 10 Intervalle gibt es nicht.","16":"16 ist die Anzahl möglicher Perioden (12 normale + 4 Sonderperioden), nicht die Anzahl der Intervalle.","4":"Zu viele — es sind 3 Intervalle."},"eselsbruecke":"3 Periodenintervalle: normale Perioden + Sonderperioden + CO. Merke: DREI Intervalle, SECHZEHN mögliche Perioden."},"source":"WBS"},{"id":"WBS-088","fragen_id":"5044701","thema":"Zahlungsverkehr","frage":"Welche der folgenden Schritte führt man normalerweise aus, wenn man einen Zahllauf durchführt?","typ":"multiple_select","optionen":["Ausnahmeliste für Zahlungsvorschläge prüfen","Rangfolge der Bankkonten festlegen","Mindestbeträge festlegen (Bagatellgrenzen)","Rangfolge der betroffenen Umsatzsteuerkonten festlegen"],"richtige_antworten":["Ausnahmeliste für Zahlungsvorschläge prüfen","Rangfolge der Bankkonten festlegen","Mindestbeträge festlegen (Bagatellgrenzen)"],"erklaerung":{"richtig":"Beim Zahllauf werden standardmäßig drei Schritte durchgeführt: Ausnahmeliste prüfen (welche Posten wurden nicht berücksichtigt und warum), Rangfolge der Bankkonten festlegen (welches Bankkonto wird bevorzugt verwendet) und Bagatellgrenzen definieren (Mindestbeträge unter denen nicht gezahlt wird).","falsch":{"Umsatzsteuerkonten Rangfolge":"Die Rangfolge von Umsatzsteuerkonten ist kein Standard-Schritt beim Zahllauf."},"eselsbruecke":"Zahllauf-Schritte: Ausnahmen prüfen + Bankkonten priorisieren + Bagatellgrenzen. USt-Konten haben keine Rangfolge im Zahllauf."},"source":"WBS"},{"id":"WBS-089","fragen_id":"5044702","thema":"Periodenabschluss","frage":"Welche Abschlussaktivitäten gehören zum Berichtswesen bzw. zur Bilanz des externen Rechnungswesens?","typ":"multiple_select","optionen":["Fremdwährungsbewertung offener Posten","Aktualisierung von Produktkostenschätzungen","Abspielen von Plankostenbewertungszyklen","Umgliederung von Forderungen und Verbindlichkeiten"],"richtige_antworten":["Fremdwährungsbewertung offener Posten","Umgliederung von Forderungen und Verbindlichkeiten"],"erklaerung":{"richtig":"Zum externen Rechnungswesen (Bilanzerstellung) gehören: Fremdwährungsbewertung (Umrechnung offener Posten zum Stichtagskurs) und Umgliederung nach Fristigkeit (kurz-/langfristig gemäß HGB/IFRS).","falsch":{"Produktkostenschätzungen":"Das ist eine CO-PC-Aktivität (Product Costing), kein FI-Abschluss.","Plankostenbewertungszyklen":"Das ist ein CO-Vorgang (Gemeinkostencontrolling), kein FI-Abschluss."},"eselsbruecke":"Externes RW Abschluss = Fremdwährung bewerten + Forderungen umgliedern. Produktkosten und Plankosten = CO, nicht FI!"},"source":"WBS"},{"id":"WBS-090","fragen_id":"5044703","thema":"Korrespondenz","frage":"Welche Korrespondenzart wird vom System für die automatische Zahlungsmitteilung verwendet?","typ":"single_select","optionen":["Die Korrespondenzart des Einzelpostens mit dem höchsten Betrag.","Das System entscheidet nicht darüber, sondern der Anwender.","Die Korrespondenzart des ersten Einzelpostens.","Die Korrespondenzart des Einzelpostens, dessen Betrag dem Durchschnittswert am nächsten kommt.","Die Korrespondenzart, die der Toleranzgruppe zugeordnet ist."],"richtige_antworten":["Die Korrespondenzart des ersten Einzelpostens."],"erklaerung":{"richtig":"Bei automatischen Zahlungsmitteilungen mit mehreren Einzelposten unterschiedlicher Korrespondenzarten verwendet SAP die Korrespondenzart des ersten Einzelpostens als Grundlage.","falsch":{"höchster Betrag":"Der Betrag spielt keine Rolle bei der Auswahl der Korrespondenzart.","Anwender entscheidet":"Die automatische Zahlungsmitteilung wird vom System erstellt — der Anwender entscheidet nicht.","Durchschnittswert":"Es gibt keine Logik die den Durchschnittswert zur Bestimmung der Korrespondenzart nutzt.","Toleranzgruppe":"Toleranzgruppen steuern Betragsabweichungen, keine Korrespondenzarten."},"eselsbruecke":"Zahlungsmitteilung mit mehreren Posten → Korrespondenzart vom ERSTEN Posten. Erste Zeile gewinnt."},"source":"WBS"},{"id":"WBS-091","fragen_id":"5044704","thema":"Offene-Posten-Verwaltung","frage":"Unter welchen Umständen kann man das Kennzeichen für Offene-Posten-Verwaltung in einem Hauptbuchkonto setzen?","typ":"multiple_select","optionen":["Wenn es sich um ein Erfolgskonto handelt","Wenn es sich um ein Abstimmkonto handelt","Wenn es sich um ein Anlagekonto handelt","Wenn ein Konto einen Saldo von Null hat (Nullsaldo)","Wenn das Konto für Buchen mit Ausgleich vorgesehen ist","Wenn es sich um ein Verrechnungskonto handelt"],"richtige_antworten":["Wenn das Konto für Buchen mit Ausgleich vorgesehen ist","Wenn es sich um ein Verrechnungskonto handelt"],"erklaerung":{"richtig":"Die Offene-Posten-Verwaltung kann nur aktiviert werden wenn: der Kontosaldo null ist (keine bestehenden Buchungen), das Konto für Ausgleichsbuchungen genutzt wird, oder es ein Verrechnungskonto ist (WE/RE-Konto etc.).","falsch":{"Erfolgskonto":"Erfolgskonten können keine OP-Verwaltung haben — sie werden saldiert, nicht einzeln ausgeglichen.","Abstimmkonto":"Abstimmkonten sind für Debi/Kredit-Nebenbücher reserviert — keine manuelle OP-Verwaltung.","Anlagekonto":"Anlagenkonten werden über die Anlagenbuchhaltung gesteuert, nicht über OP-Verwaltung."},"eselsbruecke":"OP-Verwaltung aktivieren: nur wenn Saldo = 0 + kein Abstimmkonto + kein Erfolgskonto. Am sichersten bei Verrechnungskonten und Ausgleichskonten."},"source":"WBS"},{"id":"WBS-092","fragen_id":"5044705","thema":"Zahlungsverkehr","frage":"Welche Aussagen sind korrekt?","typ":"multiple_select","optionen":["Zahllauf-Belege enthalten das Datum und die Identifikationsnummer des Laufes im Belegkopf.","Mahnungen lassen sich direkt nach Ende des Mahnlaufes ausdrucken.","Zahlläufe kann man im Gegensatz zu Mahnläufen nicht simulieren.","Um einen Zahllauf zu simulieren, setzt man das Kennzeichen 'Simulationslauf'."],"richtige_antworten":["Zahllauf-Belege enthalten das Datum und die Identifikationsnummer des Laufes im Belegkopf.","Mahnungen lassen sich direkt nach Ende des Mahnlaufes ausdrucken.","Um einen Zahllauf zu simulieren, setzt man das Kennzeichen 'Simulationslauf'."],"erklaerung":{"richtig":"Zahllauf-Belege haben Datum + ID im Kopf (zur Identifikation). Mahnungen können sofort nach dem Lauf gedruckt werden. Simulation des Zahllaufs ist über das Simulationskennzeichen in F110 möglich.","falsch":{"Zahlläufe nicht simulierbar":"Falsch — Zahlläufe KÖNNEN simuliert werden, genauso wie Mahnläufe."},"eselsbruecke":"Zahllauf simulieren = Simulationskennzeichen setzen. Beide Läufe (Mahn- und Zahllauf) sind simulierbar!"},"source":"WBS"},{"id":"WBS-093","fragen_id":"5044706","thema":"Anlagenbuchhaltung","frage":"Welche der folgenden Aussagen trifft zu?","typ":"single_select","optionen":["Man kann Anlagen Profit Center zuordnen.","Anlagenklassen werden auf Mandantenebene definiert.","Man kann einer Anlage mehrere Kostenstellen zuordnen.","Pro Anlagenklasse gibt es genau einen Bewertungsbereich."],"richtige_antworten":["Anlagenklassen werden auf Mandantenebene definiert."],"erklaerung":{"richtig":"Anlagenklassen werden mandantenweit definiert — sie gelten für alle Buchungskreise innerhalb eines Mandanten. Das ermöglicht eine einheitliche Anlagenstruktur im gesamten Unternehmen.","falsch":{"Profit Center zuordnen":"In S/4HANA wird das Profit Center aus der Kostenstelle abgeleitet — eine direkte Zuordnung im Anlagenstamm ist nicht der Standardweg.","mehrere Kostenstellen":"Einer Anlage kann immer nur EINE Kostenstelle (zeitabhängig) zugeordnet werden.","genau ein Bewertungsbereich":"Eine Anlagenklasse kann MEHRERE Bewertungsbereiche haben (z.B. für HGB und IFRS gleichzeitig)."},"eselsbruecke":"Anlagenklassen = mandantenweit (ein Unternehmen, eine Klassenstruktur). Pro Anlage = eine Kostenstelle. Pro Klasse = mehrere Bewertungsbereiche möglich."},"source":"WBS"},{"id":"WBS-094","fragen_id":"5044711","thema":"Workflow","frage":"Welche der folgenden Aussagen treffen zu?","typ":"multiple_select","optionen":["Es können mehrstufige Workflows angelegt werden.","Den Workflow-Varianten werden Buchungskreise zugeordnet.","Buchungskreisen werden Workflow-Varianten zugeordnet.","Jeder Aufgabe kann man jeweils einen Bearbeiter zuordnen.","Zu einer Aufgabe sind in der entsprechenden Definition all ihre möglichen Bearbeiter angegeben."],"richtige_antworten":["Es können mehrstufige Workflows angelegt werden.","Den Workflow-Varianten werden Buchungskreise zugeordnet.","Jeder Aufgabe kann man jeweils einen Bearbeiter zuordnen.","Zu einer Aufgabe sind in der entsprechenden Definition all ihre möglichen Bearbeiter angegeben."],"erklaerung":{"richtig":"Workflows in SAP FI: mehrstufig möglich (mehrere Genehmigungsebenen). Zuordnungsrichtung: Buchungskreise → Workflow-Varianten (nicht umgekehrt). Jede Aufgabe hat einen zugeordneten Bearbeiter, und in der Aufgabendefinition stehen alle möglichen Bearbeiter.","falsch":{"Buchungskreisen werden Workflow-Varianten zugeordnet":"Die Richtung ist umgekehrt: Den Workflow-Varianten werden Buchungskreise zugeordnet."},"eselsbruecke":"Workflow: mehrstufig möglich. Zuordnung: Workflow-Variante ← Buchungskreis (Variante bekommt den BuKr, nicht umgekehrt)."},"source":"WBS"},{"id":"WBS-095","fragen_id":"5044712","thema":"Anlagenbuchhaltung","frage":"Welche der folgenden Elemente verbinden die Transaktion eines Anlagenzuganges mit dem Hauptbuch?","typ":"multiple_select","optionen":["Abschreibungsart","Anlageklasse","Bewegungsart","Bewertungsbereich"],"richtige_antworten":["Anlageklasse","Bewertungsbereich"],"erklaerung":{"richtig":"Die Verbindung zwischen Anlagenzugang und Hauptbuch erfolgt über: Anlagenklasse (enthält die Kontenfindung — welche G/L-Konten werden verwendet) und Bewertungsbereich (bestimmt welche Ledger und Wertansätze betroffen sind).","falsch":{"Abschreibungsart":"Abschreibungsarten steuern AfA-Buchungen, nicht Zugangsbuchungen ins Hauptbuch.","Bewegungsart":"Bewegungsarten klassifizieren die Anlagenbewegung intern, sind aber nicht die direkte Verbindung zum HB."},"eselsbruecke":"Anlagenzugang → Hauptbuch via: ANLAGENKLASSE (welches Konto?) + BEWERTUNGSBEREICH (welches Ledger?). Diese zwei verbinden AA mit FI."},"source":"WBS"},{"id":"WBS-096","fragen_id":"5044713","thema":"Belegerfassung","frage":"Welche der folgenden Aussagen treffen zu?","typ":"multiple_select","optionen":["Wenn man die Option 'Beleg merken' nutzen möchte, muss man den Belegkopf und mindestens eine Belegposition erfasst haben.","Wenn man einen Beleg vorerfasst, wird eine Belegnummer erzeugt. Das geschieht bei 'Beleg merken' nicht.","Vorerfasste Belege unterliegen nicht den normalen Belegänderungsregeln.","Bei der Funktion 'Beleg merken' wird eine Belegnummer vergeben, die von der Belegart abhängt.","Die Begriffe 'Vorerfassen' und 'Merken' in Bezug auf Belege bedeuten dasselbe.","Die Begriffe 'Vorerfassen' und 'Parken' in Bezug auf Belege bedeuten dasselbe.","Man kann die Belegnummer eines gelöschten Beleges nicht noch einmal verwenden."],"richtige_antworten":["Wenn man die Option 'Beleg merken' nutzen möchte, muss man den Belegkopf und mindestens eine Belegposition erfasst haben.","Wenn man einen Beleg vorerfasst, wird eine Belegnummer erzeugt. Das geschieht bei 'Beleg merken' nicht.","Vorerfasste Belege unterliegen nicht den normalen Belegänderungsregeln.","Die Begriffe 'Vorerfassen' und 'Parken' in Bezug auf Belege bedeuten dasselbe."],"erklaerung":{"richtig":"Vier korrekte Aussagen: Merken braucht Kopf + Position. Vorerfassen = Belegnummer, Merken = keine Nummer. Vorerfasste Belege haben eigene Änderungsregeln. Vorerfassen = Parken (Synonyme!)","falsch":{"Merken vergibgt Belegnummer von Belegart":"Beim Merken wird KEINE Belegnummer vergeben — das ist der wichtigste Unterschied zum Parken.","Vorerfassen = Merken sind dasselbe":"Falsch — Vorerfassen und Merken sind UNTERSCHIEDLICHE Funktionen.","gelöschte Belegnummer":"Gelöschte Belegnummern aus vorerfassten Belegen KÖNNEN neu vergeben werden — nur gebuchte Belege nicht."},"eselsbruecke":"Parken = Vorerfassen (gleiches Ding, zwei Namen). Merken ≠ Parken! Parken gibt Nummer, Merken nicht. Gemerkte Belege = flüchtig."},"source":"WBS"},{"id":"WBS-097","fragen_id":"5044708","thema":"Anlagenbuchhaltung","frage":"Welche der folgenden Aussagen treffen auf das SAP S/4HANA-System zu?","typ":"multiple_select","optionen":["Bewertungspläne dienen der Verwaltung der Bewertungsvorschriften zum Anlagevermögen.","Einen Bewertungsplan kann man für alle Buchungskreise eines Landes verwenden.","Wenn alle Buchungskreise denselben Bewertungsvorschriften unterliegen, ist das Anlegen eines Bewertungsplanes überflüssig.","Die von SAP bereitgestellten länderspezifischen Musterbewertungspläne kann man an die eigenen Bedürfnisse anpassen.","Der Bewertungsplan für das Anlagevermögen wird auf Mandantenebene definiert."],"richtige_antworten":["Bewertungspläne dienen der Verwaltung der Bewertungsvorschriften zum Anlagevermögen.","Einen Bewertungsplan kann man für alle Buchungskreise eines Landes verwenden.","Die von SAP bereitgestellten länderspezifischen Musterbewertungspläne kann man an die eigenen Bedürfnisse anpassen.","Der Bewertungsplan für das Anlagevermögen wird auf Mandantenebene definiert."],"erklaerung":{"richtig":"Vier korrekte Aussagen: Bewertungspläne = Verwaltung der AfA-Vorschriften. Ein Plan für alle BuKr eines Landes möglich. SAP-Musterpläne sind anpassbar. Bewertungsplan = mandantenweit.","falsch":{"Bewertungsplan überflüssig":"Falsch — auch wenn alle BuKr dieselben Vorschriften haben, wird ein Bewertungsplan IMMER benötigt. Er ist zwingend erforderlich."},"eselsbruecke":"Bewertungsplan: mandantenweit, länderspezifisch anpassbar, IMMER erforderlich (auch bei gleichen Vorschriften)."},"source":"WBS"},{"id":"WBS-098","fragen_id":"5044709","thema":"MM/FI Integration","frage":"Welche Transaktionen können im Bereich der Materialwirtschaft mit der Anschaffung einer Anlage einhergehen?","typ":"multiple_select","optionen":["Anzahlungsanforderung","Wareneingang","Anlage anlegen","Bestellanforderung","Bestellung","Anlage aktivieren"],"richtige_antworten":["Wareneingang","Bestellanforderung","Bestellung"],"erklaerung":{"richtig":"Bei MM-gestützter Anlagenanschaffung laufen folgende MM-Prozesse ab: Bestellanforderung (intern: ich brauche etwas), Bestellung (extern: ich bestelle beim Lieferanten), Wareneingang (die Anlage kommt an).","falsch":{"Anzahlungsanforderung":"Anzahlungsanforderungen sind FI/SD-Vorgänge, keine Standard-MM-Transaktion bei Anschaffungen.","Anlage anlegen":"Das Anlegen des Anlagenstammsatzes ist ein FI-AA-Vorgang, kein MM-Prozessschritt.","Anlage aktivieren":"Die Aktivierung (Umbuchung von AiB auf fertige Anlage) ist FI-AA, kein MM."},"eselsbruecke":"MM bei Anlagenkauf: BANF → Bestellung → Wareneingang. Alles andere (Anlegen, Aktivieren) ist AA/FI."},"source":"WBS"},{"id":"WBS-099","fragen_id":"5044710","thema":"Sachkontenstammdaten","frage":"Was wird vor der Archivierung von Sachkonten vom System geprüft?","typ":"multiple_select","optionen":["Ob es noch offene Posten gibt","Ob das Geschäftsjahr abgeschlossen ist","Ob eine Löschvormerkung im Stammsatz gesetzt ist","Ob es noch Verkehrszahlen gibt","Ob der Periodenschluss durchgeführt worden ist"],"richtige_antworten":["Ob es noch offene Posten gibt","Ob eine Löschvormerkung im Stammsatz gesetzt ist","Ob es noch Verkehrszahlen gibt"],"erklaerung":{"richtig":"Vor der Archivierung prüft SAP drei Kriterien: keine offenen Posten (Konto muss ausgeglichen sein), Löschvormerkung gesetzt (muss bewusst markiert worden sein), keine Verkehrszahlen mehr (keine Bewegungen im relevanten Zeitraum).","falsch":{"Geschäftsjahr abgeschlossen":"Der Abschluss des Geschäftsjahres ist keine direkte Voraussetzung für die Kontarchivierung.","Periodenschluss":"Periodenschluss ist keine Prüfvoraussetzung für die Sachkontenarchivierung."},"eselsbruecke":"Sachkonto archivieren: Konto leer (keine OP, keine Verkehrszahlen) + bewusst markiert (Löschvormerkung). Drei Checks!"},"source":"WBS"},{"id":"WBS-100","fragen_id":"5044707","thema":"Mahnwesen","frage":"Welche Aussagen sind zutreffend?","typ":"multiple_select","optionen":["Nachdem man einen Mahnvorschlag erstellt hat, muss man ihn erst archivieren, bevor man ihn endgültig löschen kann.","Sonderhauptbuchvorgänge der Debitoren- oder Kreditorenbuchhaltung werden in der Regel im Hauptbuch und in den Nebenbüchern gesondert ausgewiesen.","Man kann Mahnvorschläge beliebig oft bearbeiten, löschen oder neu erstellen.","Buchungen in die Nebenbücher werden parallel in den Abstimmkonten des Hauptbuches mitgebucht."],"richtige_antworten":["Sonderhauptbuchvorgänge der Debitoren- oder Kreditorenbuchhaltung werden in der Regel im Hauptbuch und in den Nebenbüchern gesondert ausgewiesen.","Man kann Mahnvorschläge beliebig oft bearbeiten, löschen oder neu erstellen.","Buchungen in die Nebenbücher werden parallel in den Abstimmkonten des Hauptbuches mitgebucht."],"erklaerung":{"richtig":"Drei korrekte Aussagen: SHB-Vorgänge erscheinen in Haupt- und Nebenbuch separat. Mahnvorschläge sind flexibel — beliebig oft änderbar/löschbar/neu erstellbar. Nebenbuchbuchungen werden immer parallel in die Abstimmkonten des HB gebucht (Grundprinzip der integrierten Buchhaltung).","falsch":{"erst archivieren bevor löschen":"Falsch — Mahnvorschläge können direkt gelöscht werden, ohne vorherige Archivierung."},"eselsbruecke":"Mahnvorschlag: beliebig oft bearbeiten/löschen/neu — keine Archivierung nötig! Nebenbuch → Abstimmkonto im HB automatisch. SHB = separat ausgewiesen."},"source":"WBS"},{"id":"SAP-001","fragen_id":"5044740","thema":"Zahlungsverkehr","frage":"Ein Kunde bezahlt eine Rechnung nur teilweise. Welche Buchungsoptionen sind beim Eingeben dieser Eingangszahlung verfügbar?","typ":"multiple_select","optionen":["Als Restposten buchen","Als zweifelhafte Forderung buchen","Als Teilzahlung buchen","Als Merkposten buchen"],"richtige_antworten":["Als Restposten buchen","Als Teilzahlung buchen"],"erklaerung":{"richtig":"Bei einer Teilzahlung gibt es in SAP genau zwei Buchungsoptionen: Teilzahlung (ursprüngliche Rechnung bleibt offen, Zahlung wird als eigener Posten gebucht) oder Restposten (ursprüngliche Rechnung wird ausgeglichen, ein neuer offener Posten für die Restschuld wird angelegt).","falsch":{"zweifelhafte Forderung":"Zweifelhafte Forderungen sind eine Wertberichtigungsoption am Jahresabschluss, keine Buchungsoption beim Zahlungseingang.","Merkposten":"Merkposten sind Sonderhauptbuchvorgänge ohne Gegenbuchung — keine Option beim Erfassen einer echten Zahlung."},"eselsbruecke":"Teilzahlung: ZWEI Wege — Teilzahlung (beide Posten bleiben offen) oder Restposten (alte Rechnung weg, neuer Restposten). Kein dritter Weg!"},"source":"SAP"},{"id":"SAP-002","fragen_id":"5044741","thema":"Ledger / Rechnungslegung","frage":"Welche Objekte können steuern, ob ein Beleg nur in einem bestimmten Ledger gebucht wird?","typ":"single_select","optionen":["Rechnungslegungsvorschrift","Bilanz/GuV-Struktur","Sonderhauptbuchkennzeichen","Buchungsschlüssel"],"richtige_antworten":["Rechnungslegungsvorschrift"],"erklaerung":{"richtig":"Die Rechnungslegungsvorschrift steuert in welche Ledger ein Beleg gebucht wird. Durch die Verknüpfung von Rechnungslegungsvorschrift und Ledger-Gruppe kann man gezielt nur in bestimmte Ledger buchen (z.B. nur IFRS-Ledger, nicht HGB).","falsch":{"Bilanz/GuV-Struktur":"Die Bilanz/GuV-Struktur definiert wie Konten in Berichten zusammengefasst werden, nicht in welche Ledger gebucht wird.","Sonderhauptbuchkennzeichen":"SHB-Kennzeichen steuern Sonderhauptbuchvorgänge, nicht die Ledger-Zuordnung.","Buchungsschlüssel":"Buchungsschlüssel steuern Soll/Haben und Kontoart, nicht Ledger."},"eselsbruecke":"Welches Ledger? → Rechnungslegungsvorschrift bestimmt das. IFRS, HGB, US-GAAP = verschiedene Vorschriften = verschiedene Ledger."},"source":"SAP"},{"id":"SAP-003","fragen_id":"5044742","thema":"Buchungskreis","frage":"Welche Einstellungen sind für die produktive Nutzung eines Buchungskreises erforderlich?","typ":"multiple_select","optionen":["Mindestens eine lokale Währung","Mindestens ein nicht führendes Ledger","Ein eindeutiger vierstelliger alphanumerischer Schlüssel","Eine Zuordnung zu einem Ergebnisbereich"],"richtige_antworten":["Mindestens eine lokale Währung","Ein eindeutiger vierstelliger alphanumerischer Schlüssel"],"erklaerung":{"richtig":"Ein Buchungskreis braucht für den produktiven Betrieb zwingend: eine lokale Währung (Hauswährung, z.B. EUR) und einen eindeutigen 4-stelligen alphanumerischen Schlüssel (z.B. '1000' oder 'DE01').","falsch":{"nicht führendes Ledger":"Das führende Ledger (0L) ist immer vorhanden — ein nicht führendes Ledger ist optional.","Ergebnisbereich":"Der Ergebnisbereich ist ein CO-PA-Objekt (Ergebnis- und Marktsegmentrechnung), keine Pflichteinstellung für den Buchungskreis."},"eselsbruecke":"Buchungskreis-Pflicht: 4-stelliger Schlüssel + eine Währung. Mehr braucht man nicht zum Start."},"source":"SAP"},{"id":"SAP-004","fragen_id":"5044743","thema":"SAP Fiori","frage":"Welche Art von SAP-Fiori-App zeigt einem Manager die Daten seiner Kostenstelle, alle zugeordneten Anlagen und die Rechnungen?","typ":"single_select","optionen":["Transaktionale App","Analytische App","Hybride App","Factsheet"],"richtige_antworten":["Factsheet"],"erklaerung":{"richtig":"Ein Factsheet zeigt übersichtlich alle relevanten Informationen zu einem Objekt (z.B. Kostenstelle) — verknüpfte Anlagen, Rechnungen, Salden etc. Es ist eine Informationsansicht ohne direkte Buchungsfunktion.","falsch":{"Transaktionale App":"Transaktionale Apps dienen zum Ausführen von Buchungen und Transaktionen, nicht zur Informationsübersicht.","Analytische App":"Analytische Apps dienen der Datenanalyse und Reporting mit Diagrammen etc.","Hybride App":"Hybride Apps kombinieren Transaktion und Analyse — aber nicht für Objektübersichten."},"eselsbruecke":"Factsheet = Steckbrief eines Objekts. Alle Infos auf einen Blick, nichts buchen. Wie eine Visitenkarte der Kostenstelle."},"source":"SAP"},{"id":"SAP-005","fragen_id":"5044744","thema":"Ledger / Rechnungslegung","frage":"Welche Optionen stehen zur Verfügung, um verschiedene Rechnungslegungsvorschriften in SAP S/4HANA zuzuordnen?","typ":"multiple_select","optionen":["Zuordnung mit einer Ledger-Lösung","Zuordnung über Ergebnisbereich","Aktivierung der Profitcenter-Rechnung","Verwendung der Kontenlösung"],"richtige_antworten":["Zuordnung mit einer Ledger-Lösung","Verwendung der Kontenlösung"],"erklaerung":{"richtig":"In SAP S/4HANA gibt es zwei Ansätze für mehrere Rechnungslegungsvorschriften: Ledger-Lösung (jede Vorschrift bekommt ein eigenes Ledger, z.B. 0L für HGB, 2L für IFRS) und Kontenlösung (unterschiedliche Konten für verschiedene Vorschriften im selben Ledger).","falsch":{"Ergebnisbereich":"Ergebnisbereiche sind für CO-PA, nicht für Rechnungslegungsvorschriften.","Profitcenter-Rechnung":"Die Profitcenter-Rechnung ist ein Berichtswerkzeug, keine Methode für Rechnungslegungsvorschriften."},"eselsbruecke":"Zwei Wege für mehrere Vorschriften: LEDGER-Lösung (eigene Ledger) oder KONTEN-Lösung (eigene Konten). Zwei Wege, ein Ziel."},"source":"SAP"},{"id":"SAP-006","fragen_id":"5044745","thema":"Anlagenbuchhaltung","frage":"Eine Anlage ist bereits zu 100% abgeschrieben. Durch welche Anlagenbewegung ändert sich die Gewinn- und Verlustrechnung?","typ":"single_select","optionen":["Abgang zum verbundenen Unternehmen ohne Erlös","Buchungskreisinterne Umbuchung","Verschrottung","Abgang zum Debitor mit Erlös"],"richtige_antworten":["Abgang zum Debitor mit Erlös"],"erklaerung":{"richtig":"Bei einer vollständig abgeschriebenen Anlage (Buchwert = 0) führt nur der Verkauf an einen Debitor zu einer GuV-Änderung — der Verkaufserlös wird als Ertrag (Gewinn) in der GuV erfasst.","falsch":{"Abgang ohne Erlös":"Kein Erlös = kein GuV-Effekt, da Buchwert bereits 0.","Buchungskreisinterne Umbuchung":"Eine Umbuchung ist kein Abgang — die Anlage bleibt im Konzern, kein GuV-Effekt.","Verschrottung":"Verschrottung ohne Erlös bei Buchwert 0 = kein GuV-Effekt."},"eselsbruecke":"Vollabgeschriebene Anlage: Buchwert = 0. Nur VERKAUF mit Erlös bringt GuV-Effekt (Ertrag). Verschrotten oder umbuchen = kein Effekt."},"source":"SAP"},{"id":"SAP-007","fragen_id":"5044746","thema":"SAP Fiori","frage":"Wie können Benutzer SAP-Fiori-Apps personalisieren?","typ":"multiple_select","optionen":["Indem sie sich selbst Apps/Kacheln aus einem Katalog zuweisen, der ihnen anhand ihrer Berechtigungen zugewiesen wird.","Indem sie Apps/Kacheln entfernen, die sie nicht benötigen.","Indem sie sich zu Analysezwecken mit einer Vielzahl von Quellsystemen verbinden.","Indem sie bei Bedarf neue Kataloge anlegen.","Indem sie ihre Auswahl als separate Kacheln sichern."],"richtige_antworten":["Indem sie sich selbst Apps/Kacheln aus einem Katalog zuweisen, der ihnen anhand ihrer Berechtigungen zugewiesen wird.","Indem sie Apps/Kacheln entfernen, die sie nicht benötigen.","Indem sie ihre Auswahl als separate Kacheln sichern."],"erklaerung":{"richtig":"Benutzer können ihr Fiori Launchpad personalisieren indem sie aus dem ihnen zugewiesenen Katalog Apps hinzufügen oder nicht benötigte Apps/Kacheln entfernen. Die Grundberechtigungen bleiben dabei erhalten.","falsch":{"Quellsysteme verbinden":"Das Verbinden mit Quellsystemen ist eine Administrator-Aufgabe, keine Benutzerpersonalisierung.","neue Kataloge anlegen":"Kataloge werden vom Administrator angelegt, nicht von normalen Benutzern.","als separate Kacheln sichern":"Diese Option gibt es nicht als Standard-Personalisierungsfunktion."},"eselsbruecke":"Fiori personalisieren: Apps aus Katalog HINZUFÜGEN oder ENTFERNEN. Kataloge anlegen = Admin. Benutzer kann nur innerhalb seiner Berechtigungen anpassen."},"source":"SAP"},{"id":"SAP-008","fragen_id":"5044747","thema":"Jahresabschluss","frage":"Welche der folgenden Prozesse sind Teil des Jahresabschlusses?","typ":"multiple_select","optionen":["Wertberichtigungen für Forderungen vornehmen","Ausgeglichene Rechnungen in Fremdwährungen am Bilanzstichtag bewerten","Mahnungen anlegen","Offene Rechnungen in Fremdwährungen am Bilanzstichtag bewerten","Saldenbestätigungen anlegen"],"richtige_antworten":["Wertberichtigungen für Forderungen vornehmen","Offene Rechnungen in Fremdwährungen am Bilanzstichtag bewerten","Saldenbestätigungen anlegen"],"erklaerung":{"richtig":"Zum Jahresabschluss gehören: Wertberichtigungen auf zweifelhafte Forderungen, Fremdwährungsbewertung OFFENER Posten (nicht ausgeglichener!) und Saldenbestätigungen an Geschäftspartner.","falsch":{"ausgeglichene Rechnungen bewerten":"Ausgeglichene (bezahlte) Rechnungen müssen NICHT bewertet werden — sie sind bereits erledigt.","Mahnungen anlegen":"Mahnungen sind ein laufendes Geschäft, kein Jahresabschlussvorgang."},"eselsbruecke":"Jahresabschluss: Forderungen berichtigen + OFFENE Fremdwährungsposten bewerten + Salden bestätigen. Ausgeglichene Posten = fertig = kein Handlungsbedarf."},"source":"SAP"},{"id":"SAP-009","fragen_id":"5044748","thema":"Jahresabschluss","frage":"Wie müssen Sie bei der Vorbereitung des Jahresabschlusses vorgehen?","typ":"single_select","optionen":["Jahresabschluss ausführen und Bilanz anlegen, dann letzten Abschreibungslauf ausführen.","Buchungsperioden für das neue Geschäftsjahr pflegen und Bilanz anlegen, dann Löhne für Periode 12 buchen.","Reguläre Buchungsperioden für das alte Geschäftsjahr schließen und Sonderperioden für Jahresabschlussaktivitäten offen lassen.","Sonderperioden für Warenausgangsbuchungen aus MM für das alte Geschäftsjahr schließen."],"richtige_antworten":["Reguläre Buchungsperioden für das alte Geschäftsjahr schließen und Sonderperioden für Jahresabschlussaktivitäten offen lassen."],"erklaerung":{"richtig":"Bei der Jahresabschlussvorbereitung: reguläre Perioden (1-12) werden geschlossen damit keine weiteren normalen Buchungen ins alte Jahr gehen, aber Sonderperioden (13-16) bleiben offen für Jahresabschlussaktivitäten (Abgrenzungen, Korrekturbuchungen etc.).","falsch":{"Jahresabschluss zuerst dann AfA":"Falsch — der Abschreibungslauf muss VOR dem Jahresabschluss laufen.","Buchungsperioden für neues Jahr zuerst":"Das neue Jahr wird erst nach Abschluss des alten Jahres geöffnet.","Sonderperioden für MM schließen":"MM-Sonderperioden sind separat — das ist nicht der erste Schritt der FI-Jahresabschlussvorbereitung."},"eselsbruecke":"Jahresabschluss: reguläre Perioden SCHLIESSEN (kein neues Reinkommen) + Sonderperioden OFFEN (für Abschlussbuchungen). Dann arbeiten, dann Sonderperioden schließen."},"source":"SAP"},{"id":"SAP-010","fragen_id":"5044749","thema":"SAP Fiori","frage":"Nennen Sie einige Elemente der Designprinzipien von SAP Fiori.","typ":"multiple_select","optionen":["Es muss für Benutzer möglich sein, Apps schnell zu erstellen.","Die Apps passen sich automatisch an alle Geräte und Größen an.","Die Apps müssen rollenbasiert verwendet werden.","Die Verwendung von Apps muss einfach sein.","Jede App muss in der Lage sein, alle Aufgaben automatisch zu planen."],"richtige_antworten":["Die Apps passen sich automatisch an alle Geräte und Größen an.","Die Apps müssen rollenbasiert verwendet werden.","Die Verwendung von Apps muss einfach sein."],"erklaerung":{"richtig":"Die SAP Fiori Designprinzipien sind: Responsivität (alle Geräte), rollenbasierter Ansatz (jeder sieht nur was er braucht) und Einfachheit (intuitiv bedienbar ohne lange Einarbeitung).","falsch":{"Apps schnell erstellen":"Das ist kein Designprinzip für Endbenutzer — App-Entwicklung ist Sache der IT.","alle Aufgaben automatisch planen":"Automatische Planung ist kein Fiori-Designprinzip."},"eselsbruecke":"Fiori-Prinzipien: RESPONSIV + ROLLENBASIERT + EINFACH. Die drei R's (und ein E) von Fiori."},"source":"SAP"},{"id":"SAP-011","fragen_id":"5044750","thema":"Organisationsstruktur","frage":"Welche Organisationseinheit wird standardmäßig verwendet, um das Segment automatisch abzuleiten?","typ":"single_select","optionen":["Ergebnisbereich","Buchungskreis","Geschäftsbereich","Profitcenter"],"richtige_antworten":["Profitcenter"],"erklaerung":{"richtig":"In SAP S/4HANA wird das Segment (für IFRS 8 Segmentberichterstattung) standardmäßig automatisch aus dem Profit Center abgeleitet. Jedem Profit Center ist ein Segment zugeordnet.","falsch":{"Ergebnisbereich":"Ergebnisbereiche sind für CO-PA, nicht für die Segmentableitung.","Buchungskreis":"Der Buchungskreis ist eine rechtliche Einheit, keine Basis für Segmentableitung.","Geschäftsbereich":"Geschäftsbereiche sind optionale Organisationseinheiten, nicht die Standardquelle für Segmente."},"eselsbruecke":"Segment = kommt vom Profitcenter. Profitcenter → Segment (automatisch). IFRS 8 Segmentberichterstattung läuft über Profitcenter."},"source":"SAP"},{"id":"SAP-012","fragen_id":"5044751","thema":"SAP Fiori","frage":"Was ist einer der wichtigsten Vorteile von analytischen Apps?","typ":"single_select","optionen":["Auf aktiven Kacheln werden Daten (wie z.B. KPIs) in Echtzeit angezeigt.","Daten können mühelos angepasst und korrigiert werden.","Kacheln können mühelos zu mehrstufigen Hierarchien zusammengeführt werden.","Daten werden sofort als Positionen in der höchstmöglichen Granularität angezeigt und können schnell aggregiert werden."],"richtige_antworten":["Auf aktiven Kacheln werden Daten (wie z.B. KPIs) in Echtzeit angezeigt."],"erklaerung":{"richtig":"Der Hauptvorteil analytischer Apps: sie zeigen Daten sofort auf detaillierter Einzelpostenebene (höchste Granularität) und können diese schnell zu Summen hochaggregieren. Das ermöglicht echte Drill-Down-Analysen.","falsch":{"KPIs in Echtzeit auf Kacheln":"Das ist ein Merkmal von Live-Kacheln (aktive Kacheln) auf dem Launchpad, kein spezifischer Vorteil analytischer Apps.","Daten anpassen und korrigieren":"Das beschreibt transaktionale Apps, nicht analytische.","mehrstufige Hierarchien":"Das ist ein allgemeines Merkmal, nicht der Hauptvorteil analytischer Apps."},"eselsbruecke":"Analytische Apps = Detail + Aggregation. Granularste Ebene anzeigen und schnell hochsummieren. Perfekt für Controller."},"source":"SAP"},{"id":"SAP-013","fragen_id":"5044752","thema":"Sachkontenstammdaten","frage":"Für welche Kontoart ist der Kontensaldo immer Null, nachdem ein Saldovortrag im nächsten Geschäftsjahr ausgeführt wurde?","typ":"single_select","optionen":["Erfolgskonten","Debitoren- und Kreditorenkonten","Bestandskonten","Anlagekonten"],"richtige_antworten":["Erfolgskonten"],"erklaerung":{"richtig":"Erfolgskonten (Aufwands- und Ertragskonten) werden zum Jahresabschluss auf Null gestellt — der Saldo wird auf das Eigenkapitalkonto (Gewinn- und Verlustvortrag) übertragen. Bestandskonten dagegen behalten ihren Saldo als Anfangssaldo ins neue Jahr.","falsch":{"Debitoren/Kreditoren":"Offene Posten bei Debitoren/Kreditoren werden vorgetragen, Saldo ≠ 0.","Bestandskonten":"Bestandskonten (Aktiva/Passiva) behalten ihren Saldo.","Anlagekonten":"Anlagenkonten sind Bestandskonten — Saldo wird vorgetragen."},"eselsbruecke":"Erfolgskonten = Saldo wird an Gewinn/Verlust-Konto übergeben → neues Jahr beginnt bei 0. Bestandskonten = Saldo läuft weiter. GuV-Konto startet jedes Jahr frisch!"},"source":"SAP"},{"id":"SAP-014","fragen_id":"5044753","thema":"Debitorenbuchhaltung","frage":"Welche Informationen werden in der Kontenstandsanzeige eines Kundenkontos angezeigt?","typ":"multiple_select","optionen":["Kontonummer des Abstimmkontos","Summe der Sollbuchungen für jede Buchungsperiode","Gesamtzahl der offenen Posten","Summe der Habenbuchungen für jede Buchungsperiode"],"richtige_antworten":["Summe der Sollbuchungen für jede Buchungsperiode","Summe der Habenbuchungen für jede Buchungsperiode"],"erklaerung":{"richtig":"Die Kontenstandsanzeige zeigt: Soll- und Habenbuchungen pro Periode (um Umsätze zu sehen) und die Gesamtzahl der offenen Posten (wie viele unbezahlte Rechnungen gibt es).","falsch":{"Kontonummer des Abstimmkontos":"Die Abstimmkonto-Nummer steht im Stammsatz des Geschäftspartners, nicht in der Kontenstandsanzeige."},"eselsbruecke":"Kontenstand zeigt: SOLL + HABEN pro Periode + Anzahl offene Posten. Das Abstimmkonto steht im Stammsatz, nicht hier."},"source":"SAP"},{"id":"SAP-015","fragen_id":"5044754","thema":"Anlagenbuchhaltung","frage":"Was wird in der Anlagenbuchhaltung durch das Bezugsdatum in Geschäftsvorgängen gesteuert?","typ":"multiple_select","optionen":["Das Bestelldatum der Anlage in der Materialwirtschaft","Das Datum, an dem die Anlage von einer Abteilung zu einer anderen transferiert wird","Die Festlegung des Datums der Abschreibungsberechnung in Kombination mit dem Abschreibungsschlüssel","Das Aktivierungsdatum, an dem eine Anlage erworben wurde"],"richtige_antworten":["Die Festlegung des Datums der Abschreibungsberechnung in Kombination mit dem Abschreibungsschlüssel","Das Aktivierungsdatum, an dem eine Anlage erworben wurde"],"erklaerung":{"richtig":"Das Bezugsdatum (auch Wertstellungsdatum) in Anlagenvorgängen hat zwei Funktionen: Es bestimmt den Startpunkt der Abschreibungsberechnung (zusammen mit dem AfA-Schlüssel) und dient als Aktivierungsdatum der Anlage.","falsch":{"Bestelldatum in MM":"Das Bestelldatum wird in der MM-Bestellung gepflegt, nicht über das Bezugsdatum der Anlagenbuchung.","Transferdatum":"Der Anlagentransfer hat ein eigenes Datum (Buchungsdatum), nicht das Bezugsdatum als Steuerelement."},"eselsbruecke":"Bezugsdatum in AA = WANN beginnt die AfA + WANN wurde aktiviert. Zwei Zwecke, ein Datum."},"source":"SAP"},{"id":"SAP-016","fragen_id":"5044755","thema":"Ledger / Rechnungslegung","frage":"Welchen Beleg können Sie bei Verwendung von zwei Ledgern auf ein bestimmtes Ledger mit einer Ledgergruppe buchen?","typ":"multiple_select","optionen":["Abgrenzungsbuchung","Lieferantenrechnung","Sachkontenbeleg","Zahlungsausgang"],"richtige_antworten":["Abgrenzungsbuchung","Sachkontenbeleg"],"erklaerung":{"richtig":"Ledger-spezifische Buchungen (nur in ein bestimmtes Ledger) sind möglich für Abgrenzungsbuchungen (z.B. nur IFRS-Abgrenzung) und Sachkontenbelege. Diese Belege können über eine Ledgergruppe gezielt in ein Ledger gebucht werden.","falsch":{"Lieferantenrechnung":"Lieferantenrechnungen buchen in alle relevanten Ledger gleichzeitig — keine ledger-spezifische Buchung möglich.","Zahlungsausgang":"Zahlungen buchen ebenfalls in alle Ledger — sie können nicht auf ein einzelnes Ledger beschränkt werden."},"eselsbruecke":"Ledger-spezifisch buchbar: Abgrenzungen + Sachkontenbelege. Rechnungen und Zahlungen gehen immer in alle Ledger."},"source":"SAP"},{"id":"SAP-017","fragen_id":"5044756","thema":"MM/FI Integration","frage":"Das WE/RE-Konto weist für einen Einkaufsvorgang einen Sollsaldo auf. Welche Ursache kann das haben?","typ":"single_select","optionen":["Gelieferte Waren mit vollständig beglichener Rechnung","In Rechnung gestellte, aber noch nicht gelieferte Waren","Bestellte, aber noch nicht in Rechnung gestellte oder gelieferte Waren","Gelieferte, aber noch nicht in Rechnung gestellte Waren"],"richtige_antworten":["In Rechnung gestellte, aber noch nicht gelieferte Waren"],"erklaerung":{"richtig":"Das WE/RE-Konto (Waren-Eingang/Rechnungs-Eingang) funktioniert als Verrechnungskonto: Wareneingang = Haben-Buchung, Rechnungseingang = Soll-Buchung. Wenn eine Rechnung kommt bevor die Ware geliefert wurde → nur Soll-Buchung → Sollsaldo.","falsch":{"vollständig beglichen":"Wenn alles geliefert und bezahlt ist, ist das WE/RE-Konto ausgeglichen (Saldo 0).","bestellt aber nicht geliefert/berechnet":"Reine Bestellungen erzeugen keine WE/RE-Buchungen.","geliefert aber nicht berechnet":"Wareneingang ohne Rechnung = Haben-Buchung → Habensaldo, nicht Sollsaldo."},"eselsbruecke":"WE/RE Sollsaldo = Rechnung kommt VOR Ware. Rechnung → Soll. Wareneingang → Haben. Nur Rechnung da = nur Soll = Sollsaldo."},"source":"SAP"},{"id":"SAP-018","fragen_id":"5044757","thema":"Zahlungsverkehr","frage":"Welche Informationen sind in der SAP-Fiori-App 'Debitorensalden anzeigen' verfügbar?","typ":"multiple_select","optionen":["Der kumulierte Saldo eines Kundenkontos","Die Korrespondenzhistorie des entsprechenden Kundenkontos","Der Anfangssaldo eines Kundenkontos","Die Gesamtzahl der mit einer Mahnsperre versehenen Debitorenkonten"],"richtige_antworten":["Der kumulierte Saldo eines Kundenkontos","Der Anfangssaldo eines Kundenkontos"],"erklaerung":{"richtig":"Die App 'Debitorensalden anzeigen' zeigt den kumulierten aktuellen Saldo (Summe aller Buchungen) und den Anfangssaldo (Saldo zu Beginn des Geschäftsjahres) eines Kundenkontos.","falsch":{"Korrespondenzhistorie":"Korrespondenzhistorie ist in der Korrespondenz-App verfügbar, nicht in der Saldo-Anzeige.","Gesamtzahl mit Mahnsperre":"Mahnstatistiken sind im Mahnwesen verfügbar, nicht in der Saldo-App."},"eselsbruecke":"Debitorensalden = kumulierter Saldo (jetzt) + Anfangssaldo (Jahresbeginn). Alles andere steht woanders."},"source":"SAP"},{"id":"SAP-019","fragen_id":"5044758","thema":"Zahlungsverkehr","frage":"Welche Informationen können Sie beim Schritt zur Pflege von Parametern für den Zahllauf eingeben?","typ":"multiple_select","optionen":["Die Buchungskreise, für die Zahlungen angelegt werden sollen","Das Datum, an dem der nächste Zahlungslauf geplant ist","Die auszuwählenden Geschäftspartner","Die Buchungsperioden, die der Zahlungslauf öffnen soll","Den Betrag, den Sie für die Zahlungsläufe zur Verfügung stellen möchten (Höchstbetrag)"],"richtige_antworten":["Die Buchungskreise, für die Zahlungen angelegt werden sollen","Das Datum, an dem der nächste Zahlungslauf geplant ist","Die auszuwählenden Geschäftspartner"],"erklaerung":{"richtig":"In den Zahllauf-Parametern (F110) gibt man ein: Buchungskreise (welche Gesellschaften), Nächstes Zahlungsdatum (bis wann fällige Posten berücksichtigen) und Geschäftspartner (welche Lieferanten/Kunden).","falsch":{"Buchungsperioden öffnen":"Der Zahllauf öffnet keine Buchungsperioden — das ist Aufgabe der Periodensteuerung.","Höchstbetrag":"Der Höchstbetrag pro Hauskonto wird in der Hauskontenkonfiguration gepflegt, nicht in den Zahllauf-Parametern."},"eselsbruecke":"Zahllauf-Parameter: WER zahlt (Buchungskreis) + WANN zahlen (Datum) + AN WEN (Geschäftspartner). Periode öffnen und Höchstbetrag = woanders."},"source":"SAP"},{"id":"SAP-020","fragen_id":"5044759","thema":"Sachkontenstammdaten","frage":"Wie können Sie schnell ein neues Sachkonto in SAP S/4HANA anlegen?","typ":"single_select","optionen":["Sie können mit dem Asset Explorer Sachkonten anlegen.","Sie können mit COPY (mit Vorlage) Sachkonten anlegen.","Sie können mit einem Dauerbuchungsbeleg Sachkonten anlegen.","Sie können mit Bilanz/GuV Sachkonten anlegen."],"richtige_antworten":["Sie können mit COPY (mit Vorlage) Sachkonten anlegen."],"erklaerung":{"richtig":"Die schnellste Methode für ein neues Sachkonto: COPY mit Vorlage (Referenzkonto). Man wählt ein ähnliches bestehendes Konto als Vorlage, passt Nummer und Bezeichnung an — alle anderen Einstellungen werden übernommen.","falsch":{"Asset Explorer":"Der Asset Explorer ist ein Analysewerkzeug für Anlagen, kein Werkzeug zum Anlegen von Sachkonten.","Dauerbuchungsbeleg":"Dauerbuchungen sind für wiederkehrende Buchungen, nicht zum Anlegen von Stammdaten.","Bilanz/GuV":"Die Bilanz/GuV-Struktur ordnet Konten für Berichte an, legt aber keine Konten an."},"eselsbruecke":"Sachkonto schnell anlegen = COPY mit Vorlage. Ähnliches Konto nehmen, anpassen, fertig. Kein Eingeben von Grund auf!"},"source":"SAP"},{"id":"SAP-021","fragen_id":"5044760","thema":"Anlagenbuchhaltung","frage":"Was ist die Hauptaufgabe des Jahresabschlussprogramms in der Anlagenbuchhaltung?","typ":"single_select","optionen":["Sicherstellen, dass eine Abschreibung vollständig auf das aktuelle Jahr gebucht wird, damit das nächste Geschäftsjahr eröffnet werden kann","Einen Status in der Anlagenbuchhaltung setzen, damit Finanzwesen und Controlling ohne Abschluss fortgeführt werden können","Sicherstellen, dass Werte nach geprüften Jahresabschlüssen nicht mehr geändert werden","Sicherstellen, dass alle Rechnungen für das aktuelle Jahr gebucht werden"],"richtige_antworten":["Sicherstellen, dass Werte nach geprüften Jahresabschlüssen nicht mehr geändert werden"],"erklaerung":{"richtig":"Das Jahresabschlussprogramm in AA setzt einen Status der verhindert, dass Anlagenwerte des abgeschlossenen Jahres nachträglich geändert werden. Nach dem Testat dürfen keine Korrekturen mehr möglich sein.","falsch":{"Abschreibung vollständig buchen":"Das ist die Aufgabe des Abschreibungsprogramms (FAA_DEPRECIATION_POST), nicht des Jahresabschlussprogramms.","Status für FI/CO ohne Abschluss":"Das ist keine sinnvolle Beschreibung des Jahresabschlussprogramms.","Rechnungen buchen":"Das Jahresabschlussprogramm bucht keine Rechnungen."},"eselsbruecke":"AA-Jahresabschluss = EINFRIEREN. Nach dem Testat darf niemand mehr Anlagenwerte ändern. Das Programm setzt einen Schutzstatus."},"source":"SAP"},{"id":"SAP-022","fragen_id":"5044761","thema":"Geschäftspartnerstammdaten","frage":"Welche Daten sind Teil eines Debitorenstammsatzes?","typ":"multiple_select","optionen":["Buchungskreisdaten","Allgemeine Daten","Werkbereichsdaten","Kostenrechnungskreisdaten"],"richtige_antworten":["Buchungskreisdaten","Allgemeine Daten"],"erklaerung":{"richtig":"Der Debitorenstammsatz (Geschäftspartner in Debitorenrolle) besteht aus: Allgemeinen Daten (Name, Adresse, Kommunikation — mandantenweit) und Buchungskreisdaten (Abstimmkonto, Zahlungsbedingungen — je Buchungskreis).","falsch":{"Werkbereichsdaten":"Werkbereichsdaten gibt es beim Debitorenstammsatz nicht — das ist ein MM-Konzept (Lieferant pro Werk).","Kostenrechnungskreisdaten":"Debitoren haben keine eigene CO-Ebene im Stammsatz."},"eselsbruecke":"Debitorenstammsatz = ALLGEMEINE Daten (Adresse etc.) + BUCHUNGSKREIS-Daten (FI-Felder). Dazu kommt SD: Vertriebsbereichsdaten. 3 Ebenen."},"source":"SAP"},{"id":"SAP-023","fragen_id":"5044762","thema":"Geschäftspartnerstammdaten","frage":"Welche Felder sind Teil der Buchungskreisdaten (Rolle: FI Debitor) in einem Geschäftspartner-Stammsatz?","typ":"multiple_select","optionen":["Abstimmkonto","Zahlungsbedingungen","Adresse","Bankverbindung"],"richtige_antworten":["Abstimmkonto","Zahlungsbedingungen"],"erklaerung":{"richtig":"In den Buchungskreisdaten (FI-Sicht) des Geschäftspartners stehen: Abstimmkonto (welches G/L-Konto spiegelt den Debitorensaldo) und Zahlungsbedingungen (Skonto, Fälligkeit).","falsch":{"Adresse":"Die Adresse gehört zu den allgemeinen Daten (mandantenweit), nicht zu Buchungskreisdaten.","Bankverbindung":"Bankverbindungen stehen in den allgemeinen Daten, nicht in den Buchungskreisdaten."},"eselsbruecke":"Buchungskreisdaten FI-Debitor = Abstimmkonto + Zahlungsbedingungen. Adresse und Bank = allgemeine Daten (oben im Stammsatz)."},"source":"SAP"},{"id":"SAP-024","fragen_id":"5044763","thema":"Ledger / Rechnungslegung","frage":"Ein Unternehmen bucht einen integrierten Anlagenzugang mit Kreditor in zwei Ledgern (0L und 2L). Welche Buchungen ergeben sich?","typ":"single_select","optionen":["Zwei Belege: Anlagenbestandskonto an Kreditor (0L) und Anlagenbestandskonto an Kreditor (2L)","Drei Belege: Technisches Verrechnungskonto an Kreditor (leer) + Anlagenbestandskonto an techn. Verrechnungskonto (0L) + Anlagenbestandskonto an techn. Verrechnungskonto (2L)","Vier Belege: je zwei pro Ledger","Ein Beleg: Anlagenbestandskonto an Kreditor (Ledger-Gruppe leer)"],"richtige_antworten":["Drei Belege: Technisches Verrechnungskonto an Kreditor (leer) + Anlagenbestandskonto an techn. Verrechnungskonto (0L) + Anlagenbestandskonto an techn. Verrechnungskonto (2L)"],"erklaerung":{"richtig":"Bei einem integrierten Anlagenzugang mit zwei Ledgern entstehen drei Belege: Beleg 1 (ledger-unabhängig): Kreditor an technisches Verrechnungskonto. Beleg 2 (Ledger 0L): Anlagenbestandskonto an Verrechnungskonto. Beleg 3 (Ledger 2L): Anlagenbestandskonto an Verrechnungskonto (mit ggf. anderem Wert).","falsch":{"Zwei Belege":"Zwei wären zu wenig — der Kreditorenbeleg muss ledger-neutral sein.","Vier Belege":"Vier wären zu viele.","Ein Beleg":"Ein Beleg würde die Ledger-Trennung nicht ermöglichen."},"eselsbruecke":"2 Ledger + integrierter Zugang = 3 Belege. Kreditor-Beleg = ledgerneutral. Dann je ein Beleg pro Ledger für den Anlagenteil."},"source":"SAP"},{"id":"SAP-025","fragen_id":"5044764","thema":"SAP Fiori","frage":"Wie heißt der zentrale Startpunkt für Benutzer von SAP-Fiori-Apps?","typ":"single_select","optionen":["SAP Fiori Library","SAP Fiori Launchpad","SAP Fiori Catalog","SAP Fiori Marketplace"],"richtige_antworten":["SAP Fiori Launchpad"],"erklaerung":{"richtig":"Das SAP Fiori Launchpad ist die zentrale Startseite für alle Fiori-Apps. Von hier aus startet der Benutzer alle Apps, sieht Live-Kacheln und kann seinen Arbeitsbereich personalisieren.","falsch":{"Fiori Library":"Die Fiori App Library ist eine Dokumentations-Website für Entwickler/Administratoren, kein Benutzer-Startpunkt.","Fiori Catalog":"Kataloge sind Admin-Konfigurationsobjekte im Launchpad, keine eigenständige Startseite.","Fiori Marketplace":"Gibt es nicht als SAP-Produkt in diesem Kontext."},"eselsbruecke":"Fiori Launchpad = die Startseite. Wie der Desktop von Windows. Von hier aus alles starten. Launchpad = Abschussrampe für alle Apps."},"source":"SAP"},{"id":"SAP-026","fragen_id":"5044765","thema":"Belegarten","frage":"Was steuern Belegarten?","typ":"single_select","optionen":["Die Verwendung eines Nummernkreises für Belegnummern","Die Struktur von Einzelposten","Die verfügbaren Kontierungsobjekte","Die Verwendung von Abstimmkonten"],"richtige_antworten":["Die Verwendung eines Nummernkreises für Belegnummern"],"erklaerung":{"richtig":"Die wichtigste Funktion der Belegart: sie bestimmt welcher Nummernkreis für die Belegnummernvergabe verwendet wird. Jede Belegart hat einen zugeordneten Nummernkreis (z.B. KR=Kreditorenrechnung → Nummernkreis 19).","falsch":{"Struktur von Einzelposten":"Die Struktur der Einzelposten wird durch den Buchungsschlüssel gesteuert.","Kontierungsobjekte":"Kontierungsobjekte werden durch die Feldstatusvariante und den Buchungsschlüssel gesteuert.","Abstimmkonten":"Abstimmkonten sind im Geschäftspartnerstammsatz hinterlegt."},"eselsbruecke":"Belegart → Nummernkreis. Belegart KR → Nummernkreis 19 → Belegnummer 1900000xxx. Belegart = Kategorie + Nummerierung."},"source":"SAP"},{"id":"SAP-027","fragen_id":"5044766","thema":"Anlagenbuchhaltung","frage":"Von welchem Objekt hängt es ab, ob die Anlage mit Skonto (Bruttobuchung) oder ohne Skonto (Nettobuchung) aktiviert wird?","typ":"single_select","optionen":["Geschäftspartnerrolle","Belegart","Anlagenklasse","Buchungsschlüssel"],"richtige_antworten":["Belegart"],"erklaerung":{"richtig":"Ob eine Anlage zum Brutto- oder Nettowert (mit oder ohne Skonto) aktiviert wird, steuert die Belegart. In der Belegart ist hinterlegt ob Skonto den Anschaffungswert reduziert oder nicht.","falsch":{"Geschäftspartnerrolle":"Die Geschäftspartnerrolle steuert Stammdatenfelder, nicht die Aktivierungslogik.","Anlagenklasse":"Die Anlagenklasse steuert AfA-Parameter und Kontenfindung, nicht Skonto-Behandlung.","Buchungsschlüssel":"Buchungsschlüssel steuern Soll/Haben und Kontoart."},"eselsbruecke":"Brutto oder Netto aktivieren? → Belegart entscheidet. Die Belegart hat ein Kennzeichen für Skonto-Behandlung bei Anlagen."},"source":"SAP"},{"id":"SAP-028","fragen_id":"5044767","thema":"Anlagenbuchhaltung","frage":"Welchen Zwecken dient das Anlagengitter?","typ":"multiple_select","optionen":["Der Ergänzung der Bilanz aus der Perspektive der Anlagenbuchhaltung","Der automatischen Abstimmung von Anlagenkäufen und -verkäufen des Konzerns","Der Prüfung von falschen Stammsätzen und Buchungen für das aktuelle Jahr","Der Bereitstellung von Informationen zu Anlagenabgängen"],"richtige_antworten":["Der Ergänzung der Bilanz aus der Perspektive der Anlagenbuchhaltung","Der Bereitstellung von Informationen zu Anlagenabgängen"],"erklaerung":{"richtig":"Das Anlagengitter (auch Anlagenspiegel) ist gesetzlich vorgeschrieben und zeigt die Entwicklung des Anlagevermögens im Geschäftsjahr: Anfangsbestand, Zugänge, Abgänge, Umbuchungen, Abschreibungen, Endbestand. Es ergänzt die Bilanz und liefert Details zu Abgängen.","falsch":{"automatische Abstimmung Konzern":"Konzernabstimmung ist eine separate Aufgabe (Intercompany-Reconciliation), keine Funktion des Anlagengitters.","Prüfung falscher Stammsätze":"Das Anlagengitter ist kein Prüfwerkzeug für Stammsätze."},"eselsbruecke":"Anlagengitter = gesetzlicher Anhang zur Bilanz. Zeigt: wie hat sich das Anlagevermögen entwickelt? Zugänge, Abgänge, AfA."},"source":"SAP"},{"id":"SAP-029","fragen_id":"5044768","thema":"Sachkontenstammdaten","frage":"Welche Kontoart wird verwendet, um ein Nebenbuchkonto und das Hauptbuch miteinander zu verbinden?","typ":"single_select","optionen":["Ausgleichskonto","Abstimmkonto","Referenzkonto","Abgleichskonto"],"richtige_antworten":["Abstimmkonto"],"erklaerung":{"richtig":"Das Abstimmkonto ist das Bindeglied zwischen Nebenbuch (Debitoren-/Kreditorenbuchhaltung) und Hauptbuch. Jede Buchung auf einem Debitor/Kreditor-Konto wird automatisch und parallel auf das zugehörige Abstimmkonto im Hauptbuch gebucht.","falsch":{"Ausgleichskonto":"Ausgleichskonten werden für Clearing-Vorgänge genutzt, nicht als Verbindung Nebenbuch-Hauptbuch.","Referenzkonto":"Referenzkonten sind Vorlagen beim Anlegen von Sachkonten.","Abgleichskonto":"Dieser Begriff existiert nicht als SAP-Standard."},"eselsbruecke":"Abstimmkonto = Brücke Nebenbuch ↔ Hauptbuch. Debitor buchen → automatisch auf Abstimmkonto im HB. Deshalb HB immer aktuell!"},"source":"SAP"},{"id":"SAP-030","fragen_id":"5044769","thema":"S/4HANA Vorteile","frage":"Nennen Sie einige Vorteile von SAP S/4HANA.","typ":"multiple_select","optionen":["Sie modelliert alle Anforderungen aller Branchen in einer einzigen Softwarelösung.","Die Daten können in Echtzeit gelesen werden.","Sie erfordert weniger Hardware.","Datenmodelle können vereinfacht werden, indem beispielsweise Redundanzen vermieden werden.","Die Servicekosten werden reduziert, da sich alle Daten in der Cloud befinden."],"richtige_antworten":["Die Daten können in Echtzeit gelesen werden.","Sie erfordert weniger Hardware.","Die Servicekosten werden reduziert, da sich alle Daten in der Cloud befinden."],"erklaerung":{"richtig":"S/4HANA-Vorteile: Eine Lösung für alle Branchen (Industrie, Handel, Dienstleistung etc.), Echtzeit-Datenverarbeitung dank In-Memory-Technologie, weniger Hardware durch effizientere Speicherung, und vereinfachte Datenmodelle (z.B. keine Summenspeicher-Tabellen mehr).","falsch":{"Servicekosten Cloud":"S/4HANA gibt es auch On-Premise — es ist nicht zwingend Cloud-basiert. Servicekosten sind nicht pauschal reduziert."},"eselsbruecke":"S/4HANA = Eine Lösung + Echtzeit + weniger Hardware + einfacheres Datenmodell. Nicht zwingend Cloud!"},"source":"SAP"},{"id":"SAP-031","fragen_id":"5044770","thema":"Geschäftspartnerstammdaten","frage":"Welche Felder im Geschäftspartnerstammsatz können bei verschiedenen Buchungskreisen voneinander abweichen?","typ":"multiple_select","optionen":["Zahlungsbedingungen","Mahnverfahren","Zahlweg","Sprache","Bankverbindung"],"richtige_antworten":["Zahlungsbedingungen","Mahnverfahren","Zahlweg"],"erklaerung":{"richtig":"Buchungskreisspezifische Felder im GP-Stammsatz: Zahlungsbedingungen (verschiedene Konditionen je BuKr möglich), Mahnverfahren (verschiedene Mahnverfahren je BuKr) und Zahlweg (in BuKr A per Überweisung, in BuKr B per Scheck).","falsch":{"Sprache":"Die Sprache ist ein allgemeines Feld (mandantenweit) — sie ist für alle Buchungskreise gleich.","Bankverbindung":"Bankverbindungen sind ebenfalls allgemeine Daten — sie gelten für alle Buchungskreise."},"eselsbruecke":"Buchungskreis-spezifisch: ZAHLUNG (Bedingung + Weg) + MAHNUNG (Verfahren). Sprache und Bank = allgemein für alle BuKr."},"source":"SAP"},{"id":"SAP-032","fragen_id":"5044771","thema":"Geschäftspartnerstammdaten","frage":"Aus welchen Organisationselementen bestehen Vertriebsbereichsdaten eines Debitorenstammsatzes?","typ":"single_select","optionen":["Verkaufsorganisation, Vertriebsweg und Sparte","Verkaufsorganisation, Werk und Sparte","Verkaufsorganisation, Debitorengruppe und Kundenbezirk","Vertriebsweg, Sparte und Segment"],"richtige_antworten":["Verkaufsorganisation, Vertriebsweg und Sparte"],"erklaerung":{"richtig":"Der Vertriebsbereich in SAP SD besteht aus drei Elementen: Verkaufsorganisation (rechtliche Einheit für Verkauf), Vertriebsweg (wie wird verkauft: Direktvertrieb, Handel etc.) und Sparte (welche Produktgruppe: z.B. Fahrzeuge, Ersatzteile).","falsch":{"Werk":"Das Werk ist eine MM-Organisationseinheit, kein Teil des Vertriebsbereichs.","Debitorengruppe/Kundenbezirk":"Das sind Merkmale innerhalb des Vertriebsbereichs, keine definierenden Organisationselemente.","Segment":"Segment ist eine FI-Berichtseinheit, kein SD-Vertriebsbereichselement."},"eselsbruecke":"Vertriebsbereich = VKOrg + Vertriebsweg + Sparte. Die drei V's (und ein S). WER verkauft + WIE + WAS."},"source":"SAP"},{"id":"SAP-033","fragen_id":"5044772","thema":"Periodenabschluss","frage":"Unter welchen Umständen ist eine Umgliederung notwendig?","typ":"multiple_select","optionen":["Forderungen und Verbindlichkeiten in Fremdwährungen müssen für Bilanzberichte nach Fremdwährung gruppiert werden.","Es gibt weiterhin offene Forderungen und Verbindlichkeiten, die getrennt nach offen und ausgeglichen aufgeführt werden müssen.","Es gibt Kreditoren mit Sollsaldo und Debitoren mit Habensaldo.","Länderspezifische Vorschriften schreiben vor, dass Verbindlichkeiten und Forderungen nach Restlaufzeiten gemeldet werden müssen."],"richtige_antworten":["Es gibt Kreditoren mit Sollsaldo und Debitoren mit Habensaldo.","Länderspezifische Vorschriften schreiben vor, dass Verbindlichkeiten und Forderungen nach Restlaufzeiten gemeldet werden müssen."],"erklaerung":{"richtig":"Zwei Gründe für Umgliederung: Kreditoren mit Sollsaldo müssen auf der Aktivseite ausgewiesen werden (und umgekehrt) — das erfordert Umgliederung. Und nach HGB/IFRS müssen Forderungen/Verbindlichkeiten nach Fristigkeit (kurzfristig/langfristig) getrennt werden.","falsch":{"Fremdwährung nach Währung gruppieren":"Das ist keine Umgliederungsvoraussetzung.","offen vs. ausgeglichen":"Diese Trennung ist keine Umgliederungsvoraussetzung."},"eselsbruecke":"Umgliederung nötig wenn: Kredit hat Sollsaldo (falsche Bilanzseite!) ODER Gesetze verlangen Fristentrennung. Zwei klare Fälle."},"source":"SAP"},{"id":"SAP-034","fragen_id":"5044773","thema":"Ledger / Rechnungslegung","frage":"Welche Vorteile bieten Erweiterungsledger?","typ":"multiple_select","optionen":["Erweiterungsledger können für Predictive Accounting verwendet werden.","Im Erweiterungsledger werden Daten aus dem zugrunde liegenden Ledger als Sicherheitsmaßnahme noch einmal gespeichert.","Sie können einem Erweiterungsledger eine separate Buchungsperiodenvariante zuordnen.","In Erweiterungsledgern werden Daten aus verschiedenen zugrunde liegenden Ledgern automatisch abgestimmt."],"richtige_antworten":["Erweiterungsledger können für Predictive Accounting verwendet werden.","Sie können einem Erweiterungsledger eine separate Buchungsperiodenvariante zuordnen."],"erklaerung":{"richtig":"Erweiterungsledger (Extension Ledger) sind schlanke Ergänzungen zu einem Basis-Ledger. Vorteile: Predictive Accounting (Planwerte/Prognosen separat führen) und eigene Buchungsperiodenvariante (andere Öffnungs-/Schließungszeiten).","falsch":{"Sicherheitskopie":"Erweiterungsledger sind KEINE Sicherheitskopien — sie speichern NUR die Delta-Buchungen, nicht alles.","automatische Abstimmung":"Erweiterungsledger stimmen keine verschiedenen Basis-Ledger ab."},"eselsbruecke":"Erweiterungsledger = leichtes Zusatz-Ledger. Gut für Predictive Accounting und eigene Periodensteuerung. Keine Kopie!"},"source":"SAP"},{"id":"SAP-035","fragen_id":"5044774","thema":"Sachkontenstammdaten","frage":"Was ist der Zweck eines Abstimmkontos in SAP S/4HANA?","typ":"single_select","optionen":["Die Abstimmung zwischen MM und FI während des Jahresabschlusses","Die Aktivierung der Berichterstattung über Unterschiede zwischen verschiedenen Rechnungslegungsvorschriften","Die transparente Dokumentierung der Antworten in Verbindung mit Saldenbestätigungen","Nur Buchungen in einem entsprechenden Nebenbuch zuzulassen"],"richtige_antworten":["Nur Buchungen in einem entsprechenden Nebenbuch zuzulassen"],"erklaerung":{"richtig":"Der Zweck des Abstimmkontos: Es erlaubt keine direkten manuellen Buchungen — es kann nur durch Buchungen im entsprechenden Nebenbuch (Debitoren oder Kreditoren) bebucht werden. Das stellt sicher dass Nebenbuch und Hauptbuch immer übereinstimmen.","falsch":{"MM/FI Abstimmung":"Das WE/RE-Konto dient der MM/FI-Abstimmung, nicht das Abstimmkonto.","Rechnungslegungsvorschriften":"Unterschiede zwischen Vorschriften werden über Ledger oder Konten abgebildet.","Saldenbestätigungen":"Saldenbestätigungen sind eine separate Jahresabschlussaktivität."},"eselsbruecke":"Abstimmkonto = gesperrtes Konto. Nur Nebenbuch darf buchen, kein Mensch direkt. So bleiben HB und NB immer gleich."},"source":"SAP"},{"id":"SAP-036","fragen_id":"5044775","thema":"Organisationsstruktur","frage":"Welche Zuordnungen können zwischen Kostenrechnungskreis (CO) und Buchungskreis (FI) vorgenommen werden?","typ":"multiple_select","optionen":["Mehreren Kostenrechnungskreisen kann ein einzelner Buchungskreis zugeordnet sein.","Einem Kostenrechnungskreis können mehrere Buchungskreise zugeordnet sein.","Ein Buchungskreis ist automatisch zugleich der Kostenrechnungskreis.","Einem Kostenrechnungskreis kann ein einzelner Buchungskreis zugeordnet sein."],"richtige_antworten":["Einem Kostenrechnungskreis können mehrere Buchungskreise zugeordnet sein.","Einem Kostenrechnungskreis kann ein einzelner Buchungskreis zugeordnet sein."],"erklaerung":{"richtig":"Die Zuordnung CO zu FI: Einem Kostenrechnungskreis können ein ODER mehrere Buchungskreise zugeordnet sein. Ein Buchungskreis gehört immer zu genau einem Kostenrechnungskreis.","falsch":{"mehrere KoRe für einen BuKr":"Ein Buchungskreis kann NUR einem Kostenrechnungskreis zugeordnet sein — nicht mehreren.","automatisch gleich":"In S/4HANA können BuKr und KoRe identisch sein — aber das ist nicht automatisch so."},"eselsbruecke":"KoRe → BuKr: 1 KoRe kann 1 oder viele BuKr haben. Aber: 1 BuKr gehört immer nur zu 1 KoRe. Einbahnstraße!"},"source":"SAP"},{"id":"SAP-037","fragen_id":"5044776","thema":"SAP Fiori","frage":"Wozu dient die SAP-Fiori-App 'Anlagen verwalten'?","typ":"multiple_select","optionen":["Zum Anzeigen anteiliger Wertberichtigungen in den Bewertungsbereichen","Zum Auslösen der Berechnung/Buchung der geplanten Abschreibung","Zur Navigation zu weiteren Aktionen, z.B. Ändern von Werten in den Anlagenstammsätzen","Zum Navigieren zu den Buchungsbelegen für eine Anlage","Zum Ausführen des Jahresabschlussprogramms für eine Anlage"],"richtige_antworten":["Zum Anzeigen anteiliger Wertberichtigungen in den Bewertungsbereichen","Zur Navigation zu weiteren Aktionen, z.B. Ändern von Werten in den Anlagenstammsätzen","Zum Navigieren zu den Buchungsbelegen für eine Anlage"],"erklaerung":{"richtig":"Die App 'Anlagen verwalten' ist eine zentrale Fiori-App für die Anlagenbuchhaltung. Sie bietet alle fünf genannten Funktionen: Wertanzeige, AfA-Auslösung, Stammsatz-Navigation, Belegnavigation und Jahresabschluss.","falsch":{},"eselsbruecke":"Anlagen verwalten = die Zentrale für alle Anlagenaktivitäten in Fiori. Anzeigen + Buchen + Navigieren + Jahresabschluss — alles aus einer App."},"source":"SAP"},{"id":"SAP-038","fragen_id":"5044777","thema":"Berichtswesen","frage":"Für welche der folgenden Objekte kann optional eine Bilanz erstellt werden?","typ":"multiple_select","optionen":["Werk","Profitcenter","Geschäftsbereich","Ergebnisbereich","Segment"],"richtige_antworten":["Profitcenter","Geschäftsbereich","Segment"],"erklaerung":{"richtig":"Optionale Bilanzen können in SAP für Profitcenter (interne Steuerung), Geschäftsbereiche (Spartenbilanz) und Segmente (IFRS 8 Segmentberichterstattung) erstellt werden.","falsch":{"Werk":"Das Werk ist eine operative Einheit für MM/PP — keine Bilanzierungseinheit.","Ergebnisbereich":"Ergebnisbereiche sind für Deckungsbeitragsrechnung (CO-PA), nicht für Bilanzen."},"eselsbruecke":"Optionale Bilanzen: Profitcenter + Geschäftsbereich + Segment. Werk und Ergebnisbereich = keine Bilanz."},"source":"SAP"},{"id":"SAP-039","fragen_id":"5044778","thema":"Periodenabschluss","frage":"Welche SAP-Programme/-Funktionen können für automatische Abgrenzungsbuchungen für Mietvorauszahlungen verwendet werden?","typ":"multiple_select","optionen":["Zahlungsprogramm","Dauerbuchungen","Pauschalierte Einzelwertberichtigung","Abgrenzungsverwaltung/Accrual Engine"],"richtige_antworten":["Dauerbuchungen","Abgrenzungsverwaltung/Accrual Engine"],"erklaerung":{"richtig":"Für automatische Mietabgrenzungen eignen sich: Dauerbuchungen (wiederkehrende Buchungen jeden Monat) und die Accrual Engine (automatische Abgrenzungsverwaltung mit periodengenauer Verteilung).","falsch":{"Zahlungsprogramm":"Das Zahlungsprogramm führt Zahlungen aus, bucht aber keine Abgrenzungen.","Pauschalierte Einzelwertberichtigung":"Das ist ein Instrument für Forderungsabschreibungen, nicht für Mietabgrenzungen."},"eselsbruecke":"Mietabgrenzung automatisch: Dauerbuchungen (einfach, wiederkehrend) ODER Accrual Engine (komplex, periodengenau). Zwei Werkzeuge, ein Ziel."},"source":"SAP"},{"id":"SAP-040","fragen_id":"5044779","thema":"Mahnwesen","frage":"Welche der folgenden Felder für Geschäftspartner-Stammdaten werden während des Mahnlaufs automatisch aktualisiert?","typ":"multiple_select","optionen":["Mahnverfahren","Letzte Mahnung","Mahnsperre","Mahnstufe"],"richtige_antworten":["Letzte Mahnung","Mahnstufe"],"erklaerung":{"richtig":"Nach dem Mahnlauf werden automatisch aktualisiert: Letzte Mahnung (Datum der letzten Mahnung wird gesetzt) und Mahnstufe (auf welcher Stufe befindet sich der Partner aktuell).","falsch":{"Mahnverfahren":"Das Mahnverfahren ist eine Konfigurationseinstellung — es wird nicht automatisch durch den Mahnlauf geändert.","Mahnsperre":"Die Mahnsperre muss manuell gesetzt/entfernt werden — sie wird nicht automatisch aktualisiert."},"eselsbruecke":"Nach dem Mahnlauf automatisch aktuell: WANN zuletzt gemahnt (Letzte Mahnung) + WIE WEIT eskaliert (Mahnstufe). Verfahren und Sperre = manuell."},"source":"SAP"},{"id":"SAP-041","fragen_id":"5044780","thema":"Zahlungsverkehr","frage":"Auf welche Objekte kann der Zahlungslauf buchen?","typ":"multiple_select","optionen":["Geschäftspartner in Kreditorenrolle","Wareneingangs-/Rechnungseingangsverrechnungskonto","Sachkonto und Skonto","Materialbestandskonto"],"richtige_antworten":["Geschäftspartner in Kreditorenrolle","Sachkonto und Skonto"],"erklaerung":{"richtig":"Der Zahllauf bucht auf: Kreditorenkonten (Ausgleich der offenen Posten) und Sachkonten inkl. Skontokonto (Bankausgang und eventuelle Skontobuchung).","falsch":{"WE/RE-Konto":"Das WE/RE-Konto wird bei Wareneingängen/Rechnungen bebucht, nicht beim Zahllauf.","Materialbestandskonto":"Materialbestandskonten sind MM-Konten — der Zahllauf bucht nicht auf Materialkonten."},"eselsbruecke":"Zahllauf bucht: Kredit-Konto (Schuld weg) + Bank-Sachkonto (Geld weg) + ggf. Skonto. Keine MM-Konten!"},"source":"SAP"},{"id":"SAP-042","fragen_id":"5044781","thema":"Berichtswesen","frage":"Welche Gründe gibt es, verschiedene Versionen von Bilanzen und GuV-Rechnungen anzulegen?","typ":"multiple_select","optionen":["Um Bilanz und GuV auf Basis der Anforderungen der Personalverwaltung anzulegen","Um Bilanz und GuV für verschiedene Bewertungsbasen (z.B. IAS und US-GAAP) anzulegen","Um Bilanz und GuV auf Basis der Nutzungsdauer von aktiven Anlagen anzulegen","Um Bilanz und GuV gemäß internen Unternehmensaspekten anzulegen"],"richtige_antworten":["Um Bilanz und GuV für verschiedene Bewertungsbasen (z.B. IAS und US-GAAP) anzulegen","Um Bilanz und GuV gemäß internen Unternehmensaspekten anzulegen"],"erklaerung":{"richtig":"Verschiedene Bilanz-/GuV-Versionen werden benötigt für: verschiedene Rechnungslegungsstandards (IAS, US-GAAP, HGB) und interne Managementberichte (andere Gliederung als der externe Abschluss).","falsch":{"Personalverwaltung":"HR-Anforderungen sind kein Grund für verschiedene Bilanz-Versionen.","Nutzungsdauer von Anlagen":"Die Nutzungsdauer beeinflusst AfA-Beträge, ist aber kein Grund für separate Bilanz-Versionen."},"eselsbruecke":"Verschiedene Bilanzen: externe Standards (IAS, GAAP, HGB) + interne Steuerung. Zwei Welten, zwei Bilanzen."},"source":"SAP"},{"id":"SAP-043","fragen_id":"5044782","thema":"MM/FI Integration","frage":"Was ist das WE/RE-Konto?","typ":"single_select","optionen":["Ein Verrechnungskonto für Wechsel und die entsprechenden Rechnungen","Ein Verrechnungskonto für Lieferantenrechnungen in einer Fremdwährung","Ein Verrechnungskonto für Waren- und Rechnungseingänge","Ein Verrechnungskonto für nicht integrierte Kreditorenrechnungsbuchungen"],"richtige_antworten":["Ein Verrechnungskonto für Waren- und Rechnungseingänge"],"erklaerung":{"richtig":"Das WE/RE-Konto (Wareneingang/Rechnungseingang) ist das Verrechnungskonto für den MM/FI-integrierten Einkaufsprozess. Bei Wareneingang: Kreditbuchung auf WE/RE. Bei Rechnungseingang: Sollbuchung auf WE/RE. Bei beiden → Saldo = 0.","falsch":{"Wechsel":"Wechsel haben eigene Sonderhauptbuchkonten.","Fremdwährungsrechnungen":"Fremdwährungsrechnungen gehen auf normale Kreditorenkonten mit Fremdwährungsbehandlung.","nicht integriert":"Das WE/RE-Konto ist speziell für den INTEGRIERTEN MM/FI-Prozess."},"eselsbruecke":"WE/RE = Brücke zwischen Wareneingang (MM) und Rechnungseingang (FI). Ware kommt → Haben. Rechnung kommt → Soll. Beide da → Null."},"source":"SAP"},{"id":"SAP-044","fragen_id":"5044783","thema":"Sachkontenstammdaten","frage":"Ihr Unternehmen hat die Hausbank gewechselt. Was müssen Sie beim Anlegen des Sachkontos berücksichtigen?","typ":"multiple_select","optionen":["Der Sachkontoname wird automatisch vom SAP-System definiert und kann nicht geändert werden.","Das Feld für den Sachkontonamen ist ein Mussfeld und kann nicht übersprungen werden.","Der Name der Bank sollte nach Möglichkeit im Namen des Sachkontos enthalten sein.","Der Sachkontoname muss genau dem Namen im Bankleitzahlenindex entsprechen."],"richtige_antworten":["Das Feld für den Sachkontonamen ist ein Mussfeld und kann nicht übersprungen werden.","Der Name der Bank sollte nach Möglichkeit im Namen des Sachkontos enthalten sein."],"erklaerung":{"richtig":"Beim Anlegen eines Bankkontos: Der Sachkontoname ist ein Pflichtfeld (Mussfeld). Es empfiehlt sich den Banknamen im Kontonamen zu verwenden (z.B. 'Commerzbank Girokonto') für bessere Identifikation.","falsch":{"automatisch definiert":"SAP definiert den Kontonamen nicht automatisch — er muss manuell eingegeben werden.","genau wie im Bankleitzahlenindex":"Es gibt keine Pflicht den exakten Namen aus dem Bankleitzahlenindex zu verwenden."},"eselsbruecke":"Bankkonto anlegen: Name = Pflichtfeld + Bankname reinnehmen damit man's gleich erkennt. Kein automatischer Name!"},"source":"SAP"},{"id":"SAP-045","fragen_id":"5044784","thema":"Zahlungsverkehr","frage":"Welche Felder müssen bei der manuellen Buchung einer Eingangszahlung gefüllt werden (SAP-Fiori-App 'Eingangszahlungen buchen')?","typ":"multiple_select","optionen":["Ausgleichstext","Betrag","Buchungsdatum","Abstimmkonto","Bankkonto"],"richtige_antworten":["Betrag","Buchungsdatum","Bankkonto"],"erklaerung":{"richtig":"Pflichtfelder beim manuellen Buchen einer Eingangszahlung: Betrag (wie viel wurde gezahlt), Buchungsdatum (wann wurde gebucht) und Bankkonto (auf welches Konto ist das Geld gegangen).","falsch":{"Ausgleichstext":"Der Ausgleichstext ist ein optionales Beschreibungsfeld.","Abstimmkonto":"Das Abstimmkonto wird automatisch aus dem Debitorenstammsatz gezogen — es muss nicht manuell eingegeben werden."},"eselsbruecke":"Eingangszahlung: WIE VIEL (Betrag) + WANN (Datum) + WOHIN (Bankkonto). Drei Pflichtfelder, Rest ist optional."},"source":"SAP"},{"id":"SAP-046","fragen_id":"5044785","thema":"Debitorenbuchhaltung","frage":"Wozu dient eine 'pauschalierte Wertberichtigung'?","typ":"single_select","optionen":["Zur Neubewertung des Forderungsbetrags aufgrund von unvorhersehbaren allgemeinen Kreditrisiken","Damit Forderungen auf den Barwert am Bilanzstichtag abgezinst werden können","Zum Gewähren von Mengenrabatten an Kunden je nach Forderungsbetrag","Zur Anpassung von Forderungen, deren Höhe sich als falsch erwiesen hat"],"richtige_antworten":["Zur Neubewertung des Forderungsbetrags aufgrund von unvorhersehbaren allgemeinen Kreditrisiken"],"erklaerung":{"richtig":"Die pauschalierte Wertberichtigung (PWB) erfasst das allgemeine Kreditrisiko: nicht einzelne zweifelhafte Forderungen, sondern ein pauschales Ausfallrisiko (z.B. 1% aller Forderungen könnten ausfallen). Das ist HGB-Pflicht.","falsch":{"Barwert abzinsen":"Abzinsung ist ein separates IFRS-Konzept (für langfristige Forderungen), nicht die PWB.","Mengenrabatte":"Rabatte haben nichts mit Wertberichtigungen zu tun.","falsche Forderungshöhe":"Das wäre eine Einzelwertberichtigung oder Korrektur, nicht die PWB."},"eselsbruecke":"Pauschal = nicht einzeln, sondern en bloc. 1% von allen Forderungen → allgemeines Risiko. Das ist die PWB."},"source":"SAP"},{"id":"SAP-047","fragen_id":"5044786","thema":"Anlagenbuchhaltung","frage":"Wie wirkt es sich im System aus, wenn ein Abgang mit einem Debitor gebucht wird?","typ":"multiple_select","optionen":["Anlagen erhalten automatisch ein Abgangsdatum, wenn sie vollständig verkauft oder verschrottet werden.","Die Anlagenwerte werden als statistische Werte für eine mögliche Ersetzung vorgetragen.","Die Abschreibung des laufenden Jahres bis zum Verkaufsdatum wird storniert.","Der Gewinn oder Verlust wird automatisch berechnet und gebucht.","Anlagen mit Abgangsdatum werden anschließend nicht in der Anlagenbestandsliste aufgeführt."],"richtige_antworten":["Anlagen erhalten automatisch ein Abgangsdatum, wenn sie vollständig verkauft oder verschrottet werden.","Der Gewinn oder Verlust wird automatisch berechnet und gebucht.","Anlagen mit Abgangsdatum werden anschließend nicht in der Anlagenbestandsliste aufgeführt."],"erklaerung":{"richtig":"Bei Abgang mit Debitor passiert automatisch: Abgangsdatum wird gesetzt, statistische Werte bleiben für Auswertungen, AfA bis Abgangsdatum wird storniert (zeitanteilig), Anlage verschwindet aus der Bestandsliste.","falsch":{"Gewinn/Verlust automatisch":"Gewinn/Verlust WIRD berechnet — aber erst wenn der Erlös bekannt ist. Bei reiner Verschrottung ohne Erlös gibt es keinen G/V."},"eselsbruecke":"Anlagenabgang: Datum gesetzt + statistische Werte bleiben + AfA storniert + aus Bestandsliste raus. Gewinn/Verlust = separat berechnet."},"source":"SAP"},{"id":"SAP-048","fragen_id":"5044787","thema":"Periodenabschluss","frage":"Wann ist eine Fremdwährungsbewertung als Teil der Abschlussvorbereitung erforderlich?","typ":"single_select","optionen":["Wenn das Unternehmen Kunden im Ausland hat","Wenn eine Saldenbestätigung für einen ausländischen Geschäftspartner angelegt werden muss","Wenn offene Posten in einer Fremdwährung in den Nebenbuchkonten vorhanden sind","Wenn das Unternehmen über Importe verfügt"],"richtige_antworten":["Wenn offene Posten in einer Fremdwährung in den Nebenbuchkonten vorhanden sind"],"erklaerung":{"richtig":"Eine Fremdwährungsbewertung ist genau dann nötig wenn es zum Stichtag noch OFFENE (unbezahlte) Posten in Fremdwährung gibt. Diese müssen zum aktuellen Kurs bewertet werden um ein korrektes Bilanzbild zu zeigen.","falsch":{"Auslandskunden":"Auslandskunden allein bedeuten nicht automatisch offene FW-Posten zum Stichtag.","Saldenbestätigung":"Saldenbestätigungen sind eine separate Aktivität unabhängig von der FW-Bewertung.","Importe":"Importe allein — wenn bereits bezahlt — erfordern keine FW-Bewertung mehr."},"eselsbruecke":"FW-Bewertung NUR wenn: offene Posten in Fremdwährung vorhanden. Bezahlt = kein offener Posten = keine Bewertung nötig."},"source":"SAP"},{"id":"SAP-049","fragen_id":"5044788","thema":"Buchungskreis","frage":"Was ist der Buchungskreis als Organisationseinheit in SAP S/4HANA?","typ":"multiple_select","optionen":["Er ist die höchste Organisationseinheit im Finanzwesen.","Er ist die höchste Organisationseinheit im Konzernberichtswesen.","Er ist die höchste Organisationseinheit im internen Rechnungswesen.","Er ist die höchste Organisationseinheit, für die eine vollständig in sich geschlossene Buchhaltung abgebildet werden kann."],"richtige_antworten":["Er ist die höchste Organisationseinheit im Finanzwesen.","Er ist die höchste Organisationseinheit, für die eine vollständig in sich geschlossene Buchhaltung abgebildet werden kann."],"erklaerung":{"richtig":"Der Buchungskreis repräsentiert eine rechtlich selbstständige Einheit (z.B. eine GmbH) mit vollständiger Buchhaltung: Bilanz, GuV, alle Konten. Er ist NICHT die höchste Einheit im SAP-System (das ist der Mandant), aber die höchste für vollständige externe Buchhaltung.","falsch":{"höchste im Finanzwesen":"Der Mandant ist höher als der Buchungskreis.","Konzernberichtswesen":"Für Konzernberichte gibt es den Konzernkreis — über dem Buchungskreis.","internes Rechnungswesen":"Für CO ist der Kostenrechnungskreis die zentrale Einheit."},"eselsbruecke":"Buchungskreis = eine Firma mit vollständiger Buchhaltung. Bilanz + GuV = vollständig. Mandant ist höher, aber BuKr = vollständige Buchhaltung."},"source":"SAP"},{"id":"SAP-050","fragen_id":"5044789","thema":"Sachkontenstammdaten","frage":"Wie wirkt sich die Definition eines Sachkontos als Abstimmkonto aus?","typ":"multiple_select","optionen":["Jede Buchung auf einem Debitoren- oder Kreditorenkonto führt zu einer unmittelbaren automatischen Änderung im Hauptbuch.","Für den zentralen Geschäftspartner können Abstimmkonten in den Adressdaten gespeichert werden.","Mehrere Standardsachkonten können in diesem Abstimmkonto zugeordnet werden.","In der Hauptbuchhaltung können keine direkten Buchungen auf Abstimmkonten vorgenommen werden."],"richtige_antworten":["Jede Buchung auf einem Debitoren- oder Kreditorenkonto führt zu einer unmittelbaren automatischen Änderung im Hauptbuch.","In der Hauptbuchhaltung können keine direkten Buchungen auf Abstimmkonten vorgenommen werden."],"erklaerung":{"richtig":"Auswirkungen des Abstimmkonto-Kennzeichens: Automatische Parallelfortschreibung (Nebenbuch → HB in Echtzeit), Abstimmkonto im GP-Stammsatz hinterlegbar, mehrere GP-Konten können dasselbe Abstimmkonto nutzen.","falsch":{"keine direkten Buchungen":"Das ist zwar generell richtig als Konzept, aber die Aussage ist hier falsch formuliert — Abstimmkonten KÖNNEN in bestimmten Szenarien direkt bebucht werden (z.B. Fremdwährungsbewertung)."},"eselsbruecke":"Abstimmkonto: automatisch mitgebucht + im GP-Stamm hinterlegt + mehrere GPs teilen ein Abstimmkonto. Kein direktes Buchen (außer Ausnahmen)."},"source":"SAP"},{"id":"SAP-051","fragen_id":"5044790","thema":"Sachkontenstammdaten","frage":"Sie legen das Buchungskreissegment für ein neues Sachkonto an. Für wie viele Nebenbücher können Sie dieses Sachkonto als Abstimmkonto in diesem Buchungskreis definieren?","typ":"single_select","optionen":["2","4","1","3"],"richtige_antworten":["1"],"erklaerung":{"richtig":"Ein Sachkonto kann in einem Buchungskreis nur für EIN Nebenbuch als Abstimmkonto definiert werden — entweder für Debitoren ODER für Kreditoren, aber nicht für beide gleichzeitig.","falsch":{"2":"Zwei wäre falsch — Debitoren und Kreditoren brauchen getrennte Abstimmkonten.","4":"Zu viele — nur ein Nebenbuch pro Abstimmkonto.","3":"Zu viele — die Regel ist klar: 1 Konto = 1 Nebenbuch."},"eselsbruecke":"1 Abstimmkonto = 1 Nebenbuch. Debitoren-Abstimmkonto ≠ Kreditoren-Abstimmkonto. Klare Trennung!"},"source":"SAP"},{"id":"SAP-052","fragen_id":"5044791","thema":"Belegerfassung","frage":"Bei welchem Objekt wird KEIN Buchhaltungsbeleg angelegt, mit dem Verkehrszahlen aktualisiert werden?","typ":"single_select","optionen":["Bewerteter Wareneingang","Storno","Dauerbuchungsurbeleg","Zahlungsausgang"],"richtige_antworten":["Dauerbuchungsurbeleg"],"erklaerung":{"richtig":"Der Dauerbuchungsurbeleg ist eine Vorlage für wiederkehrende Buchungen — er selbst erzeugt keine FI-Buchung. Erst wenn der Urbeleg durch das Dauerbuchungsprogramm ausgeführt wird, entstehen echte Buchungsbelege mit Verkehrszahlen.","falsch":{"Wareneingang":"Ein bewerteter WE erzeugt automatisch einen FI-Beleg mit Verkehrszahlen.","Storno":"Eine Stornierung ist ein echter FI-Beleg mit Verkehrszahlen.","Zahlungsausgang":"Zahlungen erzeugen FI-Belege mit Verkehrszahlen."},"eselsbruecke":"Dauerbuchungsurbeleg = Vorlage/Schablone. Kein Beleg, keine Buchung, keine Verkehrszahlen. Erst beim Ausführen entsteht der echte Beleg."},"source":"SAP"},{"id":"SAP-053","fragen_id":"5044792","thema":"Sachkontenstammdaten","frage":"Welche verschiedenen Arten von Kontenplänen können in SAP S/4HANA definiert werden?","typ":"multiple_select","optionen":["Landeskontenplan","Zweigstellenkontenplan","Operativer Kontenplan","Segmentkontenplan","Konzernkontenplan"],"richtige_antworten":["Landeskontenplan","Operativer Kontenplan","Konzernkontenplan"],"erklaerung":{"richtig":"In SAP gibt es drei Kontenplantypen: Operativer Kontenplan (Pflicht, für laufende Buchungen), Landeskontenplan (optional, für länderspezifische Berichtsanforderungen) und Konzernkontenplan (optional, für konzerninterne Abstimmung).","falsch":{"Zweigstellenkontenplan":"Gibt es nicht als SAP-Kontenplantyp.","Segmentkontenplan":"Gibt es nicht als SAP-Kontenplantyp."},"eselsbruecke":"3 Kontenplantypen: OPERATIV (Pflicht) + LANDES (national) + KONZERN (Gruppe). Nur diese drei!"},"source":"SAP"},{"id":"SAP-054","fragen_id":"5044793","thema":"Anlagenbuchhaltung","frage":"Was steuert die Bewegungsart in der Anlagenbuchhaltung?","typ":"multiple_select","optionen":["Position der Buchungen im Anlagengitter","Abschreibungsschlüssel und Nutzungsdauer einer Anlage","Identifizierung von Zugängen, Abgängen und Umbuchungen","Buchungskreis für eine Buchung"],"richtige_antworten":["Position der Buchungen im Anlagengitter","Identifizierung von Zugängen, Abgängen und Umbuchungen"],"erklaerung":{"richtig":"Die Bewegungsart in AA steuert: wo die Buchung im Anlagengitter erscheint (Zugang, Abgang, Umbuchung in separaten Spalten) und welcher Typ es ist (Zugang, Abgang, Transfer).","falsch":{"Abschreibungsschlüssel/Nutzungsdauer":"Diese Parameter stehen im Bewertungsbereich des Anlagenstammsatzes, nicht in der Bewegungsart.","Buchungskreis":"Der Buchungskreis ist eine Organisationseinheit, keine Funktion der Bewegungsart."},"eselsbruecke":"Bewegungsart AA = WAS für eine Bewegung (Zugang/Abgang/Umbuchung) + WO im Anlagengitter. Wie ein Verkehrszeichen für Anlagenbewegungen."},"source":"SAP"},{"id":"SAP-055","fragen_id":"5044794","thema":"Anlagenbuchhaltung","frage":"Bedingungen für den AA-Jahreswechsel: Was ist zu berücksichtigen?","typ":"multiple_select","optionen":["Ein fertiggestellter Jahresabschluss muss verfügbar sein.","Alle Abschreibungsbuchungen für das aktuelle Geschäftsjahr müssen vorgenommen worden sein.","Das vorangegangene Jahr muss in der Anlagenbuchhaltung abgeschlossen sein.","Alle Rechnungen des aktuellen Jahres müssen auf Anlagen gebucht werden."],"richtige_antworten":["Das vorangegangene Jahr muss in der Anlagenbuchhaltung abgeschlossen sein."],"erklaerung":{"richtig":"Vor dem AA-Jahreswechsel: Alle AfA für das aktuelle Jahr müssen gebucht sein (letzter Abschreibungslauf). Das Vorjahr muss in AA abgeschlossen sein (kein offener Vorjahres-Status).","falsch":{"fertiggestellter Jahresabschluss":"Der AA-Jahreswechsel (Saldovortrag) kann VOR dem vollständigen Jahresabschluss durchgeführt werden.","alle Rechnungen gebucht":"Das ist keine technische Voraussetzung für den AA-Jahreswechsel."},"eselsbruecke":"AA-Jahreswechsel: AfA vollständig + Vorjahr abgeschlossen. Das reicht. Kein fertiger Abschluss nötig!"},"source":"SAP"},{"id":"SAP-056","fragen_id":"5044795","thema":"Geschäftspartnerstammdaten","frage":"Was steuert die Nummernvergabe für den zentralen Geschäftspartner?","typ":"single_select","optionen":["Die Geschäftspartnerrolle","Der Geschäftspartnertyp","Die Geschäftspartnergruppierung","Das für den Geschäftspartner definierte Abstimmkonto"],"richtige_antworten":["Die Geschäftspartnergruppierung"],"erklaerung":{"richtig":"Die Geschäftspartnergruppierung steuert die Nummernvergabe (intern oder extern) und den Nummernkreis für den GP. Bei der Anlage eines neuen GPs wählt man die Gruppierung — damit wird automatisch die Nummernvergabe gesteuert.","falsch":{"Geschäftspartnerrolle":"Die Rolle bestimmt welche Datenfelder sichtbar sind (FI-Debitor, FI-Kreditor etc.), nicht die Nummernvergabe.","Geschäftspartnertyp":"Der Typ (Person, Organisation) hat keinen Einfluss auf die Nummernvergabe.","Abstimmkonto":"Das Abstimmkonto ist ein FI-Buchungsparameter, kein Nummernvergabe-Steuerelement."},"eselsbruecke":"GP-Nummernvergabe = Gruppierung bestimmt. Gruppierung = Kategorie des GPs (z.B. Debitor, Kreditor, Mitarbeiter). Gruppierung → Nummernkreis."},"source":"SAP"},{"id":"SAP-057","fragen_id":"5044796","thema":"Mahnwesen","frage":"Was ist die korrekte Abfolge von Schritten für das Mahnprogramm?","typ":"single_select","optionen":["1. Mahnlauf ausführen 2. Parameter eingeben 3. Mahnungen drucken 4. Ausdruck planen","1. Mahnlauf ausführen 2. Parameter eingeben 3. Ausdruck planen 4. Mahnungen drucken","1. Parameter eingeben 2. Mahnlauf ausführen 3. Ausdruck planen 4. Mahnungen drucken","1. Parameter eingeben 2. Mahnlauf ausführen 3. Mahnungen drucken 4. Ausdruck planen"],"richtige_antworten":["1. Parameter eingeben 2. Mahnlauf ausführen 3. Ausdruck planen 4. Mahnungen drucken"],"erklaerung":{"richtig":"Korrekte Reihenfolge im Mahnprogramm (F150): 1. Parameter eingeben (Datum, BuKr, GP), 2. Mahnlauf ausführen (Vorschlag erstellen), 3. Ausdruck planen (Druckparameter), 4. Mahnungen drucken (ausgeben).","falsch":{"Mahnlauf zuerst":"Ohne Parameter kann kein Mahnlauf gestartet werden.","drucken vor planen":"Man muss erst planen (Druckparameter festlegen), dann drucken."},"eselsbruecke":"Mahnprogramm = PARAMETER → LAUF → PLANEN → DRUCKEN. Wie ein Druckauftrag: erst einrichten, dann ausführen."},"source":"SAP"},{"id":"SAP-058","fragen_id":"5044797","thema":"Anlagenbuchhaltung","frage":"Für welchen Geschäftsvorgang muss eine Anlage oder Teilanlage innerhalb eines Buchungskreises auf einen anderen Anlagenstammsatz übertragen werden?","typ":"multiple_select","optionen":["Eine Anlage muss aufgeteilt werden.","Eine Anlage im Bau wird außerplanmäßig ausgebucht.","Eine Anlage im Bau soll abgerechnet werden.","Eine Anlage erreicht die Passivphase mit Restbuchwert 0.","Eine Anlage wurde mit der falschen Anlagenklasse angelegt."],"richtige_antworten":["Eine Anlage muss aufgeteilt werden.","Eine Anlage im Bau soll abgerechnet werden.","Eine Anlage wurde mit der falschen Anlagenklasse angelegt."],"erklaerung":{"richtig":"Transfer innerhalb eines Buchungskreises ist nötig bei: Anlagenaufteilung (Teil auf neue Anlage), AiB-Abrechnung (Werte auf fertige Anlage), falscher Anlagenklasse (Wert auf richtig-klassifizierte Anlage umbuchen).","falsch":{"außerplanmäßig ausbuchen":"Außerplanmäßige Ausbuchung ist ein Abgang, kein Transfer.","Passivphase Restbuchwert 0":"Bei vollständiger Abschreibung bleibt die Anlage wo sie ist — kein Transfer nötig."},"eselsbruecke":"Transfer innerhalb BuKr: AUFTEILEN + AiB ABRECHNEN + FALSCHE KLASSE korrigieren. Abgang oder vollständige AfA = kein Transfer."},"source":"SAP"},{"id":"SAP-059","fragen_id":"5044798","thema":"Hauptbuchhaltung","frage":"Was ist der Zweck eines Hauptbuchs?","typ":"multiple_select","optionen":["Es speichert nur die Summen für Sachkonten.","Es ermöglicht jederzeit eine Prüfung der einzelnen Vorgänge in Echtzeit.","Es führt die Daten verschiedener Buchungskreise zusammen.","Es stellt die zentrale, aktuelle Quelle der Daten für das Reporting dar.","Es dokumentiert alle Geschäftsvorgänge."],"richtige_antworten":["Es ermöglicht jederzeit eine Prüfung der einzelnen Vorgänge in Echtzeit.","Es stellt die zentrale, aktuelle Quelle der Daten für das Reporting dar.","Es dokumentiert alle Geschäftsvorgänge."],"erklaerung":{"richtig":"Das Hauptbuch (General Ledger) hat drei Kernfunktionen: Echtzeitprüfung jedes Vorgangs (Drill-Down bis Einzelposten), zentrale Datenbasis für alle Berichte (Bilanz, GuV) und vollständige Dokumentation aller Geschäftsvorfälle.","falsch":{"nur Summen":"In S/4HANA speichert das HB KEINE Summenspeicher mehr — nur Einzelposten. Summen werden in Echtzeit berechnet.","führt Buchungskreise zusammen":"Das ist die Aufgabe des Konzernabschlusses/Konsolidierung, nicht des Hauptbuchs."},"eselsbruecke":"Hauptbuch = Gedächtnis des Unternehmens. Alles drin (Einzelposten), alles auswertbar (Echtzeit), alles dokumentiert."},"source":"SAP"},{"id":"SAP-060","fragen_id":"5044799","thema":"Mahnwesen","frage":"Wann werden Mahndaten in den Konten und Belegen aktualisiert?","typ":"single_select","optionen":["Die Aktualisierungen werden nach der Freigabe der Mahnungen ausgeführt.","Die Aktualisierungen werden ausgeführt, wenn Änderungen im Mahnvorschlag gespeichert werden.","Die Aktualisierungen werden zum Zeitpunkt des Mahndrucks ausgeführt.","Die Aktualisierungen werden zeitgleich mit dem Programm für die Mahnhistorie ausgeführt."],"richtige_antworten":["Die Aktualisierungen werden zum Zeitpunkt des Mahndrucks ausgeführt."],"erklaerung":{"richtig":"Die Mahndaten (Mahnstufe, Datum der letzten Mahnung) in den Konten und Belegen werden genau dann aktualisiert wenn die Mahnungen gedruckt werden. Erst der Druck macht die Mahnung 'offiziell'.","falsch":{"nach Freigabe":"Es gibt keine separate Freigabe im Mahnprogramm vor dem Druck.","bei Änderungen im Vorschlag":"Änderungen im Vorschlag aktualisieren nur den Vorschlag selbst, nicht die Stammdaten.","mit Mahnhistorie-Programm":"Die Mahnhistorie protokolliert den Mahnlauf, aktualisiert aber nicht die Daten."},"eselsbruecke":"Mahndaten aktuell = beim DRUCK. Erst wenn die Mahnung gedruckt ist, gilt sie als 'geschickt'. Dann wird der Stammsatz aktualisiert."},"source":"SAP"},{"id":"SAP-061","fragen_id":"5044800","thema":"SAP Fiori","frage":"Welche der folgenden Objekte des SAP Fiori Launchpad können einander zugeordnet werden?","typ":"single_select","optionen":["Gruppen und Seiten","Bereiche und Gruppen","Rollen und Bereiche","Kataloge und Seiten"],"richtige_antworten":["Rollen und Bereiche"],"erklaerung":{"richtig":"Im SAP Fiori Launchpad ist die Zuordnung: Rollen → Bereiche (Spaces). Bereiche enthalten Seiten, Seiten enthalten Kacheln. Die Rolle ist das verbindende Element zwischen Benutzer und Bereich.","falsch":{"Gruppen und Seiten":"Gruppen sind ein älteres Konzept (vor Spaces/Pages) — in der neuen Launchpad-Architektur werden Bereiche und Seiten verwendet.","Bereiche und Gruppen":"Gruppen sind dem alten Konzept zuzuordnen.","Kataloge und Seiten":"Kataloge und Seiten werden nicht direkt einander zugeordnet."},"eselsbruecke":"Fiori Launchpad Hierarchie: Rolle → Bereich → Seite → Kachel. Rollen werden BEREICHEN zugeordnet."},"source":"SAP"},{"id":"SAP-062","fragen_id":"5044801","thema":"Controlling","frage":"Welches Objekt kann mittels Umsatzkostenverfahren oder Gesamtkostenverfahren analysiert werden?","typ":"single_select","optionen":["Kostenstelle","Profitcenter","Innenauftrag","Projekt"],"richtige_antworten":["Profitcenter"],"erklaerung":{"richtig":"Das Profitcenter kann sowohl nach dem Umsatzkostenverfahren (Kosten nach Funktionsbereichen) als auch nach dem Gesamtkostenverfahren (Kosten nach Kostenarten) analysiert werden. Das macht Profitcenter zum flexiblen Analyseobjekt.","falsch":{"Kostenstelle":"Kostenstellen werden nach Kostenarten ausgewertet, nicht nach UKV/GKV.","Innenauftrag":"Aufträge werden ebenfalls nach Kostenarten ausgewertet.","Projekt":"Projekte (PSP-Elemente) werden nach Kostenarten ausgewertet."},"eselsbruecke":"Profitcenter = das einzige Objekt das BEIDE Verfahren unterstützt. UKV (nach Funktion) UND GKV (nach Kostenart). Profitcenter ist das Allrounder-Objekt."},"source":"SAP"},{"id":"SAP-063","fragen_id":"5044802","thema":"SAP GUI","frage":"Welche Optionen für die Navigation im SAP GUI stehen zur Verfügung?","typ":"multiple_select","optionen":["Programm-ID in das Befehlsfeld eingeben","Einen Transaktionscode in das Befehlsfeld eingeben","Auf die gewünschte App klicken","Einträge aus der Favoritenliste auswählen"],"richtige_antworten":["Einen Transaktionscode in das Befehlsfeld eingeben","Einträge aus der Favoritenliste auswählen"],"erklaerung":{"richtig":"Im SAP GUI kann man navigieren durch: Transaktionscode im Befehlsfeld (z.B. 'FB50' eingeben) und Favoriten (gespeicherte Transaktionen in der Favoritenliste).","falsch":{"Programm-ID":"Programm-IDs sind technische Bezeichner, keine Navigationsmethode für Endbenutzer.","App klicken":"Apps klicken ist Fiori-Navigation, nicht SAP GUI."},"eselsbruecke":"SAP GUI navigieren: T-Code tippen (schnell) ODER Favoriten klicken (komfortabel). Programm-ID und App-Klick = nicht GUI."},"source":"SAP"},{"id":"SAP-064","fragen_id":"5044803","thema":"SAP Fiori","frage":"Eine Kachel von einer Bereichsseite wird nicht im Fiori Launchpad eines Benutzers angezeigt. Woran kann das liegen?","typ":"multiple_select","optionen":["Die Seite ist in dem Bereich nicht sichtbar","Die Kachel ist der Rolle des Benutzers nicht zugeordnet","Die Seite ist in der Rolle des Benutzers nicht zugeordnet","Der Bereich ist der Rolle des Benutzers nicht zugeordnet"],"richtige_antworten":["Die Seite ist in der Rolle des Benutzers nicht zugeordnet","Der Bereich ist der Rolle des Benutzers nicht zugeordnet"],"erklaerung":{"richtig":"Eine Kachel erscheint nicht wenn: die Seite auf der sie liegt nicht der Rolle zugeordnet ist, ODER der Bereich der die Seite enthält nicht der Rolle zugeordnet ist. Die Berechtigung muss auf allen Ebenen vorhanden sein.","falsch":{"Seite im Bereich nicht sichtbar":"Die Sichtbarkeit einer Seite im Bereich ist eine Admin-Einstellung, nicht der typische Grund für fehlende Kacheln.","Kachel der Rolle nicht zugeordnet":"Einzelne Kacheln werden nicht direkt Rollen zugeordnet — das läuft über Kataloge und Bereiche."},"eselsbruecke":"Kachel fehlt → prüfe: Bereich der Rolle zugeordnet? Seite der Rolle zugeordnet? Hierarchie von oben nach unten prüfen!"},"source":"SAP"},{"id":"SAP-065","fragen_id":"5044804","thema":"Sachkontenstammdaten","frage":"Was sind die Merkmale eines Kontenplans?","typ":"multiple_select","optionen":["Jeder Buchungskreis verwendet exklusiv einen eigenen operativen Kontenplan","Ein Kontenplan kann mehreren Buchungskreisen zugeordnet sein","Ein Kontenplan enthält nur Sachkonten, die keine Konteninformationen (Kostenart) aufweisen","Der Kontenplan ist ein Verzeichnis aller Sachkonten, die von einem oder mehreren Buchungskreisen gemeinsam verwendet werden"],"richtige_antworten":["Ein Kontenplan kann mehreren Buchungskreisen zugeordnet sein","Der Kontenplan ist ein Verzeichnis aller Sachkonten, die von einem oder mehreren Buchungskreisen gemeinsam verwendet werden"],"erklaerung":{"richtig":"Kontenplan-Merkmale: Ein Kontenplan kann von mehreren Buchungskreisen gemeinsam genutzt werden (z.B. alle deutschen Tochterunternehmen nutzen denselben Kontenplan). Der Kontenplan ist das Verzeichnis aller Sachkonten.","falsch":{"exklusiv einen eigenen":"Falsch — mehrere BuKr können denselben Kontenplan teilen.","nur ohne Kostenart":"Sachkonten können gleichzeitig Kostenarten sein — der Kontenplan enthält beides."},"eselsbruecke":"Kontenplan = gemeinsames Verzeichnis. Mehrere BuKr, ein Kontenplan. Kostenarten sind oft gleichzeitig Sachkonten."},"source":"SAP"},{"id":"SAP-066","fragen_id":"5044805","thema":"SAP Fiori","frage":"Ein Benutzer möchte Kacheln aus Bereichsseiten im Fiori Launchpad anzeigen. Welche Objekte müssen Sie diesem Benutzer unter Verwendung von Rollen zuordnen?","typ":"multiple_select","optionen":["Seiten","Gruppen","Kataloge","Bereiche"],"richtige_antworten":["Kataloge","Bereiche"],"erklaerung":{"richtig":"Über Rollen werden Benutzern zugeordnet: Kataloge (damit der Benutzer die Apps überhaupt sehen darf) und Bereiche (damit der Benutzer den Bereich im Launchpad sieht). Beide sind über die Rollenpflege (PFCG) zuzuordnen.","falsch":{"Seiten":"Seiten werden Bereichen zugeordnet, nicht direkt Rollen.","Gruppen":"Gruppen sind ein altes Launchpad-Konzept — in der modernen Architektur werden Bereiche verwendet."},"eselsbruecke":"Rolle = Berechtigung. Rolle gibt: KATALOG (welche Apps darf ich) + BEREICH (welchen Bereich sehe ich). Seiten und Gruppen = nicht direkt an Rollen."},"source":"SAP"},{"id":"SAP-067","fragen_id":"5044806","thema":"SAP Fiori","frage":"Welche der folgenden Elemente sind Einstellungsebenen für das Fiori Launchpad?","typ":"multiple_select","optionen":["Kataloge","Customizing","Konfiguration","Personalisierung","Datenelemente"],"richtige_antworten":["Customizing","Konfiguration","Personalisierung"],"erklaerung":{"richtig":"Das Fiori Launchpad hat drei Einstellungsebenen: Customizing (systemweite Grundeinstellungen), Konfiguration (Rollen, Kataloge, Bereiche zuordnen) und Personalisierung (individuelle Benutzeranpassungen).","falsch":{"Kataloge":"Kataloge sind Objekte die auf der Konfigurationsebene gepflegt werden, keine eigene Einstellungsebene.","Datenelemente":"Datenelemente sind ABAP-Entwicklungsobjekte, keine Launchpad-Einstellungsebene."},"eselsbruecke":"3 Launchpad-Ebenen: CUSTOMIZING (System) → KONFIGURATION (Admin) → PERSONALISIERUNG (User). Von allgemein zu spezifisch."},"source":"SAP"},{"id":"SAP-068","fragen_id":"5044807","thema":"SAP GUI","frage":"Welche der folgenden Informationen können in der SAP-GUI-Statusleiste angezeigt werden?","typ":"multiple_select","optionen":["Programmname","Benutzer-ID","Antwortzeit","Name des Unternehmens"],"richtige_antworten":["Programmname","Benutzer-ID","Antwortzeit"],"erklaerung":{"richtig":"Die SAP GUI Statusleiste (unten im Fenster) kann anzeigen: Programmname (welches ABAP-Programm läuft), Benutzer-ID (wer ist angemeldet) und Antwortzeit (wie lange hat der Server gebraucht).","falsch":{"Name des Unternehmens":"Der Unternehmensname wird nicht in der Statusleiste angezeigt — er steht im Mandantenstammsatz."},"eselsbruecke":"Statusleiste = technische Infos: Programm + User + Zeit. Unternehmensname = nirgends in der Statusleiste."},"source":"SAP"},{"id":"SAP-069","fragen_id":"5044808","thema":"SAP Fiori","frage":"Welche Personalisierungsoptionen sind im Fiori Launchpad verfügbar?","typ":"multiple_select","optionen":["Hinzufügen und Entfernen von Katalogen","Ändern der Schriftart","Hinzufügen und Löschen von Anwendungen in Kachelgruppen","Ändern von Apps für gefilterte Berichtsergebnisse"],"richtige_antworten":["Hinzufügen und Löschen von Anwendungen in Kachelgruppen","Ändern von Apps für gefilterte Berichtsergebnisse"],"erklaerung":{"richtig":"Benutzer können im Launchpad personalisieren: Kacheln in Gruppen hinzufügen/entfernen (innerhalb ihrer Berechtigungen) und App-Einstellungen wie vordefinierte Filter für Berichte anpassen.","falsch":{"Kataloge hinzufügen/entfernen":"Kataloge werden von Administratoren über Rollen zugewiesen — Benutzer können keine Kataloge selbst hinzufügen.","Schriftart ändern":"Die Schriftart ist eine systemweite Einstellung, keine Benutzerpersonalisierung im Launchpad."},"eselsbruecke":"User-Personalisierung: Kacheln verschieben/entfernen + App-Filter anpassen. Kataloge und Schriften = Admin-Sache."},"source":"SAP"},{"id":"SAP-070","fragen_id":"5044809","thema":"Zahlungsverkehr","frage":"Was ist die korrekte Abfolge im Prozess 'Zahlungen in der Kreditorenbuchhaltung'?","typ":"single_select","optionen":["Position auswählen → Zahlweg und Bank auswählen → Zahlungsbeleg buchen → Zahlungsträger drucken","Zahlweg und Bank auswählen → Position auswählen → Zahlbetrag errechnen → Zahlungsbeleg buchen → Zahlungsträger drucken","Position auswählen → Zahlweg und Bank auswählen → Zahlungsträger drucken → Zahlungsbeleg buchen","Zahlweg und Bank auswählen → Position auswählen → Zahlbetrag errechnen → Zahlungsträger drucken → Zahlungsbeleg buchen"],"richtige_antworten":["Position auswählen → Zahlweg und Bank auswählen → Zahlungsbeleg buchen → Zahlungsträger drucken"],"erklaerung":{"richtig":"Im manuellen Kreditorenzahlungsprozess: 1. Offene Position auswählen (welche Rechnung wird bezahlt), 2. Zahlweg und Bank auswählen (wie und von wo), 3. Zahlungsbeleg buchen (FI-Buchung), 4. Zahlungsträger drucken (Überweisungsträger oder SEPA-Datei).","falsch":{"Zahlweg zuerst":"Man wählt erst die Position, dann den Zahlweg — nicht umgekehrt.","drucken vor buchen":"Erst buchen, dann drucken — die Buchung muss vor dem Druck existieren."},"eselsbruecke":"Kreditorenzahlung: WAS zahlen (Position) → WIE zahlen (Zahlweg/Bank) → BUCHEN → DRUCKEN. Logische Reihenfolge!"},"source":"SAP"},{"id":"SAP-071","fragen_id":"5044810","thema":"SAP GUI","frage":"Wie können Sie den Transaktionscode einer Transaktion im SAP GUI ermitteln?","typ":"multiple_select","optionen":["Den Transaktionscode in der Titelleiste lesen","Den Transaktionscode in der Statuszeile anzeigen lassen","Den Transaktionscode in der Anwendung ermitteln über SYSTEM-STATUS","Den Transaktionscode aus dem Business Workplace lesen"],"richtige_antworten":["Den Transaktionscode in der Statuszeile anzeigen lassen","Den Transaktionscode in der Anwendung ermitteln über SYSTEM-STATUS"],"erklaerung":{"richtig":"T-Code ermitteln: Statuszeile (unten links — dort kann /N angezeigt werden) und System → Status (zeigt den aktuellen T-Code und weitere technische Infos).","falsch":{"Titelleiste":"Die Titelleiste zeigt den Transaktions-NAMEN (z.B. 'Sachkontenbuchung erfassen'), nicht den Code.","Business Workplace":"Der Business Workplace ist für Nachrichten und Workflow — kein T-Code-Nachschlagewerk."},"eselsbruecke":"T-Code ermitteln: Statuszeile (einblenden!) oder System → Status. Titelleiste zeigt Namen, nicht Code."},"source":"SAP"},{"id":"SAP-072","fragen_id":"5044811","thema":"SAP Fiori","frage":"Eine App wird nicht im App-Finder angezeigt. Woran könnte das liegen?","typ":"single_select","optionen":["Die App ist in keinem der Ihnen zur Verfügung stehenden Kataloge enthalten","Die App wurde im System gesperrt","Sie haben keine Release-Version für Ihre Suche angegeben"],"richtige_antworten":["Die App ist in keinem der Ihnen zur Verfügung stehenden Kataloge enthalten"],"erklaerung":{"richtig":"Der App-Finder zeigt nur Apps aus Katalogen die dem Benutzer über seine Rollen zugewiesen sind. Wenn eine App nicht erscheint, liegt es daran dass sie in keinem der zugewiesenen Kataloge enthalten ist.","falsch":{"App gesperrt":"Apps werden in SAP nicht 'gesperrt' — sie werden entweder aktiviert oder nicht.","keine Release-Version":"Der App-Finder hat keine Release-Versionsfilterung für Endbenutzer."},"eselsbruecke":"App-Finder zeigt nur was im KATALOG ist, der mir zugeordnet ist. App fehlt = Katalog fehlt oder Rolle fehlt."},"source":"SAP"},{"id":"SAP-073","fragen_id":"5044812","thema":"Organisationsstruktur","frage":"Welche der folgenden Module sind Bestandteil der Finanzbuchhaltung?","typ":"multiple_select","optionen":["Gemeinkosten-Controlling","Debitorenbuchhaltung","Hauptbuchhaltung","Kreditorenbuchhaltung","Ergebnis- und Marktsegmentrechnung"],"richtige_antworten":["Debitorenbuchhaltung","Hauptbuchhaltung","Kreditorenbuchhaltung"],"erklaerung":{"richtig":"Die Finanzbuchhaltung (FI) besteht aus: Hauptbuchhaltung (FI-GL), Debitorenbuchhaltung (FI-AR) und Kreditorenbuchhaltung (FI-AP). Dazu kommen AA und BA.","falsch":{"Gemeinkosten-Controlling":"CO-OM (Overhead Cost Controlling) gehört zum Modul CO, nicht FI.","Ergebnis- und Marktsegmentrechnung":"CO-PA gehört zum Modul CO (Controlling)."},"eselsbruecke":"FI = Hauptbuch + Debitoren + Kreditoren + Anlagen + Bank. CO = Kostenstellen + Aufträge + PA. Zwei getrennte Welten!"},"source":"SAP"},{"id":"SAP-074","fragen_id":"5044813","thema":"SAP GUI","frage":"Welche der folgenden Elemente sind Bestandteil der SAP-Bildstruktur im SAP GUI?","typ":"multiple_select","optionen":["Systemfunktionsleiste","Registerkarte","Kommandofeld","Transaktionstest","Programmname"],"richtige_antworten":["Systemfunktionsleiste","Registerkarte","Kommandofeld"],"erklaerung":{"richtig":"Die SAP GUI Bildstruktur besteht u.a. aus: Systemfunktionsleiste (Buttons wie Sichern, Zurück, Abbrechen), Registerkarten (für mehrteilige Transaktionen wie Anlagenstammsatz) und Kommandofeld (für T-Code Eingabe oben links).","falsch":{"Transaktionstest":"Gibt es nicht als Element der SAP GUI Bildstruktur.","Programmname":"Der Programmname ist eine technische Info in der Statuszeile, kein Bildelement."},"eselsbruecke":"SAP GUI Bild: Kommandofeld (oben, T-Code) + Systemfunktionsleiste (Buttons) + Registerkarten (Reiter). Das sind die Basiselemente."},"source":"SAP"},{"id":"SAP-075","fragen_id":"5044814","thema":"SAP Fiori","frage":"Über welche Funktion kopieren Sie eine SAP-Fiori-App aus der SAP-Bibliothek in Ihr Fiori Launchpad?","typ":"single_select","optionen":["SAP Fiori Launchpad Designer","Rollenpflege (PFCG)","Benutzerpflege (Transaktion SU01)"],"richtige_antworten":["Rollenpflege (PFCG)"],"erklaerung":{"richtig":"Apps werden über die Rollenpflege (Transaktion PFCG) Benutzern zur Verfügung gestellt. In PFCG werden Apps/Kataloge einer Rolle zugeordnet, und die Rolle wird dann dem Benutzer zugewiesen.","falsch":{"Launchpad Designer":"Der Launchpad Designer wird für die Konfiguration von Gruppen und Kacheln verwendet, nicht für die initiale App-Zuweisung über Rollen.","SU01":"SU01 ist für Benutzerstammdaten (Passwort, Anmeldedaten) — keine App-Zuordnung."},"eselsbruecke":"Apps zuweisen = PFCG (Rollenpflege). App → Katalog → Rolle → Benutzer. PFCG ist der zentrale Punkt für Berechtigungen."},"source":"SAP"},{"id":"SAP-076","fragen_id":"5044815","thema":"SAP GUI","frage":"Wie können Sie den technischen Namen eines Feldes im SAP GUI ermitteln?","typ":"single_select","optionen":["Die Online-Hilfe-Bibliothek öffnen und nach dem Feldnamen suchen","Den Cursor in dem Feld platzieren und zum Systemstatus navigieren","Die Eingabehilfe für das Feld öffnen und den technischen Namen in der Kopfzeile finden","Die F1-Hilfe für das Feld verwenden und die 'Technischen Informationen' auswählen"],"richtige_antworten":["Die F1-Hilfe für das Feld verwenden und die 'Technischen Informationen' auswählen"],"erklaerung":{"richtig":"F1 auf ein Feld → Hilfe-Popup öffnet sich → Button 'Technische Informationen' klicken → zeigt Tabellenname, Feldname, Datenelement etc. Das ist der Standardweg für technische Feldinformationen.","falsch":{"Online-Hilfe-Bibliothek":"Die Online-Hilfe gibt funktionale Erklärungen, keine technischen Feldnamen.","Cursor + Systemstatus":"System → Status zeigt T-Code und Programm, nicht Feldnamen.","Eingabehilfe Kopfzeile":"Die F4-Hilfe (Eingabehilfe) zeigt Werte, keine technischen Feldnamen."},"eselsbruecke":"Technischer Feldname = F1 → Technische Informationen. F1 = Feldhilfe. Technische Infos = Tabelle.Feld. Entwickler-Info auf Knopfdruck."},"source":"SAP"},{"id":"SAP-077","fragen_id":"5044816","thema":"Organisationsstruktur","frage":"Was sollten Sie beim Zuordnen von Organisationseinheiten in der Buchhaltung beachten?","typ":"multiple_select","optionen":["Das Werk ist dem Kostenrechnungskreis zugeordnet","Einem Ergebnisbereich können mehrere Kostenrechnungskreise zugeordnet sein","Einem Kostenrechnungskreis können mehrere Buchungskreise zugeordnet sein","Die Profitcenter-Rechnung in der Hauptbuchhaltung ist einem Buchungskreis zugeordnet"],"richtige_antworten":["Einem Ergebnisbereich können mehrere Kostenrechnungskreise zugeordnet sein","Einem Kostenrechnungskreis können mehrere Buchungskreise zugeordnet sein"],"erklaerung":{"richtig":"Organisationshierarchie in SAP: Ergebnisbereich (oben) → mehrere Kostenrechnungskreise. Kostenrechnungskreis → mehrere Buchungskreise. Von oben nach unten: immer 'einer zu vielen'.","falsch":{"Werk dem KoRe zugeordnet":"Das Werk wird dem BUCHUNGSKREIS zugeordnet, nicht direkt dem Kostenrechnungskreis.","Profitcenter-Rechnung einem BuKr":"Die Profitcenter-Rechnung ist Teil des neuen Hauptbuchs auf Mandantenebene, nicht buchungskreisspezifisch."},"eselsbruecke":"Hierarchie: Ergebnisbereich → KoRe → BuKr → Werk. Von oben nach unten. Ergebnisbereich ist ganz oben in CO."},"source":"SAP"},{"id":"SAP-078","fragen_id":"5044817","thema":"SAP Fiori","frage":"Eine App, die in Ihrem zugewiesenen Katalog enthalten ist, wird nicht in Ihrem Fiori Launchpad angezeigt. Woran könnte das liegen?","typ":"single_select","optionen":["Die App ist in keiner Ihrer verfügbaren Kachelgruppen enthalten","Die App hat kein Aktivierungskennzeichen","Es handelt sich nicht um eine native App"],"richtige_antworten":["Die App ist in keiner Ihrer verfügbaren Kachelgruppen enthalten"],"erklaerung":{"richtig":"Auch wenn eine App im Katalog vorhanden ist, erscheint sie nur im Launchpad wenn sie auch einer Kachelgruppe zugeordnet ist, die dem Benutzer zugewiesen ist. Katalog = Berechtigung, Gruppe = Anzeige.","falsch":{"kein Aktivierungskennzeichen":"Apps haben kein separates Aktivierungskennzeichen in diesem Sinne.","nicht native":"Native vs. nicht-native beeinflusst nicht die Anzeige im Launchpad."},"eselsbruecke":"Katalog = Berechtigung haben. Kachelgruppe = sichtbar sein. Beide braucht man! Katalog ohne Gruppe = nicht sichtbar."},"source":"SAP"},{"id":"SAP-079","fragen_id":"5044818","thema":"SAP GUI","frage":"Welche der folgenden Elemente können der Favoritenleiste im SAP GUI hinzugefügt werden?","typ":"multiple_select","optionen":["Internetadressen","Verknüpfung zu Dateien","Transaktionen","E-Mail-Adressen","Kurzschlüssel"],"richtige_antworten":["Internetadressen","Verknüpfung zu Dateien","Transaktionen"],"erklaerung":{"richtig":"In die SAP GUI Favoritenliste können aufgenommen werden: Transaktionen (am häufigsten), Internetadressen (URLs) und Verknüpfungen zu Dateien auf dem lokalen System.","falsch":{"E-Mail-Adressen":"E-Mail-Adressen können nicht als Favoriten gespeichert werden.","Kurzschlüssel":"Kurzschlüssel im Sinne von Tastaturkürzeln sind keine Favoriten-Einträge."},"eselsbruecke":"Favoriten = T-Codes + URLs + Dateien. Das sind die drei Typen. Kein E-Mail, kein Tastaturkürzel."},"source":"SAP"},{"id":"SAP-080","fragen_id":"5044819","thema":"Debitorenbuchhaltung","frage":"Was sind Merkmale der Debitorenbuchhaltung?","typ":"multiple_select","optionen":["Die Debitorenbuchhaltung lässt sich mit dem Cash Management verknüpfen","Das System zeichnet nicht jede Buchung in der Debitorenbuchhaltung direkt auch im Hauptbuch auf","Debitoren werden im Hauptbuch angelegt und über die Schnittstelle in die Nebenbücher kopiert","Die Debitorenbuchhaltung stellt die erforderlichen Daten für das Kreditmanagement bereit","Die Debitorenbuchhaltung ist ein Teil des Rechnungswesens"],"richtige_antworten":["Die Debitorenbuchhaltung lässt sich mit dem Cash Management verknüpfen","Die Debitorenbuchhaltung stellt die erforderlichen Daten für das Kreditmanagement bereit","Die Debitorenbuchhaltung ist ein Teil des Rechnungswesens"],"erklaerung":{"richtig":"Die Debitorenbuchhaltung: ist Teil des FI-Rechnungswesens, verknüpft mit Cash Management (Liquiditätsplanung) und liefert Daten ans Kreditmanagement (Kreditlimits, Zahlungsverhalten).","falsch":{"nicht direkt im HB":"Falsch — jede Debitorenbuchung wird AUTOMATISCH UND DIREKT im Hauptbuch mitgebucht (über Abstimmkonto).","im HB angelegt und kopiert":"Falsch — Debitoren sind Nebenbuch-Stammdaten, sie werden NICHT im HB angelegt."},"eselsbruecke":"Debitoren: FI-Teil + Cash Management + Kreditmanagement. Immer sofort ins HB gebucht (Abstimmkonto). Stammdaten im Nebenbuch."},"source":"SAP"},{"id":"SAP-081","fragen_id":"5044820","thema":"SAP Fiori","frage":"Was sind einige Designprinzipien von SAP Fiori?","typ":"multiple_select","optionen":["Einfachheit","Funktionale Möglichkeiten","Rollenbasierter Ansatz","Reaktionsfähigkeit","Flexibilität"],"richtige_antworten":["Einfachheit","Rollenbasierter Ansatz","Flexibilität"],"erklaerung":{"richtig":"SAP Fiori Designprinzipien: Einfachheit (intuitive, minimalistische Oberfläche), rollenbasierter Ansatz (jeder sieht nur was er braucht) und Flexibilität (funktioniert auf allen Geräten und in verschiedenen Kontexten).","falsch":{"Funktionale Möglichkeiten":"Das ist kein Designprinzip — es beschreibt eher den Umfang der Funktionen.","Reaktionsfähigkeit":"Responsivität ist ein technisches Merkmal, nicht eines der Kern-Designprinzipien von Fiori."},"eselsbruecke":"Fiori Design: EINFACH + ROLLENBASIERT + FLEXIBEL. Die drei Kernprinzipien. Einfach merken: EiRoFle!"},"source":"SAP"},{"id":"SAP-082","fragen_id":"5044821","thema":"Geschäftspartnerstammdaten","frage":"Was sind die Merkmale des Geschäftspartnerstamms?","typ":"multiple_select","optionen":["Geschäftspartner können in manchen Prozessen als Debitoren und in anderen als Kreditoren agieren","Debitoren- und Kreditorenstammdaten können in SAP S/4HANA in einer einzigen Transaktion gepflegt werden","Die Vertriebsdaten für Debitoren werden im SD-Modul gepflegt","Debitoren- und Kreditorenstammdaten müssen in SAP S/4HANA in separaten Transaktionen gepflegt werden"],"richtige_antworten":["Geschäftspartner können in manchen Prozessen als Debitoren und in anderen als Kreditoren agieren","Debitoren- und Kreditorenstammdaten können in SAP S/4HANA in einer einzigen Transaktion gepflegt werden","Die Vertriebsdaten für Debitoren werden im SD-Modul gepflegt"],"erklaerung":{"richtig":"Der zentrale Geschäftspartner in S/4HANA: Ein GP kann gleichzeitig Debitor UND Kreditor sein. Alle Daten werden in einer Transaktion (BP) gepflegt. SD-spezifische Vertriebsdaten werden weiterhin im SD-Modul verwaltet.","falsch":{"separate Transaktionen":"In S/4HANA gibt es nur EINE Transaktion BP für alle GP-Rollen — keine separaten Transaktionen mehr."},"eselsbruecke":"S/4HANA GP: EINE Transaktion (BP) für alles. GP kann Debitor + Kreditor sein. SD-Daten bleiben in SD."},"source":"SAP"},{"id":"SAP-083","fragen_id":"5044822","thema":"SAP GUI","frage":"Wie können Sie die Benutzeroberfläche des SAP GUI personalisieren?","typ":"multiple_select","optionen":["Das Layout des Bilds 'SAP Easy Access' ändern","Statusmeldungen in Dialogfenstern anzeigen","Bevorzugte Transaktionen in verschiedenen Farben markieren","Neue Transaktionscodes anlegen","Farben, sowie das Verhalten der Bilder und Felder anpassen"],"richtige_antworten":["Das Layout des Bilds 'SAP Easy Access' ändern","Statusmeldungen in Dialogfenstern anzeigen","Farben, sowie das Verhalten der Bilder und Felder anpassen"],"erklaerung":{"richtig":"SAP GUI Personalisierung: Layout des Startbildschirms (SAP Easy Access) ändern, Statusmeldungen als Popup anzeigen lassen und über Optionen/Einstellungen Farben und Feldeigenschaften anpassen.","falsch":{"Transaktionen farbig markieren":"Einzelne Transaktionen können nicht in verschiedenen Farben markiert werden.","neue Transaktionscodes anlegen":"T-Codes anlegen ist Entwickler-/Administrator-Aufgabe, keine Benutzerpersonalisierung."},"eselsbruecke":"GUI personalisieren: Layout + Meldungsanzeige + Farben/Felder. T-Codes anlegen = Entwickler. Farben für Favoriten = nicht möglich."},"source":"SAP"},{"id":"SAP-084","fragen_id":"5044823","thema":"SAP Fiori","frage":"Auf welche Weise können Sie auf das Fiori Launchpad zugreifen?","typ":"multiple_select","optionen":["Web Browser","SAP Business Client","SAP Enterprise Portal","SAP GUI"],"richtige_antworten":["Web Browser","SAP Business Client"],"erklaerung":{"richtig":"Das Fiori Launchpad ist über zwei Wege erreichbar: Web Browser (direkte URL, kein Client nötig) und SAP Business Client (SAP-eigener Browser-ähnlicher Client der das Launchpad integriert).","falsch":{"SAP Enterprise Portal":"Das Enterprise Portal ist eine ältere Portalstruktur — das Fiori Launchpad ersetzt es zunehmend.","SAP GUI":"Das SAP GUI ist die klassische Desktop-Oberfläche — Fiori läuft nicht im GUI."},"eselsbruecke":"Fiori Launchpad: Browser (direkt) + Business Client (SAP-Client). Kein GUI, kein altes Portal."},"source":"SAP"},{"id":"SAP-085","fragen_id":"5044824","thema":"Sachkontenstammdaten","frage":"Was wird für die Strukturierung von Sachkonten verwendet?","typ":"single_select","optionen":["Kontenpläne","Kontoschlüssel","Kontoversionen","Sachkontenhierarchie"],"richtige_antworten":["Kontenpläne"],"erklaerung":{"richtig":"Sachkonten werden durch Kontenpläne strukturiert. Der Kontenplan ist das Verzeichnis und die Gliederung aller Sachkonten — er gibt die Struktur vor (Kontonummernbereiche für Anlage, Forderungen, etc.).","falsch":{"Kontoschlüssel":"Kontoschlüssel sind keine SAP-Standard-Strukturierungselemente.","Kontoversionen":"Kontoversionen gibt es nicht als SAP-Konzept für Sachkonten.","Sachkontenhierarchie":"Sachkontenhierarchien gibt es in manchen CO-Bereichen, aber die primäre Strukturierung erfolgt über Kontenpläne."},"eselsbruecke":"Sachkonten strukturieren = Kontenplan. Kontenplan = das Ordnungssystem für alle Konten. SKR03, SKR04 sind bekannte deutsche Kontenpläne."},"source":"SAP"},{"id":"SAP-086","fragen_id":"5044825","thema":"SAP Fiori","frage":"Welche Analysefunktionen bietet die SAP-Fiori-App 'Sachkontenstammdaten verwalten'?","typ":"multiple_select","optionen":["Offene Posten","Verwendungsnachweis","Marktsegment","Detailinformationen zum Sachkonto"],"richtige_antworten":["Verwendungsnachweis","Detailinformationen zum Sachkonto"],"erklaerung":{"richtig":"Die App 'Sachkontenstammdaten verwalten' bietet: Verwendungsnachweis (wo wird dieses Konto verwendet — in welchen Buchungskreisen, Kontenplänen) und Detailinformationen (alle Stammdatenfelder des Kontos).","falsch":{"Offene Posten":"Offene Posten sind für Debitoren/Kreditoren-Konten relevant — Sachkonten haben keine Offene-Posten-Anzeige in dieser App.","Marktsegment":"Marktsegmente sind CO-PA-Objekte, keine Funktion der Sachkontenstammdaten-App."},"eselsbruecke":"Sachkonto-App: WO genutzt (Verwendungsnachweis) + WAS sind die Daten (Detailinfos). Keine OP, kein CO."},"source":"SAP"},{"id":"SAP-087","fragen_id":"5044826","thema":"SAP Fiori","frage":"Was sind einige Merkmale des Fiori-Designs 'Belize'?","typ":"multiple_select","optionen":["Zusätzliche visuelle Schichten","Dynamisierung von App-Prozessen","Mehr Details in Mikrointeraktionen","Auswahlmöglichkeiten für die Tastaturbelegung"],"richtige_antworten":["Zusätzliche visuelle Schichten","Mehr Details in Mikrointeraktionen"],"erklaerung":{"richtig":"Das Fiori-Design 'Belize' (ein visuelles Theme) bringt: zusätzliche visuelle Schichten (Tiefe durch Schatten/Layering), verfeinerte Mikrointeraktionen (kleine Animationen und Feedbacks) und Tastaturbelegungs-Optionen für Barrierefreiheit.","falsch":{"Dynamisierung von App-Prozessen":"Das ist kein spezifisches Merkmal des Belize-Themes — es beschreibt eher allgemeine App-Entwicklung."},"eselsbruecke":"Belize = visuell schöner. Mehr Tiefe (Schichten) + feinere Interaktionen (Mikro) + Barrierefreiheit (Tastatur). Design-Update, kein Funktions-Update."},"source":"SAP"},{"id":"WBS-101","fragen_id":"5044714","thema":"SAP GUI Navigation","frage":"Welche Aussage zur Funktion der folgenden Transaktionscodes ist richtig?","typ":"single_select","optionen":["/oSM04 = die Transaktion SM04 wird in einem neuen Modus gestartet","/nex = der Anmeldemodus wird mit einem Bestätigungsdialogfenster beendet","/i = ein neuer Modus wird geöffnet","/nSM04 = die Transaktion SM04 wird in einem neuen Modus gestartet"],"richtige_antworten":["/oSM04 = die Transaktion SM04 wird in einem neuen Modus gestartet"],"erklaerung":{"richtig":"/o startet eine Transaktion in einem neuen Modus. /n wechselt im gleichen Modus. /nex beendet ohne Dialog. /i existiert nicht als Standard.","falsch":{},"eselsbruecke":"/o = öffnet neuen Modus + Transaktion. /n = neue Transaktion im gleichen Modus."},"source":"WBS"},{"id":"WBS-102","fragen_id":"5044715","thema":"Sachkontenstammdaten","frage":"Welche Daten werden im Kontenplansegment eines Sachkontos eingegeben?","typ":"multiple_select","optionen":["Steuerungsfelder (zum Beispiel Kontengruppe)","Konsolidierungsdaten (zum Beispiel eindeutige Gesellschaftsnummer im Konzern)","Sprache","Kontonummer","Währungskennzeichen"],"richtige_antworten":["Steuerungsfelder (zum Beispiel Kontengruppe)","Konsolidierungsdaten (zum Beispiel eindeutige Gesellschaftsnummer im Konzern)","Kontonummer"],"erklaerung":{"richtig":"Das Kontenplansegment enthält Steuerungsfelder (Kontengruppe), Konsolidierungsdaten und die Kontonummer. Sprache und Währungskennzeichen gehören zum Buchungskreissegment.","falsch":{},"eselsbruecke":"Kontenplan = mandantenweit: Nummer, Gruppe, Konsolidierung."},"source":"WBS"},{"id":"WBS-103","fragen_id":"5044716","thema":"Sonderhauptbuchvorgänge","frage":"Welche drei Sonderhauptbucharten gibt es in SAP S/4HANA unter technischen Gesichtspunkten?","typ":"multiple_select","optionen":["Stornierung","Freie Gegenbuchungen","Automatische/festgelegte Gegenbuchung (statistische Buchung)","Skonto-Retoure","Aktiver Rechnungsabgrenzungsposten","Merkposten"],"richtige_antworten":["Freie Gegenbuchungen","Automatische/festgelegte Gegenbuchung (statistische Buchung)","Merkposten"],"erklaerung":{"richtig":"Die drei technischen SHB-Arten: Freie Gegenbuchung (z.B. Wechsel), Automatische/festgelegte Gegenbuchung (statistische Buchung, z.B. Bürgschaft) und Merkposten (ohne Gegenbuchung).","falsch":{},"eselsbruecke":"Frei, Fest, Keiner — drei Arten je nach Gegenbuchung."},"source":"WBS"},{"id":"WBS-104","fragen_id":"5044717","thema":"Sonderhauptbuchvorgänge","frage":"Wobei handelt es sich um Merkposten?","typ":"multiple_select","optionen":["Anzahlungsanforderung","Wechselanforderung (gibt es in Spanien, Italien und Frankreich)","Gemerkte Rechnung","Wechsel","Vorerfasste Zahlung"],"richtige_antworten":["Anzahlungsanforderung","Wechselanforderung (gibt es in Spanien, Italien und Frankreich)"],"erklaerung":{"richtig":"Merkposten sind Anzahlungsanforderung und Wechselanforderung. Sie sind statistische Buchungen ohne Gegenkonto.","falsch":{},"eselsbruecke":"Merkposten = Anforderungen: Anzahlung anfordern, Wechsel anfordern."},"source":"WBS"},{"id":"WBS-105","fragen_id":"5044718","thema":"Anlagenbuchhaltung","frage":"Welche Aussagen sind zutreffend?","typ":"multiple_select","optionen":["Die Konten 'Sonstige Forderungen' und 'Sonstige Verbindlichkeiten' werden im Bilanzanhang ausgewiesen.","Beim Buchen von Beschaffungsbelegen kann man Anlagen anlegen.","Beim unbewerteten Wareneingang wird eine Anlage erst bei Rechnungsbuchung aktiviert."],"richtige_antworten":["Beim Buchen von Beschaffungsbelegen kann man Anlagen anlegen.","Beim unbewerteten Wareneingang wird eine Anlage erst bei Rechnungsbuchung aktiviert."],"erklaerung":{"richtig":"Alle drei Aussagen sind korrekt.","falsch":{},"eselsbruecke":"Alle drei stimmen."},"source":"WBS"},{"id":"WBS-106","fragen_id":"5044719","thema":"Anlagentransfer","frage":"Welche der folgenden Aussagen treffen auf den Begriff des Anlagentransfers zu?","typ":"multiple_select","optionen":["Bei der Forecast-Methode erfolgt die Angabe des Transferpreises durch manuelle Eingabe eines im Controlling für die nächsten 12 Monate vorausberechneten Anlagewertes.","Bei der Bruttomethode erfolgt die Angabe des Transferpreises durch manuelle Eingabe.","Bei der Neubewertungsmethode transferiert das System historische AHK sowie die kumulierten Wertberichtigungen der sendenden Anlage."],"richtige_antworten":["Bei der Bruttomethode erfolgt die Angabe des Transferpreises durch manuelle Eingabe.","Bei der Neubewertungsmethode transferiert das System historische AHK sowie die kumulierten Wertberichtigungen der sendenden Anlage."],"erklaerung":{"richtig":"Bruttomethode = manueller Transferpreis. Neubewertungsmethode = historische AHK + kumulierte Wertberichtigungen werden übertragen.","falsch":{},"eselsbruecke":"Brutto = manuell eingeben. Neubewertung = historische Werte mitnehmen."},"source":"WBS"},{"id":"WBS-107","fragen_id":"5044720","thema":"Anlagenbuchhaltung","frage":"Welche Aussagen sind korrekt?","typ":"multiple_select","optionen":["Jede Anlagennummer besteht aus Anlagenhaupt- und -unternummer.","Über die Anlagenklasse werden die Anlagenstammsätze mit den entsprechenden Hauptbuchkonten verbunden.","Die Nummernvergabe bei Anlagen erfolgt grundsätzlich intern. Eine externe Nummernvergabe ist bei Anlagen nicht möglich.","Die Nummernvergabe bei Anlagen erfolgt grundsätzlich extern. Eine interne Nummernvergabe ist bei Anlagen nicht möglich.","Der Nummernkreis bestimmt die Zuordnung der Anlagenstammsatznummer.","Die Festlegung der Feldeigenschaften im Anlagenstammsatz und der Pflegeebene der Felder erfolgt über die Bildaufbausteuerung.","Anzahlungen können auf eine Anlage im Bau (AiB) gebucht werden."],"richtige_antworten":["Jede Anlagennummer besteht aus Anlagenhaupt- und -unternummer.","Über die Anlagenklasse werden die Anlagenstammsätze mit den entsprechenden Hauptbuchkonten verbunden.","Der Nummernkreis bestimmt die Zuordnung der Anlagenstammsatznummer.","Die Festlegung der Feldeigenschaften im Anlagenstammsatz und der Pflegeebene der Felder erfolgt über die Bildaufbausteuerung.","Anzahlungen können auf eine Anlage im Bau (AiB) gebucht werden."],"erklaerung":{"richtig":"Anlagennummer = Haupt- + Unternummer. Anlagenklasse verbindet mit HB-Konten. Nummernkreis bestimmt Nummer. Bildaufbausteuerung steuert Felder. Anzahlungen auf AiB möglich.","falsch":{},"eselsbruecke":"5 von 7 sind richtig — nur die zwei sich widersprechenden Nummernvergabe-Aussagen sind falsch."},"source":"WBS"},{"id":"WBS-108","fragen_id":"5044721","thema":"Anlagenbuchhaltung","frage":"Was dient in der Anlagenbuchhaltung der Realisierung der parallelen Rechnungslegung?","typ":"single_select","optionen":["Bewertungshierarchie","Bewertungsbereich","Abschreibungsgitter","Anlagenwertezuordnung"],"richtige_antworten":["Bewertungsbereich"],"erklaerung":{"richtig":"Der Bewertungsbereich ermöglicht parallele Rechnungslegung (z.B. HGB + IFRS) durch separate Abschreibungsberechnungen je Vorschrift.","falsch":{},"eselsbruecke":"Bewertungsbereich = eine Rechnungslegungsvorschrift. Mehrere Bereiche = parallele Rechnungslegung."},"source":"WBS"},{"id":"WBS-109","fragen_id":"5044722","thema":"Periodenabschluss","frage":"Wobei handelt es sich um Tätigkeiten des Monatsabschlusses im externen Rechnungswesen?","typ":"multiple_select","optionen":["Buchen von Lagerkorrekturen","Erstellen externer und interner Berichte","Durchführung von Fremdwährungsbewertungen offener Posten","Schließen der vergangenen Periode"],"richtige_antworten":["Erstellen externer und interner Berichte","Durchführung von Fremdwährungsbewertungen offener Posten","Schließen der vergangenen Periode"],"erklaerung":{"richtig":"Monatliche Abschlussarbeiten im ext. RW: Berichte erstellen, Fremdwährung bewerten, Periode schließen. Lagerkorrekturen gehören zur MM.","falsch":{},"eselsbruecke":"Extern = Berichte + Fremdwährung + Periode schließen. Lager = MM."},"source":"WBS"},{"id":"WBS-110","fragen_id":"5044723","thema":"Zahlungsverkehr","frage":"Aus welchen Gründen kann es passieren, dass eine Rechnung nicht bezahlt wird?","typ":"multiple_select","optionen":["Weil der zu zahlende Betrag unter dem festgelegten Mindestzahlbetrag liegt","Weil bei der Rechnungsbuchung eine falsche Sprache gewählt worden ist","Weil eine ungültige Hausbank gewählt worden ist","Weil die Skontofrist abgelaufen ist","Weil das Kreditorenkonto (Lieferantenkonto) einen Soll-Saldo hat"],"richtige_antworten":["Weil der zu zahlende Betrag unter dem festgelegten Mindestzahlbetrag liegt","Weil eine ungültige Hausbank gewählt worden ist","Weil das Kreditorenkonto (Lieferantenkonto) einen Soll-Saldo hat"],"erklaerung":{"richtig":"Drei Gründe: Betrag unter Mindestbetrag, ungültige Hausbank, Kreditor hat Sollsaldo (also haben wir eine Gutschrift). Sprache und Skontofrist blockieren keine Zahlung.","falsch":{},"eselsbruecke":"Zahlung scheitert: zu kleiner Betrag, falsche Bank, Kreditorsaldo positiv."},"source":"WBS"},{"id":"WBS-111","fragen_id":"5044724","thema":"Sachkontenstammdaten","frage":"Welche der folgenden Aussagen treffen zu?","typ":"multiple_select","optionen":["Bei der Archivieren von Sachkontenstammsätzen müssen immer alle Stammsätze archiviert werden.","Die Löschvormerkung kann man im allgemeinen Bereich und im buchungskreisspezifischen Bereich des Sachkontos separat setzen.","Die Löschvormerkung in einem Sachkonto ist Voraussetzung dafür, dass es archiviert werden kann."],"richtige_antworten":["Die Löschvormerkung kann man im allgemeinen Bereich und im buchungskreisspezifischen Bereich des Sachkontos separat setzen.","Die Löschvormerkung in einem Sachkonto ist Voraussetzung dafür, dass es archiviert werden kann."],"erklaerung":{"richtig":"Man kann selektiv archivieren (nicht alle). Löschvormerkung ist Voraussetzung. Sie kann separat für allgemeinen und buchungskreisspezifischen Bereich gesetzt werden.","falsch":{},"eselsbruecke":"Löschvormerkung zuerst setzen, dann archivieren — getrennt je Bereich möglich."},"source":"WBS"},{"id":"WBS-112","fragen_id":"5044725","thema":"Zahlungsverkehr","frage":"Wie verhält sich das System, wenn eine Rechnung als Restzahlung verarbeitet wird?","typ":"single_select","optionen":["Die Zahlungsdifferenz wird als aktiver Rechnungsabgrenzungsposten gebucht.","Die Zahlungsdifferenz wird auf ein Konto für Erlösausfälle gebucht.","Forderung bleibt solange mit dem Betrag in dem ursprünglichen Rechnungsbeleg als offener Posten bestehen, bis der Betrag vollständig bezahlt ist.","Der Restzahlungsbetrag wird gegen den offenen Posten aus der Rechnung ausgeglichen, und ein neuer offener Posten mit dem verbliebenen Betrag wird auf dem Debitorenkonto gebildet. Der Ursprungsbeleg (offener Posten) wird geschlossen."],"richtige_antworten":["Der Restzahlungsbetrag wird gegen den offenen Posten aus der Rechnung ausgeglichen, und ein neuer offener Posten mit dem verbliebenen Betrag wird auf dem Debitorenkonto gebildet. Der Ursprungsbeleg (offener Posten) wird geschlossen."],"erklaerung":{"richtig":"Bei Restzahlung: Ursprungsbeleg wird geschlossen, neuer offener Posten für den Restbetrag wird angelegt.","falsch":{},"eselsbruecke":"Rest = alt zu, neu auf. Teilzahlung = beide bleiben offen."},"source":"WBS"},{"id":"WBS-113","fragen_id":"5044726","thema":"Organisationsstruktur","frage":"Wie ist der Buchungskreisschlüssel aufgebaut?","typ":"single_select","optionen":["Sechsstellige Zahl","Zehnstellige Zahl","Zehnstellige alphanumerische Zahl","Sechsstellige alphanumerische Zahl","Vierstellige alphanumerische Zahl"],"richtige_antworten":["Vierstellige alphanumerische Zahl"],"erklaerung":{"richtig":"Der Buchungskreisschlüssel ist vierstellig alphanumerisch (z.B. 1000, DE01).","falsch":{},"eselsbruecke":"Buchungskreis = 4-stellig alphanumerisch. Wie alle SAP-Schlüssel auf Organisationsebene."},"source":"WBS"},{"id":"WBS-114","fragen_id":"5044727","thema":"Korrespondenz","frage":"Ein Debitor bezahlt eine Rechnung nur teilweise, weil ein Teil der Lieferung beschädigt ist. Welche Korrespondenzart wählt das System?","typ":"single_select","optionen":["Die, die der Kombination aus Differenzgrund und Debitor zugeordnet ist","Die, die dem Differenzgrund zugeordnet ist","Die, die dem gelieferten Material zugeordnet ist","Die, die der Toleranzgruppe zugeordnet ist"],"richtige_antworten":["Die, die dem Differenzgrund zugeordnet ist"],"erklaerung":{"richtig":"Das System wählt die Korrespondenzart die dem Differenzgrund zugeordnet ist.","falsch":{},"eselsbruecke":"Differenzgrund bestimmt die Korrespondenzart."},"source":"WBS"},{"id":"WBS-115","fragen_id":"5044728","thema":"Belegerfassung","frage":"Welche der folgenden Aussagen treffen zu?","typ":"multiple_select","optionen":["Ein gemerkter Beleg muss nicht vollständig sein.","Zahlungs- und Mahnprogramm können auf Merkposten zugreifen.","Beim Sichern eines Merkpostens werden Verkehrszahlen fortgeschrieben.","Ein gemerkter Beleg und ein Merkposten sind nicht dasselbe.","Merkposten können die Summe von Konzernbilanzen verändern, jedoch nicht die von Buchungskreisbilanzen."],"richtige_antworten":["Ein gemerkter Beleg muss nicht vollständig sein.","Zahlungs- und Mahnprogramm können auf Merkposten zugreifen.","Ein gemerkter Beleg und ein Merkposten sind nicht dasselbe."],"erklaerung":{"richtig":"Alle fünf Aussagen sind korrekt.","falsch":{},"eselsbruecke":"Alle 5 stimmen — gemerkter Beleg ≠ Merkposten!"},"source":"WBS"},{"id":"WBS-116","fragen_id":"5044729","thema":"Validierung / Substitution","frage":"Welche Aussagen sind korrekt?","typ":"multiple_select","optionen":["Mit dem Schlüsselwort 'UNLIKE' kann man Diskrepanzen in logischen Aussagen identifizieren.","Mit dem Schlüsselwort 'LIKE' lassen sich in logischen Aussagen Textmuster miteinander vergleichen.","Wenn eine Boole'sche Aussage häufig verwendet werden soll oder eine komplexe Logik enthält, sollte man für die Aussage eine Regel anlegen.","Bei der Validierung wird eine Prüfung durchgeführt, ob eine Voraussetzung erfüllt ist.","Eine Boole'sche logische Aussage ist eine logische linguistische Struktur, die entweder wahr (TRUE) oder unwahr (FALSE) ist.","Substitutionen ermöglichen das individuelle Ersetzen bestimmter Feldinhalte."],"richtige_antworten":["Mit dem Schlüsselwort 'LIKE' lassen sich in logischen Aussagen Textmuster miteinander vergleichen.","Wenn eine Boole'sche Aussage häufig verwendet werden soll oder eine komplexe Logik enthält, sollte man für die Aussage eine Regel anlegen.","Bei der Validierung wird eine Prüfung durchgeführt, ob eine Voraussetzung erfüllt ist.","Eine Boole'sche logische Aussage ist eine logische linguistische Struktur, die entweder wahr (TRUE) oder unwahr (FALSE) ist.","Substitutionen ermöglichen das individuelle Ersetzen bestimmter Feldinhalte."],"erklaerung":{"richtig":"5 von 6 stimmen. 'UNLIKE' existiert nicht als SAP-Schlüsselwort.","falsch":{},"eselsbruecke":"UNLIKE gibt es nicht — alles andere stimmt."},"source":"WBS"},{"id":"WBS-117","fragen_id":"5044730","thema":"Mahnwesen","frage":"Welche mahnbezogenen Daten pflegen Sie im Geschäftspartnerstammsatz?","typ":"multiple_select","optionen":["Mahnverfahren","Mahnintervall","Mahnschlüssel","Mahnblock","Mahnbereich"],"richtige_antworten":["Mahnverfahren","Mahnschlüssel","Mahnbereich"],"erklaerung":{"richtig":"Im GP-Stammsatz: Mahnverfahren, Mahnschlüssel, Mahnbereich. Mahnintervall und Mahnblock gehören nicht zum Stammsatz.","falsch":{},"eselsbruecke":"Verfahren + Schlüssel + Bereich = die 3 Mahndaten im GP-Stammsatz."},"source":"WBS"},{"id":"WBS-118","fragen_id":"5044731","thema":"MM/FI Integration","frage":"Welche der folgenden logistischen Prozesse sind bei der Beschaffung von Vermögenswerten mit MM beteiligt?","typ":"multiple_select","optionen":["Bestellung","Bestellanforderung","Wareneingang","Inventarbeleg"],"richtige_antworten":["Bestellung","Bestellanforderung","Wareneingang"],"erklaerung":{"richtig":"Bei Anlagenbeschaffung über MM: Bestellanforderung → Bestellung → Wareneingang. Inventarbeleg gehört nicht zum Beschaffungsprozess.","falsch":{},"eselsbruecke":"Beschaffung = BANF → Bestellung → WE. Inventar ist separat."},"source":"WBS"},{"id":"WBS-119","fragen_id":"5044732","thema":"Belegerfassung","frage":"Welche Felder können Sie bearbeiten, bevor Sie ein geparktes Dokument veröffentlichen?","typ":"multiple_select","optionen":["Belegart","Konto","Buchungsdatum","Betrag","Währung"],"richtige_antworten":["Konto","Buchungsdatum","Betrag"],"erklaerung":{"richtig":"Bei geparkten Belegen können Konto, Buchungsdatum und Betrag geändert werden. Belegart und Währung sind nicht änderbar.","falsch":{},"eselsbruecke":"Parken = flexibel: Konto, Datum, Betrag änderbar. Belegart und Währung fest."},"source":"WBS"},{"id":"WBS-120","fragen_id":"5044733","thema":"SD/FI Integration","frage":"Wo wird die Faktura erstellt?","typ":"single_select","optionen":["Finanzbuchhaltung","Buchhaltung","Materialwirtschaft","Vertrieb"],"richtige_antworten":["Vertrieb"],"erklaerung":{"richtig":"Die Faktura wird im Vertrieb (SD) erstellt.","falsch":{},"eselsbruecke":"Faktura = Rechnung an Kunden = Vertrieb erstellt sie."},"source":"WBS"},{"id":"WBS-121","fragen_id":"5044734","thema":"MM/FI Integration","frage":"Welcher der folgenden Schritte wird bei der Buchung von Beschaffungsvorgängen ausschließlich in der Materialwirtschaft ausgeführt?","typ":"single_select","optionen":["Bestellung","Rechnung","Wareneingang"],"richtige_antworten":["Bestellung"],"erklaerung":{"richtig":"Die Bestellung wird ausschließlich in MM angelegt. Wareneingang und Rechnung erzeugen auch FI-Belege.","falsch":{},"eselsbruecke":"Bestellung = nur MM. WE und Rechnung = MM + FI."},"source":"WBS"},{"id":"WBS-122","fragen_id":"5044735","thema":"Geschäftspartnerstammdaten","frage":"In welchem der folgenden Segmente eines Kunden- oder Lieferantenstammsatzes können Sie die Zahlungsbedingungen eingeben?","typ":"multiple_select","optionen":["Buchungskreissegment","Vertriebsbereichsdaten","Allgemeine Daten","Einkaufsorganisation"],"richtige_antworten":["Buchungskreissegment","Vertriebsbereichsdaten","Einkaufsorganisation"],"erklaerung":{"richtig":"Zahlungsbedingungen können in Buchungskreissegment (FI), Vertriebsbereichsdaten (SD) und Einkaufsorganisation (MM) gepflegt werden. Allgemeine Daten enthalten keine Zahlungsbedingungen.","falsch":{},"eselsbruecke":"Zahlungsbedingungen = überall außer allgemeine Daten."},"source":"WBS"},{"id":"WBS-123a","fragen_id":"5044736","thema":"Anlagenbuchhaltung","frage":"Welche der folgenden ursprünglichen Management Accounting-Objekte können Sie im Anlagenstammsatz zuordnen?","typ":"multiple_select","optionen":["Leistungsart","Kostenstelle","Kostenart","Bestellung"],"richtige_antworten":["Leistungsart","Kostenstelle"],"erklaerung":{"richtig":"Im Anlagenstammsatz können Leistungsart und Kostenstelle als CO-Objekte zugeordnet werden. Kostenart und Bestellung nicht.","falsch":{},"eselsbruecke":"Anlage → CO: Leistungsart und Kostenstelle. Kostenart ist keine Zuordnung im Stammsatz."},"source":"WBS"},{"id":"WBS-123b","fragen_id":"5044737","thema":"Belegerfassung","frage":"Was definieren Sie, wenn Sie eine neue Belegart erstellen?","typ":"multiple_select","optionen":["Gründe für die Umkehrung","Zulässige Kontoarten","Buchungsschlüssel für die Belegart","Nummernkreis"],"richtige_antworten":["Zulässige Kontoarten","Nummernkreis"],"erklaerung":{"richtig":"Bei der Belegart werden zulässige Kontoarten und der Nummernkreis definiert. Buchungsschlüssel und Umkehrungsgründe sind keine Bestandteile der Belegart-Definition.","falsch":{},"eselsbruecke":"Belegart = Kontoarten erlauben + Nummernkreis zuweisen."},"source":"WBS"},{"id":"WBS-124","fragen_id":"5044738","thema":"Periodensteuerung","frage":"Sie möchten Journaleinträge in eine Sonderperiode buchen. Welche Bedingungen müssen erfüllt sein?","typ":"multiple_select","optionen":["Der Saldovortrag auf das neue Geschäftsjahr muss stattgefunden haben.","Sie müssen ein Buchungsdatum in der letzten Buchungsperiode eingeben.","Sie müssen über eine spezielle Berechtigung zum Posten in bestimmten Zeiträumen verfügen.","Die Sonderperiode muss für die Buchung in der Periodenkontrolle geöffnet sein."],"richtige_antworten":["Sie müssen ein Buchungsdatum in der letzten Buchungsperiode eingeben.","Sie müssen über eine spezielle Berechtigung zum Posten in bestimmten Zeiträumen verfügen.","Die Sonderperiode muss für die Buchung in der Periodenkontrolle geöffnet sein."],"erklaerung":{"richtig":"Für Sonderperioden: Buchungsdatum in letzter Periode, Sonderberechtigung und Sonderperiode muss geöffnet sein. Saldovortrag ist keine Voraussetzung.","falsch":{},"eselsbruecke":"Sonderperiode = besonderes Datum + Berechtigung + Periode offen."},"source":"WBS"},{"id":"WBS-125","fragen_id":"5044739","thema":"SAP S/4HANA","frage":"Welche Anwendungen aus dem SAP-Portfolio lassen sich in SAP S/4HANA integrieren, um beim Personalmanagement zu unterstützen?","typ":"multiple_select","optionen":["SAP Success Factors","SAPAriba","SAP C/4HANA","SAP Fieldglass"],"richtige_antworten":["SAP Success Factors","SAP Fieldglass"],"erklaerung":{"richtig":"SAP SuccessFactors (HR-System) und SAP Fieldglass (externe Arbeitskräfte) unterstützen Personalmanagement. SAPAriba = Einkauf, SAP C/4HANA = CRM.","falsch":{},"eselsbruecke":"Personal = SuccessFactors + Fieldglass. Ariba = Einkauf, C/4HANA = Kunden."},"source":"WBS"}];
